-- Poems batch 204
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('52cab53e-18f7-480b-bbb5-972bf8164034','次韻德脩弟','陶夢桂','宋','宋诗','song-poetry','','[]','自古賢名隠魏亭，老夫底用更專城。',64,'全唐诗/poet.song.192000.json','["自古賢名隠魏亭，老夫底用更專城。", "得閑且看雲來往，不飲休論酒濁清。", "險阻備嘗知世味，消磨不盡是詩情。", "西堂不作惠連夢，共聽茅簷夜雨聲。"]'),
('f103f347-bf28-4e0b-9912-e983f3a2d01e','望郡城酬舟中諸丈','陶夢桂','宋','宋诗','song-poetry','','[]','歸路寧迂三兩程，落霞孤鶩近鄉城。',64,'全唐诗/poet.song.192000.json','["歸路寧迂三兩程，落霞孤鶩近鄉城。", "水連南浦天然碧，秋入西山雨後清。", "鹿夢已醒諳世事，鷗盟猶在見交情。", "近來一事君知否，耳畔全無鼙鼓聲。"]'),
('5ffedf65-d39c-4f19-ae54-83da2a8e2bbb','次韻德脩弟','陶夢桂','宋','宋诗','song-poetry','','[]','一笑相逢在眼前，底須尺素付郵傳。',63,'全唐诗/poet.song.192000.json','["一笑相逢在眼前，底須尺素付郵傳。", "池塘生草尋殘夢，風雨連床了宿緣。", "遮暮雪霜侵兩鬢，倚雲梨棗出丹。", "從今不願重分手，糲飯團欒滿百年。"]'),
('a2c307c7-0259-4b35-9fad-e476ccd497c8','書懷','陶夢桂','宋','宋诗','song-poetry','','[]','明時容我老山林，病骨那禁歲月侵。',64,'全唐诗/poet.song.192000.json','["明時容我老山林，病骨那禁歲月侵。", "破屋僅存容膝地，短檠喚起讀書心。", "三生習氣磨難盡，一餉榮華去莫尋。", "苦學吟詩終不近，信知前輩用工深。"]'),
('62ab1dd4-f8be-4310-a3b0-01314e5283be','自題','陶夢桂','宋','宋诗','song-poetry','','[]','短衣匹馬遍關山，二十年來一夢間。',64,'全唐诗/poet.song.192000.json','["短衣匹馬遍關山，二十年來一夢間。", "萬里煙塵催我老，一溪風月伴人閑。", "處心簡淡常常足，著意經求事事艱。", "亭午厨人多喜色，隣翁舉網得魚還。"]'),
('9aef1f61-f694-493d-b614-463a7c075c99','次韻堅大師','陶夢桂','宋','宋诗','song-poetry','','[]','明時有分坐空山，終日心遊天壤間。',64,'全唐诗/poet.song.192000.json','["明時有分坐空山，終日心遊天壤間。", "無欲始安貧裏樂，是人只得睡時閑。", "離家便憶居家好，論事那知任事難。", "自快此身天所相，干戈叢裏得生還。"]'),
('c2f3b107-95bd-44fa-b9b4-e828b3a6e2fe','次韻友人','陶夢桂','宋','宋诗','song-poetry','','[]','只將夢幻視浮生，志念俱消豈復增。',64,'全唐诗/poet.song.192000.json','["只將夢幻視浮生，志念俱消豈復增。", "竹杖芒鞋輕勝馬，布衣蔬飯淡於僧。", "睡魔爲祟勤呼茗，病眼羞明懶近燈。", "好把金鎞輕掠削，近來知有阿誰能。"]'),
('d5c2fc7e-f4aa-4e80-b487-badd05d247ef','次韻汪山園  其一','陶夢桂','宋','宋诗','song-poetry','','[]','泉石相干興味長，夢魂飛不到錢塘。',64,'全唐诗/poet.song.192000.json','["泉石相干興味長，夢魂飛不到錢塘。", "病來弘景難忘藥，老去淵明不御觴。", "舊館溪山勤檢校，新收風月懶平章。", "讀書事業依然在，一目猶慚不十行。"]'),
('e015d9df-94cd-4d4f-a422-fd1302fb3f7f','次韻汪山園  其二','陶夢桂','宋','宋诗','song-poetry','','[]','急雨聲中夜漏長，曉來嫩水漲平塘。',64,'全唐诗/poet.song.192000.json','["急雨聲中夜漏長，曉來嫩水漲平塘。", "試扶竹杖穿三徑，自折梅花薦一觴。", "我縱撚鬚難得句，君纔開口便成章。", "偃旗仆鼓退三舍，且遜元戎十乘行。"]'),
('e588c81d-e6de-45e5-bd26-f2deccc105b1','次韻毛幼聲','陶夢桂','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','人生自得即逍遥，到底聲名不用高。',64,'全唐诗/poet.song.192000.json','["人生自得即逍遥，到底聲名不用高。", "心地一朝收汗馬，泰山萬仞等秋毫。", "處囊脫穎君非晚，爲米折腰余憚勞。", "喜得新詩當文選，何須痛飲讀離騷。"]'),
('c4ff43e6-0d67-4a0a-87d7-a7d29dc72af9','謾興','陶夢桂','宋','宋诗','song-poetry','','[]','吟情常得閑情助，和氣多爲直氣侵。',64,'全唐诗/poet.song.192000.json','["吟情常得閑情助，和氣多爲直氣侵。", "易說難行天下事，未爲先懶老來心。", "公然排闥清風入，悄地窺窗好月尋。", "風月無情肯相管，塵緣終淺道緣深。"]'),
('2f5ed5da-a4f7-426a-b6c0-66f23b64a4ea','寄王良佐','陶夢桂','宋','宋诗','song-poetry','','[]','高高林木带烟霞，短短茅簷寄水涯。',64,'全唐诗/poet.song.192000.json','["高高林木带烟霞，短短茅簷寄水涯。", "儘有清風疎種竹，苦無空地密栽花。", "雲停栗里淵明屋，月滿剡溪安道家。", "會待子猷清興發，扁舟一葉著平沙。"]'),
('74a1d677-7d62-4df0-8424-d65a987f151d','次韻二首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','倦倚欄桿對暮霞，展君吟卷喜無涯。',64,'全唐诗/poet.song.192000.json','["倦倚欄桿對暮霞，展君吟卷喜無涯。", "圓如掌上黄金彈，清比梅梢白玉花。", "試問山林無我輩，却將景物付誰家。", "風簷把玩徘徊久，煙在平林月在沙。"]'),
('158d4099-dc82-43eb-a6f4-1b73cf8dabfc','次韻二首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','平塘古木带餘霞，清蔭週遭水四涯。',64,'全唐诗/poet.song.192000.json','["平塘古木带餘霞，清蔭週遭水四涯。", "在世能消幾兩屐，惱人無奈四時花。", "好隨彩筆題詩句，笑入青帘賣酒家。", "却憶當年杜陵老，有誰相伴醉長沙。"]'),
('026f185c-917d-4d44-8a5a-a53b8c983758','次韻良佐歇心歌三首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','一生受用燕營窠，百歲光陰馬駐坡。',64,'全唐诗/poet.song.192000.json','["一生受用燕營窠，百歲光陰馬駐坡。", "晚境喜無干己事，故人遠寄歇心歌。", "君開經卷塵緣了，我闢山林詩料多。", "得句却愁成綺語，何如一意向禪那。"]'),
('8538021d-288b-4bb0-aebb-be00cbab822f','次韻良佐歇心歌三首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','隨意栽培花幾窠，梅坡安穩即鑾坡。',64,'全唐诗/poet.song.192000.json','["隨意栽培花幾窠，梅坡安穩即鑾坡。", "土尊豈勝茅柴酒，法曲何如欵乃歌。", "著意事無虛事有，快行時少坐時多。", "閑身散誕休驚去，塵世光陰等剎那。"]'),
('e286d3fc-24ac-424f-ab33-596e0c8c4739','次韻良佐歇心歌三首  其三','陶夢桂','宋','宋诗','song-poetry','','[]','鳥窠看了看蜂窠，纔上坡來又下坡。',64,'全唐诗/poet.song.192000.json','["鳥窠看了看蜂窠，纔上坡來又下坡。", "松竹徑中逢野老，芰荷香裏唱漁歌。", "歸來不見香風改，老去何愁明月多。", "况有句文供佈施，僧來也喚作檀那。"]'),
('6394077a-6708-4ca4-beaa-25e0c6e199f0','寄椿上人','陶夢桂','宋','宋诗','song-poetry','','[]','顔童齒豁老書生，習氣消除道氣增。',64,'全唐诗/poet.song.192000.json','["顔童齒豁老書生，習氣消除道氣增。", "自止酒來疎酒伴，閑吟詩去寄詩僧。", "不才臃腫莊周木，無盡光明摩詰燈。", "解道本來無一物，未容盡遜嶺南能。"]'),
('470955e0-cf2e-422a-990b-86c2e37bb5a1','次韻龔子輝','陶夢桂','宋','宋诗','song-poetry','','[]','身計平生盡付天，歸來環堵更蕭然。',64,'全唐诗/poet.song.192000.json','["身計平生盡付天，歸來環堵更蕭然。", "君於客裏懷新紱，我愧齋中祇舊氈。", "一見便論千古事，定教遲了十餘年。", "駑駘强欲追高躅，病骨摧頹怕受鞭。"]'),
('c6ad2cc3-5055-45b9-ab7d-548c1f8dcf3e','讀傳燈錄','陶夢桂','宋','宋诗','song-poetry','','[]','公案堆來高似山，人人沉着語言間。',64,'全唐诗/poet.song.192000.json','["公案堆來高似山，人人沉着語言間。", "水中掬月徒辛苦，衣下尋珠只等閑。", "此事不從人世得，諸賢枉道法門艱。", "千山萬水參禪者，行到窮時祇自還。"]'),
('472e73a0-e158-4141-b9c5-02ce34c5001c','遊永福寺二首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','二十餘年不入山，重來疑是夢魂間。',64,'全唐诗/poet.song.192000.json','["二十餘年不入山，重來疑是夢魂間。", "薰爐已冷燈猶在，經卷纔收磬自閑。", "寂寂禪關人罕到，茫茫人世事多艱。", "朅來細說無生話，穩坐蒲團不忍還。"]'),
('1943d488-07b0-491c-8b56-5558ae9d23ef','遊永福寺二首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','寺占吾鄉好處山，半新半舊屋千間。',64,'全唐诗/poet.song.192000.json','["寺占吾鄉好處山，半新半舊屋千間。", "水中蓮似尼清浄，雨後雲如僧退閑。", "石路教人修整過，芒鞋怕我往來艱。", "夜深火炬渾無用，長是天教月送還。"]'),
('f0bb023f-ebd5-460e-a64a-5aa3ee104a83','次韻陶明甫','陶夢桂','宋','宋诗','song-poetry','','[]','寸質元非紫磨金，少時徒有濟時心。',64,'全唐诗/poet.song.192000.json','["寸質元非紫磨金，少時徒有濟時心。", "中年世味諳常盡，晚節宗門趨向深。", "萬境皆空何所着，百年未滿得長吟。", "人間俯仰咸塵跡，惟有江山不古今。"]'),
('0f9cc37f-95db-48d0-afa9-40fb016ab8c0','約客','陶夢桂','宋','宋诗','song-poetry','','[]','家在青山綠水間，柴門雖設亦常關。',64,'全唐诗/poet.song.192000.json','["家在青山綠水間，柴門雖設亦常關。", "稠花浪蕊隨時有，樂事賞心從古慳。", "世上人多爲物役，眼前誰肯掣身還。", "君能不負平生約，袖有新詩慰病顔。"]'),
('cafff7c3-09e6-4397-b772-a8a476d78e0a','次韻王衡甫','陶夢桂','宋','宋诗','song-poetry','','[]','野徑溪橋取次行，山青水秀眼增明。',64,'全唐诗/poet.song.192000.json','["野徑溪橋取次行，山青水秀眼增明。", "身居塵外年年健，心到灰時事事輕。", "文陣揮戈吾退舍，詩壇歃血子同盟。", "直將修月拿雲手，拾得人間句見成。"]'),
('d56dd048-dd8e-44b7-b0c0-549a18093f5b','次韻良佐','陶夢桂','宋','宋诗','song-poetry','','[]','回也逍遥只寓言，參乎三省道真傳。',64,'全唐诗/poet.song.192000.json','["回也逍遥只寓言，參乎三省道真傳。", "明知榮悴何由我，誰道修爲亦屬天。", "朝市山林皆寄耳，簡編燈火故依然。", "窮年矻矻人休訝，山宅臞儒便是仙。"]'),
('531dc8ce-1ad6-4955-a08b-8e2220eb2a7a','次弓天錫送胡儒文韻','陶夢桂','宋','宋诗','song-poetry','','[]','不論朝市與山林，兩鬢難禁白髮侵。',64,'全唐诗/poet.song.192000.json','["不論朝市與山林，兩鬢難禁白髮侵。", "物外休論天下事，書中要見古人心。", "老來酒債渾無有，公等詩名儘可尋。", "吟料從來無盡藏，江湖萬里水雲深。"]'),
('286d3aa1-6345-4209-ba73-56606f3b90e6','與弓王二尉談詩二首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','從來造物只兒嬉，用舍行藏各一時。',64,'全唐诗/poet.song.192000.json','["從來造物只兒嬉，用舍行藏各一時。", "玉兔金烏元去速，曉猿夜鶴怪歸遲。", "幸然三徑菊如舊，且與兩梅仙說詩。", "試問釣車茶具外，當時誰予伴天隨。"]'),
('1d16194c-8064-402a-bfed-e15b2d713dd3','與弓王二尉談詩二首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','雀羅門巷駐高車，靄靄停雲滿眼時。',64,'全唐诗/poet.song.192000.json','["雀羅門巷駐高車，靄靄停雲滿眼時。", "惟有故情來得得，却搜詩句步遲遲。", "北窗不放淵明卧，南澗同看子厚詩。", "要識吾儕長久處，此心如月鎮相隨。"]'),
('e1c3b7b5-acfa-400e-a990-69f10d728c23','良佐留別詩頗悽惋次韻敘閑居之樂以釋之二首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','困人天氣晝沉沉，飯罷茶甌儘放深。',64,'全唐诗/poet.song.192000.json','["困人天氣晝沉沉，飯罷茶甌儘放深。", "笑領故人遊竹洞，因尋詩句到梅林。", "已教兒去將詩寫，又喚孫來把酒斟。", "行樂既知明日少，合如吾祖惜分陰。"]'),
('f6130ea7-fb8a-4ce4-941c-2ff5e4dc1873','良佐留別詩頗悽惋次韻敘閑居之樂以釋之二首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','騰騰曉日夕還沉，淺淺秋江春又深。',64,'全唐诗/poet.song.192000.json','["騰騰曉日夕還沉，淺淺秋江春又深。", "消息既知由造化，憂愁那得到山林。", "已吟有興猶重和，未醉開樽任滿斟。", "浮利浮名都莫問，只將詩酒送光陰。"]'),
('204fabaf-85e6-4949-9785-2fd42830e24c','次韻汪子與','陶夢桂','宋','宋诗','song-poetry','','[]','生來骨相不如人，那更心空似此君。',64,'全唐诗/poet.song.192000.json','["生來骨相不如人，那更心空似此君。", "一見好書惟恐盡，每逢佳客怕言分。", "自知原憲貧非病，莫問琴張達是聞。", "吟罷不知身已老，莫教萬里浄無雲。"]'),
('ddd943e6-cc8a-46cb-b82a-4c5c5f484926','次韻粲上人','陶夢桂','宋','宋诗','song-poetry','','[]','飛錫來尋避俗翁，不辭劈面受霜風。',64,'全唐诗/poet.song.192000.json','["飛錫來尋避俗翁，不辭劈面受霜風。", "因君髮被詩催白，知我顔須借酒紅。", "秀谷幾年千里隔，空寮今夕一燈同。", "恨無日暮碧雲句，編入文通雜綬中。"]'),
('fd655273-6682-4fc7-a1a0-200ce335dded','同子興賦雪中折带冰梅','陶夢桂','宋','宋诗','song-poetry','','[]','雪裏攀梅冷不勝，歸來分插幾空瓶。',64,'全唐诗/poet.song.192000.json','["雪裏攀梅冷不勝，歸來分插幾空瓶。", "花間亂綴未凋玉，窗下細看元是冰。", "旋覺暖回還易散，只愁凍損獨先零。", "詩翁貪看橫斜影，未暝呼童急上燈。"]'),
('3311f183-f5b2-482e-9acb-fec86c811c3a','即事','陶夢桂','宋','宋诗','song-poetry','','[]','桂花香處麝臍破，楓葉丹時錦帳開。',64,'全唐诗/poet.song.192000.json','["桂花香處麝臍破，楓葉丹時錦帳開。", "天遣年華隨水去，山將野色入簾來。", "鑷殘白髮愁無迹，割盡黄雲酒有材。", "不負小園佳景致，乘閑與客共徘徊。"]'),
('fd92beb4-e92b-488b-a990-6cad1c345219','八月十三夜月','陶夢桂','宋','宋诗','song-poetry','','[]','人情何待十分圓，滿目金波已浩然。',64,'全唐诗/poet.song.192000.json','["人情何待十分圓，滿目金波已浩然。", "明到杜陵頭上髮，寒侵鄭老客中氈。", "中秋未必似今夕，好景其如又隔年。", "多謝望舒知此意，冰輪緩碾不加鞭。"]'),
('daaf1716-7e89-456b-8f92-f5a648b9df55','送範之侄謁留守別先生','陶夢桂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','不待吹噓送上天，凌雲意氣自飄然。',64,'全唐诗/poet.song.192000.json','["不待吹噓送上天，凌雲意氣自飄然。", "長江秋色將征旆，半夜霜威襲客氈。", "淝水功名須爾力，斜川風月了吾年。", "師門念舊如相問，爲道衰頹怕着鞭。"]'),
('59b5201b-c72f-4480-9b71-fd580109d62a','酬堅大師','陶夢桂','宋','宋诗','song-poetry','','[]','蜀山越嶠倦躋攀，拄杖經年掛壁間。',64,'全唐诗/poet.song.192000.json','["蜀山越嶠倦躋攀，拄杖經年掛壁間。", "駒隙光中驚迅速，龍泉山裏占清閑。", "但存寶藏明珠在，不管石頭行路難。", "香冷磬殘經卷了，倚欄靜數暮鴉還。"]'),
('7b409925-7db2-4094-9fe7-4c701755f499','極高明樓飲散次韻二首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','有景可觀無遠近，新樓真是極高明。',64,'全唐诗/poet.song.192000.json','["有景可觀無遠近，新樓真是極高明。", "水因雨過多新進，楓到年來獨老成。", "萬頃煙波魚得計，一天風月雁能鳴。", "醉餘客散清愁入，嘹亮漁舟笛數聲。"]'),
('1563f606-583b-4bbb-8c7e-87161105b83a','極高明樓飲散次韻二首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','江練緊纏山脚白，露珠密簇草頭明。',64,'全唐诗/poet.song.192000.json','["江練緊纏山脚白，露珠密簇草頭明。", "一天秋意淒涼甚，幾日西風醖造成。", "新月光中新雁過，暮雲深處暮鐘鳴。", "得君吟卷呼兒讀，吹竹彈絲無此聲。"]'),
('1a761621-1845-4b16-aa00-62e4a507c425','送胡上人遊浙','陶夢桂','宋','宋诗','song-poetry','','[]','大別山頭訪早梅，梅邊邂逅笑顔開。',64,'全唐诗/poet.song.192000.json','["大別山頭訪早梅，梅邊邂逅笑顔開。", "十年一夢看看老，萬水千山得得來。", "馬祖話中心即佛，盧能偈裏鏡非臺。", "即今了却此公案，便是公門及第回。"]'),
('bf0f7c89-7f96-4a27-85e0-ecd6f22fc875','黄澄伯下第以詩來訪次韻','陶夢桂','宋','宋诗','song-poetry','','[]','平塘水外竹三畝，古木陰中屋數間。',64,'全唐诗/poet.song.192000.json','["平塘水外竹三畝，古木陰中屋數間。", "天幸諸賢皆大用，分甘少病比長閑。", "百年世事皆前定，一枕清風無後艱。", "多謝新詩來慰藉，不堪溢美欲封還。"]'),
('3d101ac7-d27c-4f65-8074-b54af8373c7c','題涂季儒愚安堂','陶夢桂','宋','宋诗','song-poetry','','[]','而翁吉德怕人知，天與良孫一似之。',64,'全唐诗/poet.song.192000.json','["而翁吉德怕人知，天與良孫一似之。", "自分隨緣栖矮室，何曾弄巧蹈危機。", "人生懷抱祇平易，天下道塗皆坦夷。", "此語莫書堂上壁，客來徒說是和非。"]'),
('c87dd1ba-2b76-4fd0-8b9f-a65abfc5ea77','送饒守萬仲衡葬次山園韻','陶夢桂','宋','宋诗','song-poetry','','[]','塵埃滿面雪蒙頭，只合滄洲把釣鈎。',64,'全唐诗/poet.song.192000.json','["塵埃滿面雪蒙頭，只合滄洲把釣鈎。", "鄉里故人今日少，山川英氣一時收。", "絕憐逝者成千古，誰念淒其老一邱。", "野店相逢聊舉酒，潸然苦淚落瓷甌。"]'),
('f6ac65c2-bdd9-4648-b37d-d514ddeef396','先塋之左得生壙喜而示兒','陶夢桂','宋','宋诗','song-poetry','','[]','鼓樓岡上舊墳頭，又有山靈獻寢邱。',64,'全唐诗/poet.song.192000.json','["鼓樓岡上舊墳頭，又有山靈獻寢邱。", "萬里歸來生處樂，一心甘向死前休。", "盡捐世事兼家事，但把嬉遊當宦遊。", "糲飯藜羹而辦得，吾衰此外更何求。"]'),
('f7621b80-e606-45e1-990d-c8f8cb2d7e47','題竹巖丁直卿鏤冰集','陶夢桂','宋','宋诗','song-poetry','','[]','一片好詩如片月，半生愁殺鏤冰翁。',64,'全唐诗/poet.song.192000.json','["一片好詩如片月，半生愁殺鏤冰翁。", "多情誤以苦爲樂，衆體疑於異却同。", "幾度手抄方刻棗，數莖髮在已如蓬。", "江湖醉墨爭馳騁，誰識巖燈夜夜紅。"]'),
('40c98b0a-8c77-4bf6-a80f-6a47c3d94a37','登胡氏樓  其一','陶夢桂','宋','宋诗','song-poetry','','[]','草際露華白，天邊雲浪開。',24,'全唐诗/poet.song.192000.json','["草際露華白，天邊雲浪開。", "好風何處起，和月入簾來。"]'),
('a7d7ab8e-420f-41dc-9394-10286c2c2e42','登胡氏樓  其二','陶夢桂','宋','宋诗','song-poetry','','[]','水將羅带繞，山展畫圖開。',24,'全唐诗/poet.song.192000.json','["水將羅带繞，山展畫圖開。", "二十年前客，身閑又此來。"]'),
('50155f04-3838-4167-a3f5-b5829b5379f0','感懷五首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','記得當年宴杏園，旁人儘道似神仙。',32,'全唐诗/poet.song.192000.json','["記得當年宴杏園，旁人儘道似神仙。", "全家自此廢耕織，枉費公家多少錢。"]'),
('55af8c0c-19f7-492e-920d-c2ab1e51a0fc','感懷五首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','憶昔身章兩度新，庭闈恨不拜雙親。',32,'全唐诗/poet.song.192000.json','["憶昔身章兩度新，庭闈恨不拜雙親。", "雖然累贈光泉壤，還是酬恩未了人。"]'),
('e7258acc-cfba-41f2-a537-697c4636e019','感懷五首  其三','陶夢桂','宋','宋诗','song-poetry','','[]','佐岳歸來得自如，依然服色似芙蕖。',32,'全唐诗/poet.song.192000.json','["佐岳歸來得自如，依然服色似芙蕖。", "兒童癡絕牽衣問，腰下如何不見魚。"]'),
('08226748-2970-4eb2-ad11-9c4b7c472a5f','感懷五首  其四','陶夢桂','宋','宋诗','song-poetry','','[]','心力較衰於少日，園池差勝似前原。',32,'全唐诗/poet.song.192000.json','["心力較衰於少日，園池差勝似前原。", "畦蔬繞舍苔侵徑，棘刺編籬竹打門。"]'),
('935f001c-08e1-4ad4-9a27-31b50ff53b97','感懷五首  其五','陶夢桂','宋','宋诗','song-poetry','','[]','每憶間關離陷穽，一年剡壁一番新。',32,'全唐诗/poet.song.192000.json','["每憶間關離陷穽，一年剡壁一番新。", "雖無毫髦私於己，豈有涓埃及得人。"]'),
('1d29c649-b866-426b-aaf0-ac5c9806af6e','平塘三首次子輝韻  其一','陶夢桂','宋','宋诗','song-poetry','','[]','歸來荒却舊田園，手自誅鋤又一番。',32,'全唐诗/poet.song.192000.json','["歸來荒却舊田園，手自誅鋤又一番。", "江上清風終耐久，依然和月到柴門。"]'),
('7efeb89d-60a0-48e2-893e-e7998f37c534','平塘三首次子輝韻  其二','陶夢桂','宋','宋诗','song-poetry','','[]','秋水清明鏡不如，含羞照影獨紅蕖。',32,'全唐诗/poet.song.192000.json','["秋水清明鏡不如，含羞照影獨紅蕖。", "莫因風冷嫌衣破，容我傍邊看戲魚。"]'),
('627853bd-278e-4fa2-8844-9caca993de16','平塘三首次子輝韻  其三','陶夢桂','宋','宋诗','song-poetry','','[]','平築三塘共一園，箇中宜著老癯仙。',32,'全唐诗/poet.song.192000.json','["平築三塘共一園，箇中宜著老癯仙。", "隨緣妝點非難事，粗果閑花不值錢。"]'),
('f019d147-e621-4583-8088-2210b93f0ca1','贈神眼相士','陶夢桂','宋','宋诗','song-poetry','','[]','邊檄煙塵日漲天，天教老病喚歸田。',32,'全唐诗/poet.song.192000.json','["邊檄煙塵日漲天，天教老病喚歸田。", "從君試問平塘水，更照衰容得幾年。"]'),
('bf3ac510-dee4-44f1-8998-8532cc8ce32d','重次龔子輝平塘韻三首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','夢覺歸來涉舊園，共尋幽事有梅仙。',32,'全唐诗/poet.song.192000.json','["夢覺歸來涉舊園，共尋幽事有梅仙。", "乍穿綠竹教成徑，莫踏蒼苔破却錢。"]'),
('d81b2655-e2dd-47da-b92c-d957578421b7','重次龔子輝平塘韻三首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','白髮多時精力少，綠樽疎後簡編親。',32,'全唐诗/poet.song.192000.json','["白髮多時精力少，綠樽疎後簡編親。", "本無世上榮華分，莫作山間懶惰人。"]'),
('86fbac6a-3a1f-4139-ab61-13aef49f0020','重次龔子輝平塘韻三首  其三','陶夢桂','宋','宋诗','song-poetry','','[]','家園指擬似淇園，惜笋兼存上下番。',32,'全唐诗/poet.song.192000.json','["家園指擬似淇園，惜笋兼存上下番。", "若與此君情分薄，應無風月到吾門。"]'),
('16eec1d4-99fe-4b83-9501-f1bc46cf0f0e','重九與堅大師登墳庵新閣因憶癸巳歲此日同在益昌道中行役之勞遂成一絕','陶夢桂','宋','宋诗','song-poetry','','[]','茱萸笑把登高閣，菊蕊纔堪薦一觴。',32,'全唐诗/poet.song.192000.json','["茱萸笑把登高閣，菊蕊纔堪薦一觴。", "却憶當年關表路，無花無酒更凄涼。"]'),
('5d54ea99-84c5-4fe7-b443-20a010c1f862','舟次卷雪樓四首  其一','陶夢桂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','簿書期會不相關，老眼如何不得閑。',32,'全唐诗/poet.song.192000.json','["簿書期會不相關，老眼如何不得閑。", "景物無端故勾引，淮山盡處又廬山。"]'),
('d8ece274-326e-47c6-8b5a-a04d23a48976','舟次卷雪樓四首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','踏遍三邊過劍關，故山風月幾年閑。',32,'全唐诗/poet.song.192000.json','["踏遍三邊過劍關，故山風月幾年閑。", "如今著我中間住，風月無緣獨占山。"]'),
('31a118f7-00ad-4cf9-a17e-a7e0e36c9279','舟次卷雪樓四首  其三','陶夢桂','宋','宋诗','song-poetry','','[]','生怕老來先告老，却於閑處不禁閑。',32,'全唐诗/poet.song.192000.json','["生怕老來先告老，却於閑處不禁閑。", "不將黄卷遮雙眼，便捲朱簾看遠山。"]'),
('3099cd97-fabe-48b7-abe3-28197c9cf647','舟次卷雪樓四首  其四','陶夢桂','宋','宋诗','song-poetry','','[]','虎豹從渠守九關，不求進步只求閑。',32,'全唐诗/poet.song.192000.json','["虎豹從渠守九關，不求進步只求閑。", "歸裝幸有新詩在，一字千金儘買山。"]'),
('27857c03-b77d-4902-8317-68529fddda0d','懷帥書黄先生余時次萬安先生開閣九江檄莫底','陶夢桂','宋','宋诗','song-poetry','','[]','碧落班中出鎮時，紅蓮幕裏我栖遲。',32,'全唐诗/poet.song.192000.json','["碧落班中出鎮時，紅蓮幕裏我栖遲。", "四年兩地無消息，好倩西風爲寄詩。"]'),
('a6cc9386-b06a-4647-a68c-819e305bc3b1','書事','陶夢桂','宋','宋诗','song-poetry','','[]','有書有史聊遮眼，半瓦半茅還是家。',32,'全唐诗/poet.song.192000.json','["有書有史聊遮眼，半瓦半茅還是家。", "莫道幽人無受用，銅瓶徧插木犀花。"]'),
('e5d71511-6d12-4e3e-b144-74721e9a6683','謾興','陶夢桂','宋','宋诗','song-poetry','','[]','圖書叢裏清癯老，山水光中瀟灑家。',32,'全唐诗/poet.song.192000.json','["圖書叢裏清癯老，山水光中瀟灑家。", "除却栽花栽竹外，更將何事作生涯。"]'),
('ce6e1f3e-031f-41f5-a2d6-f84b7b79c049','同子輝月下觀梅二首  其一','陶夢桂','宋','宋诗','song-poetry','','[]','風聲不作寒無力，雲翳纔收月有華。',32,'全唐诗/poet.song.192000.json','["風聲不作寒無力，雲翳纔收月有華。", "清興牽人眠不得，開門共看古梅花。"]'),
('497b5b77-678f-4afb-818d-de8804d37c1a','同子輝月下觀梅二首  其二','陶夢桂','宋','宋诗','song-poetry','','[]','白髮從來羞月色，弊衣那更带霜華。',32,'全唐诗/poet.song.192000.json','["白髮從來羞月色，弊衣那更带霜華。", "三生結習依然在，貪看寒梅幾樹花。"]'),
('28717ebc-9b96-4232-acfb-aa3a047006d0','次友人韻','陶夢桂','宋','宋诗','song-poetry','','[]','綠竹漫山元積玉，青苔滿地又流錢。',32,'全唐诗/poet.song.192000.json','["綠竹漫山元積玉，青苔滿地又流錢。", "箇般也怕難消受，日炷爐薰答上天。"]'),
('c850c069-9432-4258-bead-eb867c36aaca','贈眼科舒醫士','陶夢桂','宋','宋诗','song-poetry','','[]','此老年來醫有靈，病眸纔洗便增明。',32,'全唐诗/poet.song.192000.json','["此老年來醫有靈，病眸纔洗便增明。", "教儂還盡讀書債，頭白依然對短檠。"]'),
('f85317b8-8020-4488-add9-e1b97e240830','老梅','陶夢桂','宋','宋诗','song-poetry','','[]','早年鋤月手親栽，看到成陰結子來。',32,'全唐诗/poet.song.192000.json','["早年鋤月手親栽，看到成陰結子來。", "二十餘年如一夢，歸來五度見花開。"]'),
('4a8892ce-d6f0-49bb-b388-98cdf2712846','稚梅','陶夢桂','宋','宋诗','song-poetry','','[]','更好軒中幾報春，幽人去後化爲薪。',32,'全唐诗/poet.song.192000.json','["更好軒中幾報春，幽人去後化爲薪。", "向來花在孫枝上，一笑相看似故人。"]'),
('28e26997-6144-4989-bdbe-513de36e4ee0','桑','陶夢桂','宋','宋诗','song-poetry','','[]','密葉柔條綠更腴，幾年培植費工夫。',32,'全唐诗/poet.song.192000.json','["密葉柔條綠更腴，幾年培植費工夫。", "牡丹剩費醫治力，曾有絲毫利益無。"]'),
('b7551d31-8e02-403b-9bca-a6e3be02003d','柘','陶夢桂','宋','宋诗','song-poetry','','[]','老矣能消幾許衣，一株休論幾鉤絲。',32,'全唐诗/poet.song.192000.json','["老矣能消幾許衣，一株休論幾鉤絲。", "垂楊舞徹鶑歌歇，且看東風舞柘枝。"]'),
('0bf58d37-53cc-44ee-b9bd-f7addc0ea0ba','金燈花','陶夢桂','宋','宋诗','song-poetry','','[]','紫磨真金百煉成，花神妝點似燈明。',32,'全唐诗/poet.song.192000.json','["紫磨真金百煉成，花神妝點似燈明。", "膽瓶盛取當書案，白首韓公對短檠。"]'),
('3eafdbef-baad-4e31-9f28-41449d033740','古樟','陶夢桂','宋','宋诗','song-poetry','','[]','抱合材堪任棟梁，斧斤相引到明堂。',32,'全唐诗/poet.song.192000.json','["抱合材堪任棟梁，斧斤相引到明堂。", "何如生近幽人屋，歲晚相看各老蒼。"]'),
('2a12d3ed-1f4f-4fc1-b624-6b8e614e7f02','種梅','陶夢桂','宋','宋诗','song-poetry','','[]','矮窗元向竹邊開，竹已森然只欠梅。',32,'全唐诗/poet.song.192000.json','["矮窗元向竹邊開，竹已森然只欠梅。", "新種一株花尚少，暗香早逐細風來。"]'),
('366150a1-0a95-4d6e-8c45-6897e7006b50','小桃源','陶夢桂','宋','宋诗','song-poetry','','[]','乾坤無處著臞仙，乞與桃源小洞天。',32,'全唐诗/poet.song.192000.json','["乾坤無處著臞仙，乞與桃源小洞天。", "不用窮源防失路，桃花盡處便回船。"]'),
('a234e511-d522-4e83-a046-f89d391513f8','桃','陶夢桂','宋','宋诗','song-poetry','','[]','誰從王母覓來栽，等得花開結子來。',32,'全唐诗/poet.song.192000.json','["誰從王母覓來栽，等得花開結子來。", "我種數株能幾久，有花如錦子如杯。"]'),
('a7796890-1656-43fb-b7ba-625bb8700003','李','陶夢桂','宋','宋诗','song-poetry','','[]','仙李栽培舊滿門，歸來僅有一株存。',32,'全唐诗/poet.song.192000.json','["仙李栽培舊滿門，歸來僅有一株存。", "年年碧實和煙摘，老子未嘗先乞孫。"]'),
('b9a063a6-14ae-47d8-ba94-dbf3a85a507f','雙楓','陶夢桂','宋','宋诗','song-poetry','','[]','山緣何事也窮空，百里岡巒化作童。',32,'全唐诗/poet.song.192000.json','["山緣何事也窮空，百里岡巒化作童。", "莫道吾廬無認處，行人遠遠見雙楓。"]'),
('c6b1dff1-5845-47f7-8d1b-201a36f9a937','梧桐','陶夢桂','宋','宋诗','song-poetry','','[]','妝點山居要碧梧，向來培植費工夫。',32,'全唐诗/poet.song.192000.json','["妝點山居要碧梧，向來培植費工夫。", "一株隨風成仙去，留得孫枝乞鳳雛。"]'),
('a5a63aee-8071-4acd-aa25-c2da473bb345','孤松','陶夢桂','宋','宋诗','song-poetry','','[]','傲睨風霜老更臞，旁邊著我未爲孤。',32,'全唐诗/poet.song.192000.json','["傲睨風霜老更臞，旁邊著我未爲孤。", "向來元亮盤桓後，試問曾逢我輩無。"]'),
('2e1b1930-0259-4dbb-b38c-c9a7a7cd7663','苦竹','陶夢桂','宋','宋诗','song-poetry','','[]','住近幽人善卜隣，少陵詩句豈虛文。',32,'全唐诗/poet.song.192000.json','["住近幽人善卜隣，少陵詩句豈虛文。", "平生清苦過於我，祇合呼爲苦節君。"]'),
('0167caa3-efb9-451b-96f9-aac47cc6478c','山礬','陶夢桂','宋','宋诗','song-poetry','','[]','香遠花繁葉耐冬，人人道與木犀同。',32,'全唐诗/poet.song.192000.json','["香遠花繁葉耐冬，人人道與木犀同。", "一般賽得木犀過，能爲人間報歲豐。"]'),
('ff719f83-612d-4cce-ad12-2c85b9898aee','拒霜','陶夢桂','宋','宋诗','song-poetry','','[]','消磨水上芙蓉了，岸上難兄正木彊。',32,'全唐诗/poet.song.192000.json','["消磨水上芙蓉了，岸上難兄正木彊。", "遭際東坡一題品，後來祇合字宜霜。"]'),
('40b1b5e0-4d34-471c-be40-3c045efe92cb','挽故知容州朝請陶公  其一','丁師正','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','游宦天西北，心隨造物游。',48,'全唐诗/poet.song.192000.json','["游宦天西北，心隨造物游。", "春風鄖子國，明月岳陽樓。", "政出黔黎喜，名高夷狄愁。", "案巡邊萬里，風雪破貂裘。"]'),
('a18fc8de-b01a-4129-9c84-e859487c9396','挽故知容州朝請陶公  其二','丁師正','宋','宋诗','song-poetry','','[]','嚼得菜根斷，詩寒骨更臞。',48,'全唐诗/poet.song.192000.json','["嚼得菜根斷，詩寒骨更臞。", "愛民心雪白，報國鬢霜枯。", "仕久衣長破，歸來屋亦無。", "全家寄僧舍，冰凍折吟鬚。"]'),
('ec00c9b6-704d-43d4-bb74-186b33ea9996','挽故知容州朝請陶公  其三','丁師正','宋','宋诗','song-poetry','','[]','萬影奔朝市，歸山見一人。',48,'全唐诗/poet.song.192000.json','["萬影奔朝市，歸山見一人。", "青雲莫相附，白雪不生塵。", "暖日眠松石，凉風岸葛巾。", "依然舊原憲，猿鶴伴清貧。"]'),
('2bd3dbfc-f00b-45dc-ba82-ddd8912dee14','挽故知容州朝請陶公  其四','丁師正','宋','宋诗','song-poetry','','[]','苦硬黄花節，霜枝香更清。',48,'全唐诗/poet.song.192000.json','["苦硬黄花節，霜枝香更清。", "乾坤一龐老，今古兩淵明。", "白玉難重見，孤冰不復清。", "夢中期會面，雪涕話平生。"]'),
('1237fb28-36d9-4955-97a8-805357bf7727','挽故知容州朝請陶公  其五','丁師正','宋','宋诗','song-poetry','','[]','揖坐樓頭夜，酒杯生菜盤。',48,'全唐诗/poet.song.192000.json','["揖坐樓頭夜，酒杯生菜盤。", "交情三月暮，細雨一燈寒。", "談笑響如在，賡酬墨未乾。", "死生千古別，西日照闌干。"]'),
('a0aebfb3-91b2-486b-a163-1117909c5fce','飲故祭酒黄公園林','江安止','宋','宋诗','song-poetry','','[]','記曾飛矢集蠻氈，一着鞭爭萬騎先。',64,'全唐诗/poet.song.192000.json','["記曾飛矢集蠻氈，一着鞭爭萬騎先。", "邑篆媿分炎瘴地，朝衣猶惹御爐煙。", "蓮塘小飲香隨艇，月榭高吟水壓天。", "此日隔花參簿尉，烏紗同樂太平年。"]'),
('a5155b78-cc05-4b8e-80d7-ab8b67bee2e0','次唐彥猷顧亭林韵','張堯幹','宋','宋诗','song-poetry','','[]','蘭若王家像，相望博陸居。',48,'全唐诗/poet.song.192000.json','["蘭若王家像，相望博陸居。", "衣冠塵易暗，簫鼓祭全疎。", "草色侵花徑，潮聲過夕墟。", "遺風猶可想，吊古一觴餘。"]'),
('06db2d6d-d8dd-4b7d-886f-d878779bbb15','句','高橫槎','宋','宋诗','song-poetry','','[]','宦情薄於水，吟鬢早爲霜。',12,'全唐诗/poet.song.192000.json','["宦情薄於水，吟鬢早爲霜。"]'),
('8689dbd0-ae18-498f-b8a7-8342adf98507','閑詠','龔炳','宋','宋诗','song-poetry','','[]','年踰八袠雪蒙頭，時對親朋話舊遊。',64,'全唐诗/poet.song.192000.json','["年踰八袠雪蒙頭，時對親朋話舊遊。", "萬事無心閑日月，一杯有味小公侯。", "癡兒粗爾逃譏議，家訓從來戒刻掊。", "世道漸艱宜勇退，爲吾及早理松楸。"]'),
('d7873005-83f6-4a3e-8725-0d14099b637a','服椒法歌','陳曄','宋','宋诗','song-poetry','','[]','青城山老人，服椒得妙訣。',264,'全唐诗/poet.song.192000.json','["青城山老人，服椒得妙訣。", "年過九十餘，貌不類期耋。", "再拜而請之，忻然爲我說。", "蜀椒貳斤凈，解鹽六兩潔。", "糝鹽慢火煮，煮透滾菊末。", "初服十五圓，早晚不可輟。", "每月漸漸增，累之至二百。", "鹽酒或鹽湯，任君意所歠。", "服及半年間，胸膈微覺塞。", "每日退十圓，還至十五粒。", "俟其無礙時，數復如前日。", "常令氣熏蒸，否則前功失。", "飲食蔬果等，並無所忌節。", "一年效即見，容顔頓悅澤。", "目明而耳聰，鬚烏而髮黑。", "補腎輕腰身，固氣益精血。", "椒溫鹽亦溫，菊性去煩熱。", "四旬方可服，服之幸毋忽。", "逮至數十年，功與造化埒。", "耐老更延年，不知幾歲月。", "嗜慾若能忘，其效尤卓絕。", "我欲世人安，作歌故怛切。"]'),
('4c6e7008-3253-4b29-8bab-917f707c9af8','毛希元隠居廬山卧龍瀑','葉述','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','毛子駡吳曦，蜀山渺孤憤。',120,'全唐诗/poet.song.192000.json','["毛子駡吳曦，蜀山渺孤憤。", "五老急扣聘，延留如大賓。", "龍分自眠地，蕙帳饒珠蠙。", "巖花開恨晚，谷鳥鳴先春。", "弔古一沉思，千載多逸民。", "登高一長望，萬里皆積雲。", "子勇書印曆，憂憤著彌綸。", "曷不草露布，從容靜風塵。", "低頭汲澗曲，煮豆萁爲薪。", "沮溺士之耻，昔賢終賤貧。"]'),
('04ac2d57-56da-4646-abd7-c77250fba83b','征夫','喻汝楫','宋','宋诗','song-poetry','','[]','白骨茫茫散不收，朔風吹雪度瓜州。',32,'全唐诗/poet.song.192000.json','["白骨茫茫散不收，朔風吹雪度瓜州。", "殘陽欲落未落處，照盡行人今古愁。"]'),
('b9b36969-dbf9-4948-a851-2ca1634cc1bf','題趙千里夜潮圖','名山樵子','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u94b1\u5858\u6c5f"]','八月錢塘江上水，風靜浪平清澈底。',64,'全唐诗/poet.song.192000.json','["八月錢塘江上水，風靜浪平清澈底。", "夜半潮聲带月來，沙頭眠雁還驚起。", "何人一幅鵝溪絹，畫出長江千萬里。", "莫道波聲靜不聞，請君默坐聊傾耳。"]'),
('d5ff71a2-7790-46cc-8bf4-b6c1c9cfb2b5','宿橫山禱雨','林棐','宋','宋诗','song-poetry','','[]','寸心憂國願年豐，曉挈楓香入翠峰。',64,'全唐诗/poet.song.192000.json','["寸心憂國願年豐，曉挈楓香入翠峰。", "幸有一壇瞻斗象，豈無尺水起淵龍。", "松風不住雨聲碎，嵐霧常隨雲氣濃。", "願覓天瓢一滴水，三符需夢慰三農。"]'),
('d085406c-6654-428a-bf98-ade393a2b657','泛剡','林棐','宋','宋诗','song-poetry','','[]','水闊無風似有風，蘆花摇落櫓聲中。',32,'全唐诗/poet.song.192000.json','["水闊無風似有風，蘆花摇落櫓聲中。", "鷗無一點驚猜意，認作當時載雪翁。"]'),
('253e0a77-ac38-4f6c-bb95-eb9a387c6bcd','遊武夷作  其一','陳韡','宋','宋诗','song-poetry','','[]','閬風元不隔扃扉，桑柘松筠匼匝圍。',64,'全唐诗/poet.song.192000.json','["閬風元不隔扃扉，桑柘松筠匼匝圍。", "溪貫一原藏曲折，山羅萬象欲騰飛。", "仙壇起霧成丹竈，玉女披霞作綵衣。", "寂寂幔亭天籟息，笙簫疑向夜深歸。"]'),
('091ce567-9149-47e2-a091-a0d68ad368c2','遊武夷作  其二','陳韡','宋','宋诗','song-poetry','','[]','來爲羣元扣右扉，香生瓊宇碧油圍。',64,'全唐诗/poet.song.192000.json','["來爲羣元扣右扉，香生瓊宇碧油圍。", "前騶所過風俱靜，幽鳥不驚雲與飛。", "清嘯一山旋暮角，和蒸九曲未秋衣。", "勝遊英槩真奇遇，卷入豪端放棹歸。"]'),
('03e2beae-0404-4bb0-bf8c-5fb1b3e3e3a5','武夷築精舍','陳韡','宋','宋诗','song-poetry','','[]','浮世何嘗有定居，愜情便可著茅廬。',64,'全唐诗/poet.song.192000.json','["浮世何嘗有定居，愜情便可著茅廬。", "久知名利爲韁鎖，愛此溪山似畫圖。", "種菊疎籬慕陶令，栽梅淺水學林逋。", "只須此地延風月，休問君王乞鑑湖。"]'),
('f0cd9aba-36fa-44ba-adaa-49c322471358','初夏郊行','陳韡','宋','宋诗','song-poetry','','[]','羽檄暫稀槐晝永，出郊遠眺得神清。',64,'全唐诗/poet.song.192000.json','["羽檄暫稀槐晝永，出郊遠眺得神清。", "田間野水縱橫注，林外嬌鶑自在鳴。", "爲羨僧閑逢寺飲，要知民樂遶村行。", "逢迎尚有山花在，見識聞香不識名。"]'),
('ec98805f-8e44-430d-9d2f-052cd4972c3c','句','陳韡','宋','宋诗','song-poetry','','[]','寄語園丁勤剗草，有時病叟出看花。',16,'全唐诗/poet.song.192000.json','["寄語園丁勤剗草，有時病叟出看花。"]'),
('bd218d68-7031-4a69-a1b7-eedac12b7a00','挽德潤','方審權','宋','宋诗','song-poetry','','[]','力挽端平疏，追還元祐風。',144,'全唐诗/poet.song.192000.json','["力挽端平疏，追還元祐風。", "祇今名未正，自古直難容。", "去國身如葉，憂時鬢易蓬。", "轉輸煩計使，鎮撫仗元戎。", "化寓文章內，人游禮樂中。", "五年懷赤子，一念契蒼穹。", "寵僅優奎閣，言猶簡帝聰。", "頓忘前席召，虛抱死疆衷。", "預决同師魯，先知即了翁。", "至誠存素履，定力見臨終。", "族黨哲人逝，朝家善類空。", "我爲天下哭，非但哭吾崇。"]'),
('f86e1435-565f-44f4-9025-f3befe9aa789','題秀江亭','李宗勉','宋','宋诗','song-poetry','','[]','經行塔下幾春秋，每歎無緣到上頭。',32,'全唐诗/poet.song.192000.json','["經行塔下幾春秋，每歎無緣到上頭。", "今日登臨方覺險，不如歸去卧林丘。"]'),
('2401429c-eab6-478c-be74-7476dda63f91','句','林自知','宋','宋诗','song-poetry','','[]','公來無琴鶴，公去有芒鞋。',12,'全唐诗/poet.song.192000.json','["公來無琴鶴，公去有芒鞋。"]'),
('b923ba0c-d854-4d9f-9081-3018041705cd','夜泊浯溪  其一','董鴻道','宋','宋诗','song-poetry','','[]','艤舟和月上𢈪亭，風露淒寒酒易醒。',32,'全唐诗/poet.song.192000.json','["艤舟和月上𢈪亭，風露淒寒酒易醒。", "誰爲漫郎寫幽思，度香橋下水泠泠。"]'),
('6411db58-6910-4381-bef5-73d2ff8da572','夜泊浯溪  其二','董鴻道','宋','宋诗','song-poetry','','[]','二十年前八桂回，摩挲蒼蘚讀碑來。',32,'全唐诗/poet.song.192000.json','["二十年前八桂回，摩挲蒼蘚讀碑來。", "如今再自浯溪過，折得梅花伴酒杯。"]'),
('38b7240b-35fb-4bbc-a4ca-8420487ddebe','答友人二首  其一','戴仔','宋','宋诗','song-poetry','','[]','著書非爲進，歲久漫成編。',48,'全唐诗/poet.song.192000.json','["著書非爲進，歲久漫成編。", "道遇言非贅，身幽志自堅。", "種瓜新學圃，藝稻晚知田。", "吾事未多闕，衣裾莫浪褰。"]'),
('ba5a33a4-0731-4641-a1a9-689cad148a60','答友人二首  其二','戴仔','宋','宋诗','song-poetry','','[]','說經蠡測海，且欲付家藏。',48,'全唐诗/poet.song.192000.json','["說經蠡測海，且欲付家藏。", "難爲越言雪，徒令鬢似霜。", "荷君心見許，顧我道非長。", "若肯嬪王內，當爲時世裝。"]'),
('e94d7b35-e480-4518-8b32-1d9b27af4989','偶成','戴仔','宋','宋诗','song-poetry','','[]','尚想夷與齊，求仁無怨嘖。',24,'全唐诗/poet.song.192000.json','["尚想夷與齊，求仁無怨嘖。", "誰傳采薇音，荒哉太史筆。"]'),
('f1359d14-94f7-4d22-88ef-4ba66d5cb7ab','白水山','王栐','宋','宋诗','song-poetry','','[]','高空重素練，界斷碧山紋。',48,'全唐诗/poet.song.192000.json','["高空重素練，界斷碧山紋。", "雪浪衝天下，風濤带霧分。", "烏尖峰頂水，馿迹嶺頭雲。", "幾欲乘槎訪，星河沒夕曛。"]'),
('51482267-acb1-4a29-8064-3e5ed06be784','及第謝恩','吳必達','宋','宋诗','song-poetry','','[]','聖朝更化廣蒐賢，丹陛遥瞻穆穆天。',64,'全唐诗/poet.song.192000.json','["聖朝更化廣蒐賢，丹陛遥瞻穆穆天。", "歷數萬年垂統正，精微一理得心傳。", "輸忠敢罄劉蕡膽，擢第應同李郃肩。", "四海尚期王德洽，小臣稽首頌周篇。"]'),
('55228474-4137-4445-8967-ca7c69d198d2','句','鄭思忱','宋','宋诗','song-poetry','','[]','讀罷西銘日未斜。',8,'全唐诗/poet.song.192000.json','["讀罷西銘日未斜。"]'),
('cd47f889-d90d-43f2-b8d7-603eec2f1186','煉丹觀','黄甲','宋','宋诗','song-poetry','','[]','天地爲爐變化間，丹砂點石石成丹。',32,'全唐诗/poet.song.192000.json','["天地爲爐變化間，丹砂點石石成丹。", "丹成遺竈空陳迹，留與高人圖畫看。"]'),
('9fa86c46-eba4-4f78-8e88-1fa0e49205bc','石城峰','黄甲','宋','宋诗','song-poetry','','[]','岧峨第二石城峰，雉堞天然不費工。',32,'全唐诗/poet.song.192000.json','["岧峨第二石城峰，雉堞天然不費工。", "妙典飛昇何處是，城頭咫尺紫霞宮。"]'),
('1130908f-46d0-47dc-9d55-42e1eec6a1cf','桂林峰','黄甲','宋','宋诗','song-poetry','','[]','第八峰高是桂林，安期曾度馬明生。',32,'全唐诗/poet.song.192000.json','["第八峰高是桂林，安期曾度馬明生。", "箇中自有通仙路，拂袖天香影裏行。"]'),
('46432aba-15c3-4c55-980a-bf5e70abb9c3','第七渡','黄甲','宋','宋诗','song-poetry','','[]','仙源七渡更流長，鵝管瓶頭滴乳香。',32,'全唐诗/poet.song.192000.json','["仙源七渡更流長，鵝管瓶頭滴乳香。", "觸處巖前如雨瀉，舉瓢挹處訝天漿。"]'),
('f4ccecd8-6936-41de-8ca4-d1e58724ba56','第八渡','黄甲','宋','宋诗','song-poetry','','[]','八渡凉生五月秋，瓊花六出似浮漚。',32,'全唐诗/poet.song.192000.json','["八渡凉生五月秋，瓊花六出似浮漚。", "掬來睥睨真如雪，不覺輕寒動玉樓。"]'),
('c5b91359-0225-4cc1-a891-b1af7dde0f2f','永福寺','黄甲','宋','宋诗','song-poetry','','[]','永福叢林古道場，烟霞深處白雲堂。',32,'全唐诗/poet.song.192000.json','["永福叢林古道場，烟霞深處白雲堂。", "木魚堂下常虛設，擊動龍王無處藏。"]'),
('9d25e438-5ddb-431e-82d7-c8afb2b760a4','魯女觀','黄甲','宋','宋诗','song-poetry','','[]','見說當年魯女冠，長年向此餌金丹。',32,'全唐诗/poet.song.192000.json','["見說當年魯女冠，長年向此餌金丹。", "一朝羽化無人識，野鶴孤猿繞紫壇。"]'),
('1f4b6b23-a7c6-4473-ab89-1d1e879ec2aa','玉琯巖','黄甲','宋','宋诗','song-poetry','','[]','橋山往日葬衣冠，玉琯深藏在此山。',32,'全唐诗/poet.song.192000.json','["橋山往日葬衣冠，玉琯深藏在此山。", "料得當時十二牧，也隨龍駕到其間。"]'),
('0312658b-14d9-49fb-a810-38bbea26017d','月帔巖','黄甲','宋','宋诗','song-poetry','','[]','仙翁騎鶴上青冥，月帔空留松桂林。',32,'全唐诗/poet.song.192000.json','["仙翁騎鶴上青冥，月帔空留松桂林。", "遮斷世塵無點污，橫拖一抹翠烟深。"]'),
('593ef4f7-b264-4cdb-abd4-561b7a0fa7fa','羊權山','黄甲','宋','宋诗','song-poetry','','[]','聞道仙人萼綠華，曾來此地訪仙家。',32,'全唐诗/poet.song.192000.json','["聞道仙人萼綠華，曾來此地訪仙家。", "青衣數十隨行處，環珮紛紛香霧車。"]'),
('075adcba-270d-4ead-903a-157a49d9b2d8','白孩兒蓮','黄甲','宋','宋诗','song-poetry','','[]','玉質冰姿出淤泥，花間朶朶簇孩兒。',32,'全唐诗/poet.song.192000.json','["玉質冰姿出淤泥，花間朶朶簇孩兒。", "不因潔白身清凈，安得靈根孕九疑。"]'),
('7b07b5ce-f878-412a-842d-0bc1f426f4e6','龍鬚草','黄甲','宋','宋诗','song-poetry','','[]','龍卧寒潭漾碧虛，風雲變化只須臾。',32,'全唐诗/poet.song.192000.json','["龍卧寒潭漾碧虛，風雲變化只須臾。", "奮髯驤首無人問，錯認巖頭草似鬚。"]'),
('ee875d56-1b39-45b1-8122-499624ac91f5','題趙千里夜潮圖','周假庵','宋','宋诗','song-poetry','','[]','烟蒼蒼，江茫茫，明月夜挂天中央。',92,'全唐诗/poet.song.192000.json','["烟蒼蒼，江茫茫，明月夜挂天中央。", "奔潮不盡當日恨，金波怒，捲虯龍。", "長浦口，秋飛揚，鷗雁不眠聲周章。", "風高沙漲望難到，羽翰但逐潮低昂。", "窗間簾炷香，開卷有素商。", "何須八月上錢唐，對此秋濤生錦囊。"]'),
('9ec13be4-634e-45bf-b6df-21ac2220ab6f','贈胡季昭','葉夢得','宋','宋诗','song-poetry','','[]','澹菴久死瘴江濱，依舊歸來侍禁宸。',80,'全唐诗/poet.song.192000.json','["澹菴久死瘴江濱，依舊歸來侍禁宸。", "浩歎宗孫長去國，從知志士不謀身。", "皇天若假令多算，聖代終無棄□□。", "我時閲報痛生哀，灑淚南詹吊象臺。", "今日方知公有子，皇天祐善世生才。"]'),
('842e3f31-028f-41da-90a4-3df2db6132d0','鵝湖山','葉夢得','宋','宋诗','song-poetry','','[]','鵝王牧群鵝，濁世肯下遊。',168,'全唐诗/poet.song.192000.json','["鵝王牧群鵝，濁世肯下遊。", "積水近天闕，有時戲沉浮。", "老禪天人師，領略傾九州。", "初開選佛場，坐斷諸峰頭。", "當時江東西，海納吞衆流。", "歲晚徙山麓，華堂跨龍樓。", "至今韋公碑，照耀蒼崖幽。", "陳迹記往昔，登臨縱冥搜。", "重來歲月疾，俯仰五十秋。", "撫事一太息，何從問馬牛。", "惟餘拱把木，百尺環道周。", "成壞各有時，干戈今少休。", "空懷三宿戀，爲汝半日留。", "鐘聲遠送客，霧雨昏林丘。"]'),
('f82c3b9c-f9b9-4e07-b898-443b1682bff5','石井','葉夢得','宋','宋诗','song-poetry','','[]','神龍傲幽蟄，睡美得所安。',132,'全唐诗/poet.song.192000.json','["神龍傲幽蟄，睡美得所安。", "宇宙豈不廣，斂收寄深蟠。", "不知九地藏，何似海濱寬。", "謾作無底竇，言依小巑岏。", "微流出紺地，碧玉儲清寒。", "亂木共蒼翠，佛宮蔭檀欒。", "寧懷帝者家，未暇排雲端。", "油雲有時去，霧雨森濛漫。", "聊從老農戲，旱魃不可干。", "客行度嵌巖，塵土疲跨鞍。", "願借壁間瓢，一飲凉肺肝。"]'),
('665ba3e8-7f90-4360-8219-07ff450cc050','游洞霄','薛泳','宋','宋诗','song-poetry','','[]','群山皆玉立，中有一峰危。',48,'全唐诗/poet.song.192000.json','["群山皆玉立，中有一峰危。", "天近秋雲薄，松深夜月遲。", "洞因尋藥入，席爲聽泉移。", "此趣無人會，臨風酒一巵。"]'),
('5bb8d0b9-6772-465d-8015-b64e0c51c1d1','句  其一','薛泳','宋','宋诗','song-poetry','','[]','柳斷橋方出，烟深寺欲浮。',12,'全唐诗/poet.song.192000.json','["柳斷橋方出，烟深寺欲浮。"]'),
('650065ba-7579-44fa-8210-3b10358ccece','句  其二','薛泳','宋','宋诗','song-poetry','','[]','歸心如病葉，一片落江城。',12,'全唐诗/poet.song.192000.json','["歸心如病葉，一片落江城。"]'),
('73937b0e-9e1e-4a5c-b948-c57aa85f41f4','寄薛泳','杜北山','宋','宋诗','song-poetry','','[]','長安君別後，動即是相思。',48,'全唐诗/poet.song.192000.json','["長安君別後，動即是相思。", "料想還家日，勝如爲客時。", "江寒驚夢斷，路遠得書遲。", "幾度空凝望，春風又柳絲。"]'),
('b26b5078-45fc-41d1-ba79-3d180842f548','寄吳夢鶴','杜北山','宋','宋诗','song-poetry','','[]','憐君如泛梗，漂泊竟何之。',48,'全唐诗/poet.song.192000.json','["憐君如泛梗，漂泊竟何之。", "經歲無來信，還家是幾時。", "秋高鴻過少，地冷菊開遲。", "屢夕寒燈下，秋吟只自知。"]'),
('4f102d8c-d0ea-49ed-b719-c3f37c058c8e','元日','趙淦夫','宋','宋诗','song-poetry','','[]','鳳曆首春王，三元啟運昌。',48,'全唐诗/poet.song.192000.json','["鳳曆首春王，三元啟運昌。", "衣冠充閭里，雲物動笙簧。", "共舞椒花醉，真成機械忙。", "人生當此日，何必古羲皇。"]'),
('2248dba0-0d68-44f1-add4-f29bd9d63393','禱正一真君','夏元鼎','宋','宋诗','song-poetry','','[]','未登龍虎榜，且登龍虎山。',48,'全唐诗/poet.song.192000.json','["未登龍虎榜，且登龍虎山。", "一見三清易，三年一第難。", "劍埋光射斗，雞鳴曉度關。", "乾坤誰整頓，擬伴赤松閒。"]'),
('25133c12-9a00-4bb4-8450-e01d811d38a8','題壁二首  其一','夏元鼎','宋','宋诗','song-poetry','','[]','世學金丹亂似麻，謾將心腎向人誇。',32,'全唐诗/poet.song.192000.json','["世學金丹亂似麻，謾將心腎向人誇。", "眼前有藥無人識，火裏栽蓮長道芽。"]'),
('1117f301-b574-4e19-b4f7-8baa86016337','題壁二首  其二','夏元鼎','宋','宋诗','song-poetry','','[]','崆峒訪道屈尊乎，萬卷丹書看轉愚。',32,'全唐诗/poet.song.192000.json','["崆峒訪道屈尊乎，萬卷丹書看轉愚。", "着破鐵鞋無覓處，得師全不費功夫。"]'),
('994ef85f-2744-4cf7-867a-7c41328842c3','黄鶴樓','游似','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','長江巨浪拍天浮，城郭相望萬景收。',64,'全唐诗/poet.song.192000.json','["長江巨浪拍天浮，城郭相望萬景收。", "漢水北吞雲夢入，蜀江西带洞庭流。", "角聲交送千家月，帆影中分兩岸秋。", "黄鶴樓高人不見，却隨鸚鵡過汀洲。"]'),
('3347fd59-457a-469e-9870-5f55ca29ce61','登雲巖塔二絕  其一','方萬里','宋','宋诗','song-poetry','','[]','湖迥山明玉宇澄，浮圖絕頂快高登。',32,'全唐诗/poet.song.192000.json','["湖迥山明玉宇澄，浮圖絕頂快高登。", "天風吹我今宵夢，多在瑶臺十二層。"]'),
('37ea4d9a-8713-4339-8deb-440e903d06ee','登雲巖塔二絕  其二','方萬里','宋','宋诗','song-poetry','','[]','窣堵崔嵬置曲欄，不知身在碧雲端。',32,'全唐诗/poet.song.192000.json','["窣堵崔嵬置曲欄，不知身在碧雲端。", "墨題便是慈恩約，只尺聯鑣上廣寒。"]'),
('51a63b44-35fe-4515-bfd7-3abd28dd1b46','齊雲菴','文洪源','宋','宋诗','song-poetry','','[]','齊雲山特立，古剎懸危壁。',84,'全唐诗/poet.song.192000.json','["齊雲山特立，古剎懸危壁。", "翠竹舞柔風，高峰聳紅日。", "龍井冽生寒，冰房清澈骨。", "半空神氣怡，恍入羣仙窟。", "仰盼天河明，俯濯龍潭碧。", "白雲任去留，好鳥時棲息。", "一笑塵世空，此樂復何極。"]'),
('bc0d77a4-f771-4ee5-828b-0c8a1b49d386','雁湖','史公亮','宋','宋诗','song-poetry','','[]','梅艷凌霜带雪餘，露華洗盡玉生膚。',32,'全唐诗/poet.song.192000.json','["梅艷凌霜带雪餘，露華洗盡玉生膚。", "東方千騎催人去，聊折春風寄雁湖。"]'),
('c3e589f6-b069-4ff0-89f9-c98fe31d53f5','賀人生女','王大烈','宋','宋诗','song-poetry','','[]','祥光子夜都明徹，婷婷仙子來仙闕。',64,'全唐诗/poet.song.192000.json','["祥光子夜都明徹，婷婷仙子來仙闕。", "精神玉雪比不如，猶带蓬萊秋夜月。", "郎罷今晨莫世情，那知便不顯門庭。", "我來只誦香山句，不重生男重生女。"]'),
('1953a1f1-3bb8-4d2e-aa70-1a92765b438e','賀生子索杯','王大烈','宋','宋诗','song-poetry','','[]','小童門外走雙壺，知是君家毓掌珠。',64,'全唐诗/poet.song.192000.json','["小童門外走雙壺，知是君家毓掌珠。", "前語果然符老蚌，這番不可學乾烏。", "且將詩句爲君問，還有婆杯惠我無。", "莫怪明朝東閣地，要教泥醉索人扶。"]'),
('6de768bc-eaff-4540-8c24-6584c78fdb1e','絕句','王大烈','宋','宋诗','song-poetry','','[]','弧矢重懸舊禮儀，郎君又産玉麟兒。',32,'全唐诗/poet.song.192000.json','["弧矢重懸舊禮儀，郎君又産玉麟兒。", "便煩着眼從頭看，的似徐卿二子奇。"]'),
('f187775d-501f-41ee-ba9d-92f347948da8','律詩','王大烈','宋','宋诗','song-poetry','','[]','纔入新秋節，君家又得珠。',48,'全唐诗/poet.song.192000.json','["纔入新秋節，君家又得珠。", "石麟天上種，丹鳳穴中雛。", "喜羨徐卿有，休誇伯道無。", "他年雙折桂，携手上雲衢。"]'),
('5118060f-adfb-42d7-84c9-3808eaa21243','自慶生次子','王大烈','宋','宋诗','song-poetry','','[]','屈指春歸三月餘，葱葱佳氣應充閭。',64,'全唐诗/poet.song.192000.json','["屈指春歸三月餘，葱葱佳氣應充閭。", "人言再入長庚夢，我喜新添萬卷書。", "栗愛從渠自年少，蘭芬看爾長庭除。", "吾家積善由來久，當繼公侯衮衮餘。"]'),
('13a11012-2b77-4431-a673-fecc52e7e6f8','賀人雙生','王大烈','宋','宋诗','song-poetry','','[]','白石山川貴可知，公侯衮衮應斯時。',64,'全唐诗/poet.song.192000.json','["白石山川貴可知，公侯衮衮應斯時。", "藍田美玉雙呈瑞，滄海明珠兩朶奇。", "從此一門成薛鳳，如今三子勝徐麒。", "東君更有靈椿壽，看取他年折桂枝。"]'),
('5697676f-2262-4d03-9bf9-8cfa85ec1354','賀生次子','王大烈','宋','宋诗','song-poetry','','[]','昔也惟珍一角麟，如今雙璧更驚人。',32,'全唐诗/poet.song.192000.json','["昔也惟珍一角麟，如今雙璧更驚人。", "今朝蘇子晉朝陸，許事從初又一新。"]'),
('1db267fc-3aac-48ba-b1b5-a0a8be7435df','王氏螟羅氏子','王大烈','宋','宋诗','song-poetry','','[]','庚星一點光無涯，日來飛入江東家。',96,'全唐诗/poet.song.192000.json','["庚星一點光無涯，日來飛入江東家。", "江東江左舊聲氣，叔氏得之真差事。", "歸來瑞光凌九虛，叔氏喜亦盈眉鬚。", "家人驚起偏物色，袖中却得真英物。", "螟蛉須信逢蜾蠃，莫惜丁甯長類我。", "他年解有速肖時，會振風流舊江左。"]'),
('69ff8c47-4ed0-4e18-b4e6-d35cb9d5976e','賀人生子  其一','王大烈','宋','宋诗','song-poetry','','[]','蚌胎未老出明珠，或表高門慶有餘。',64,'全唐诗/poet.song.192000.json','["蚌胎未老出明珠，或表高門慶有餘。", "我病阻爲湯餠客，人言的是鳳凰雛。", "磽磽頭角奇男子，衮衮公侯大丈夫。", "寄語王渾防跨竈，阿戎清賞只須臾。"]'),
('b45775c0-643c-4b41-8324-55ab77c6b412','賀人生子  其二','王大烈','宋','宋诗','song-poetry','','[]','盡道生來骨相奇，若非鳳種必麟兒。',64,'全唐诗/poet.song.192000.json','["盡道生來骨相奇，若非鳳種必麟兒。", "幾年仙李蟠根固，一顆蟠桃結子遲。", "岐嶷兩全真鮮克，之無二字已先知。", "徐卿衣鉢今傳取，衮衮公侯看異時。"]'),
('ee567981-d9e4-4301-95b9-6aa8f0aa080f','自贊','葉元素','宋','宋诗','song-poetry','','[]','心事茫然兩鬢斑，十年空走利名關。',32,'全唐诗/poet.song.192000.json','["心事茫然兩鬢斑，十年空走利名關。", "算來只合苔磯坐，釣不得魚猶得閒。"]'),
('a73f0f0e-4222-47e7-8d5a-45311026bb05','絕句','葉元素','宋','宋诗','song-poetry','','[]','家住夕陽江上村，一灣流水護柴門。',32,'全唐诗/poet.song.192000.json','["家住夕陽江上村，一灣流水護柴門。", "種來松樹高于屋，借與春禽養子孫。"]'),
('10797e2e-7d0e-4070-ae2b-288046b1bf9d','漁家雜興','葉元素','宋','宋诗','song-poetry','','[]','鳴榔聲裏過吳松，月似銀槃貼水中。',32,'全唐诗/poet.song.192000.json','["鳴榔聲裏過吳松，月似銀槃貼水中。", "網得錦鱗魚數尾，豈無一尾是蛟龍。"]'),
('1aa7fab8-e3c5-4635-9d3f-7c7111433b98','留宿山家','葉元素','宋','宋诗','song-poetry','','[]','山翁留我宿，行倦看羣捷。',48,'全唐诗/poet.song.192000.json','["山翁留我宿，行倦看羣捷。", "黄□滿山落，白猿終夜啼。", "枕邊千里夢，窗外一聲雞。", "明日登程去，何村日又西。"]'),
('b914857b-b0ca-43ba-a9e1-cbb6735a3b43','山寺','葉元素','宋','宋诗','song-poetry','','[]','一樹桃花一半空，不堪狼籍梵王宮。',32,'全唐诗/poet.song.192000.json','["一樹桃花一半空，不堪狼籍梵王宮。", "山僧手把青鸞尾，背却東風掃落紅。"]'),
('e6b4bd0a-90a9-4741-899d-389d65eac49a','送友人從軍','葉元素','宋','宋诗','song-poetry','','[]','斗酒不爲薄，餞君千里行。',48,'全唐诗/poet.song.192000.json','["斗酒不爲薄，餞君千里行。", "時危見豪傑，年少易功名。", "旗影龍蛇動，甲光霜雪明。", "天山三箭定，不請羽林兵。"]'),
('f3efde28-d4c1-43b3-a193-30a0344259dc','次韻何安節撫機','丁木','宋','宋诗','song-poetry','','[]','送別邗江路，梅花作暮愁。',48,'全唐诗/poet.song.192000.json','["送別邗江路，梅花作暮愁。", "關情何水部，回首古揚州。", "雁影明寒水，冰凘澀去舟。", "想應今夜宿，霜月滿瓜洲。"]'),
('cac839cc-3738-45ff-8295-aa684f7b9bba','聞兄衜竄作詩寄之','張磻','宋','宋诗','song-poetry','','[]','飛旆翩然拂曙涼，都門餞送集冠裳。',64,'全唐诗/poet.song.192000.json','["飛旆翩然拂曙涼，都門餞送集冠裳。", "竄鄉此去嗟予季，忠國古來留異方。", "賈誼誰云時不遇，酈生自謂我非狂。", "橫江一網空朝市，何物充庖薦廟廊。"]'),
('b1200b61-a571-4eff-8273-e9ffb3ae80b5','採藥徑','朱元昇','宋','宋诗','song-poetry','','[]','黄精與鉤吻，貌同性相反。',24,'全唐诗/poet.song.192000.json','["黄精與鉤吻，貌同性相反。", "寄詩徑中人，采時高著眼。"]'),
('c9c8de95-9555-40ba-9e06-0d0b32ea1d60','曉雲峰','朱元昇','宋','宋诗','song-poetry','','[]','旱天無覓處，曉雲此無數。',24,'全唐诗/poet.song.192000.json','["旱天無覓處，曉雲此無數。", "只消一縷飛，亦可作甘露。"]'),
('ba1e3eb2-9921-48ef-9aef-707422e9dbaa','月牖','朱元昇','宋','宋诗','song-poetry','','[]','誰將造化手，開此混沌竅。',24,'全唐诗/poet.song.192000.json','["誰將造化手，開此混沌竅。", "每夜吐月時，九州同一照。"]'),
('c12cde61-eb1f-4dee-be4b-5bb04c6e5c29','天馬峰','朱元昇','宋','宋诗','song-poetry','','[]','塞上風塵高，處處尋天馬。',24,'全唐诗/poet.song.192000.json','["塞上風塵高，處處尋天馬。", "只在此山中，無人到圖寫。"]'),
('7ba71576-31f5-46fb-9b31-66e5bf68d683','龍角巖','朱元昇','宋','宋诗','song-poetry','','[]','本是一頑石，偶如龍角象。',24,'全唐诗/poet.song.192000.json','["本是一頑石，偶如龍角象。", "至今渴仰人，便作風雷想。"]'),
('f9871cba-1cc3-43d6-9c2a-a5d35ec105ce','龍隠巖','朱元昇','宋','宋诗','song-poetry','','[]','巖根嵐霧深，神龍隠其所。',24,'全唐诗/poet.song.192000.json','["巖根嵐霧深，神龍隠其所。", "莫恃雲霄近，容易興雲雨。"]'),
('4b1755c4-e0a1-42dd-87e3-6f9a7f7df151','天聰洞','朱元昇','宋','宋诗','song-poetry','','[]','雲開巖玲瓏，一竅入虛空。',24,'全唐诗/poet.song.192000.json','["雲開巖玲瓏，一竅入虛空。", "亦有閭閻事，何當叩上穹。"]'),
('74f6704b-7248-4509-a2c0-d4d3878da910','應潮潭','朱元昇','宋','宋诗','song-poetry','','[]','羣山雖疊嶂，大海暗來通。',24,'全唐诗/poet.song.192000.json','["羣山雖疊嶂，大海暗來通。", "氣類倘相應，寸心千里同。"]'),
('543e22f1-fa95-4708-b7cc-b9be0a281e0b','挽蔡西山先生','李閎祖','宋','宋诗','song-poetry','','[]','有名天所靳，無位世仍擠。',48,'全唐诗/poet.song.192000.json','["有名天所靳，無位世仍擠。", "不得西山卧，還同濂水棲。", "元精抽秘鑰，衆妙貫圓機。", "友盡人間士，巋然季子題。"]'),
('b674d2db-fed1-4dc4-8f9d-58b617e63996','華子岡','鄒斌','宋','宋诗','song-poetry','','[]','風流晉人物，康樂性樂山。',84,'全唐诗/poet.song.192000.json','["風流晉人物，康樂性樂山。", "文選數十詩，大半皆林泉。", "未知當時士，多少肥遯賢。", "投書犯世網，何如康樂阡。", "小隠華子岡，世事成雲烟。", "高風輞川期，師法甪里傳。", "倘悟神仙訣，千載如眼前。"]'),
('1a582a61-bc5b-47ad-8b9e-b16e94bee22d','萬峰菴','黄登','宋','宋诗','song-poetry','','[]','上到山巔曉色分，眼看殘月待朝昕。',64,'全唐诗/poet.song.192000.json','["上到山巔曉色分，眼看殘月待朝昕。", "望迷四顧渾如海，立欲移時祇是雲。", "隠隠樓臺平地見，行行鐘磬半天聞。", "舉頭頓覺青霄近，我欲乘風謁帝君。"]'),
('a99d9d02-9b04-4ff7-8185-be56578f75f5','題三岩  其一','黄登','宋','宋诗','song-poetry','','[]','占斷烟霞老一丘，玉岩閲歷幾春秋。',64,'全唐诗/poet.song.192000.json','["占斷烟霞老一丘，玉岩閲歷幾春秋。", "削成四壁開三面，比似他山出一頭。", "幾欲登臨尋勝概，偶然休沐得佳遊。", "醉磨濃墨書岩石，恨不携琴更少留。"]'),
('bc41743c-fdd8-4882-9a66-8f8711659e20','題三岩  其二','黄登','宋','宋诗','song-poetry','','[]','飄然投紱卧雲林，一片平生鐵石心。',64,'全唐诗/poet.song.192000.json','["飄然投紱卧雲林，一片平生鐵石心。", "不是遺文能動我，誰令弔古便沾襟。", "身同逝水幾寒暑，名在空山無古今。", "仰止高風琴牀下，還教三嘆薄朝簪。"]'),
('c713c866-39c3-48b1-881f-c5a0317419e2','句','趙絳夫','宋','宋诗','song-poetry','','[]','取水觀爲政。',6,'全唐诗/poet.song.192000.json','["取水觀爲政。"]'),
('8649536f-aae1-4730-9276-81abc6fdb1ba','跋山谷書范滂傳帖','俞疇','宋','宋诗','song-poetry','','[]','貂璫羣雛擅天網，手驅名流入鈎黨。',256,'全唐诗/poet.song.192000.json','["貂璫羣雛擅天網，手驅名流入鈎黨。", "屯雲蔽日日光無，卯金神器春冰上。", "汝南節士居危邦，志剗蕭艾扶蘭芳。", "致君生不逮堯舜，死合夷齊俱首陽。", "千年興壞真暮旦，殷鑒詎應如許遠。", "安知後人哀後人，又起諸賢落南歎。", "宜州老子筆有神，蟬蛻顔揚端逼真。", "少模龍爪已名世，晚用鷄毛亦絕人。", "平生孟博吾尚友，時事駸駸建寧舊。", "胸蟠萬卷老蠻鄉，獨感斯文聊運肘。", "老子書名橫九州，一紙千金不當酬。", "此書豈但翰墨設，心事悢悢關百憂。", "人言老子味禪悅，疾惡視滂寧爾切。", "須知許國本精忠，不幸爲滂甘伏節。", "九原莫作令人悲，遺墨敗素皆吾師。", "從君乞取宜州字，要對崇寧黨籍碑。"]'),
('da1ead08-b06e-4a0d-ba41-26b089175f74','君山浮遠堂','王呈瑞','宋','宋诗','song-poetry','','[]','萬室東南裏，炊煙落照黄。',48,'全唐诗/poet.song.192000.json','["萬室東南裏，炊煙落照黄。", "山腰圍野闊，沙尾刺江長。", "好景終然遠，浮雲轉已亡。", "幾多如湛輩，今昔一淒涼。"]'),
('62e720f4-da90-4bbd-8a0b-3f57ed571250','芙蓉峰','鄭芝秀','宋','宋诗','song-poetry','','[]','芙蓉秀插最高峰，上有仙臺近碧空。',32,'全唐诗/poet.song.192000.json','["芙蓉秀插最高峰，上有仙臺近碧空。", "不憚攀蘿登絕頂，俯看塵世一樊籠。"]'),
('688e5072-7003-45d1-ad0d-1e64d0d63f39','鴟夷子皮贊','李華','宋','宋诗','song-poetry','','[]','龍蟠幽谷，非時則伏。',60,'全唐诗/poet.song.193000.json','["龍蟠幽谷，非時則伏。", "蟬蛻高枝，飲露而飛。", "進如風行，退若雲歸。", "冥冥其幾，赫赫其居。", "于越霸興，强吳蕩夷。", "功成不居，先生得之。"]'),
('4f264f45-1c19-4a41-8eb6-32f00cf6e45c','戊寅入嶺丁亥上元遊碧落洞','李華','宋','宋诗','song-poetry','','[]','乳床奇詭鑑清漣，碧落真人古洞天。',32,'全唐诗/poet.song.193000.json','["乳床奇詭鑑清漣，碧落真人古洞天。", "十載南遊纔一到，不訪重補到難篇。"]'),
('1eaa1597-516b-45a1-a7c2-06df897d34ea','句','李華','宋','宋诗','song-poetry','','[]','後夜鬰孤臺上月，更從何處照詩人。',16,'全唐诗/poet.song.193000.json','["後夜鬰孤臺上月，更從何處照詩人。"]'),
('40602a3d-024e-4a81-9545-4a48cde21d2d','句','李知孝','宋','宋诗','song-poetry','','[]','秋雨梧桐皇子宅，春風楊柳相公橋。',16,'全唐诗/poet.song.193000.json','["秋雨梧桐皇子宅，春風楊柳相公橋。"]'),
('03e4b055-4efc-47b6-9fb4-21765e5934a5','妙相寺清節軒','徐良弼','宋','宋诗','song-poetry','','[]','此君高節抗浮雲，環寺幽亭分外清。',64,'全唐诗/poet.song.193000.json','["此君高節抗浮雲，環寺幽亭分外清。", "凌厲雪霜真有守，招邀日月自多情。", "更無一點紅塵到，但覺中襟爽氣生。", "爭似南牆相對處，蕭蕭流水遶除鳴。"]'),
('429c537e-343b-4f1b-9214-f851ec1bd93b','桃花洲','徐良弼','宋','宋诗','song-poetry','','[]','歷騁禪扉到暮鐘，苦無勝事可深窮。',32,'全唐诗/poet.song.193000.json','["歷騁禪扉到暮鐘，苦無勝事可深窮。", "歸來喚渡青溪上，唯有山桃滿路紅。"]'),
('6ee6674f-aee5-4a83-a6f1-e9bdc5be5b4c','秋霜閣','徐良弼','宋','宋诗','song-poetry','','[]','秋霜閣下水潺潺，一片清泉漱玉寒。',32,'全唐诗/poet.song.193000.json','["秋霜閣下水潺潺，一片清泉漱玉寒。", "試把塵襟來此濯，要看披腹吐琅玕。"]'),
('a0c3ced5-af37-472b-8583-c41c6897b8dc','東峰亭','徐良弼','宋','宋诗','song-poetry','','[]','東峰亭上共徜徉，列嶂低銜夕照黄。',32,'全唐诗/poet.song.193000.json','["東峰亭上共徜徉，列嶂低銜夕照黄。", "酒興未闌歸騎促，一鷗輕泛白雲鄉。"]'),
('328db806-c906-471f-bb39-17e85c584636','句','徐良弼','宋','宋诗','song-poetry','','[]','青春不再汝知乎。',8,'全唐诗/poet.song.193000.json','["青春不再汝知乎。"]'),
('d8457706-0942-4308-9f2a-39c8840aa4b1','題張氏十詠圖','陳振孫','宋','宋诗','song-poetry','','[]','平生聞說張三影，十詠誰知有乃翁。',64,'全唐诗/poet.song.193000.json','["平生聞說張三影，十詠誰知有乃翁。", "逢世昇平百年久，與齡耆艾一家同。", "名賢敘述文章好，勝事流傳繪素工。", "遐想盛時生恨晚，恍如身在畫圖中。"]'),
('759fe6af-434d-4a54-ad2b-dd8e51bb6f32','題浯溪','趙某','宋','宋诗','song-poetry','','[]','元頌顔書□□□，好風吹我過三吾。',48,'全唐诗/poet.song.193000.json','["元頌顔書□□□，好風吹我過三吾。", "倚空□□煙雲□，□古興亡草木枯。", "讀盡□□留□□，□□□□較錙銖。"]'),
('9eab815f-f03d-4c31-bb6a-d8f3a7ce8212','絕句','趙範','宋','宋诗','song-poetry','','[]','半窗圖畫梅花月，一枕波濤松樹風。',32,'全唐诗/poet.song.193000.json','["半窗圖畫梅花月，一枕波濤松樹風。", "不是客愁眠不得，此山詩在此香中。"]'),
('fe8c225f-b888-46fc-9628-f267789002de','梅花','鄭會','宋','宋诗','song-poetry','','[]','江梅欲雪樹槎牙，雪片飄零梅片斜。',32,'全唐诗/poet.song.193000.json','["江梅欲雪樹槎牙，雪片飄零梅片斜。", "半有和風到窗紙，不知是雪是梅花。"]'),
('a3df3e6e-0948-46d0-ba66-2e86feee042d','楊柳','鄭會','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶別東湖兩度春，西湖柳眼又新新。',32,'全唐诗/poet.song.193000.json','["憶別東湖兩度春，西湖柳眼又新新。", "想因一樣湖邊柳，一樣春風一樣青。"]'),
('3122532b-e456-4953-993e-f57eb7517e99','題邸間壁','鄭會','宋','宋诗','song-poetry','','[]','酴釄香夢怯春寒，翠掩重簾燕子閒。',32,'全唐诗/poet.song.193000.json','["酴釄香夢怯春寒，翠掩重簾燕子閒。", "敲斷玉釵紅燭冷，計程應說到常山。"]'),
('af7a6f80-72e2-49bc-bb8f-273781802483','游金精山','鄭會','宋','宋诗','song-poetry','','[]','春風棧閣曉雲寒，中有潺潺一玉灣。',32,'全唐诗/poet.song.193000.json','["春風棧閣曉雲寒，中有潺潺一玉灣。", "白石寨盤青石磴，蘚花猶带漢時斑。"]'),
('db2d1835-e854-48dd-b9f4-735edcab71d1','簡頡監酒','鄭會','宋','宋诗','song-poetry','','[]','小立西風翠袖垂，淡黄蛺蝶□高低。',32,'全唐诗/poet.song.193000.json','["小立西風翠袖垂，淡黄蛺蝶□高低。", "重門不鎖秋香冷，何處人家有木犀。"]'),
('3eb0cf88-d827-455f-acc7-5cdc007c89cf','謝送酒','鄭會','宋','宋诗','song-poetry','','[]','刺豹朝淋血，烹龍莫泣脂。',48,'全唐诗/poet.song.193000.json','["刺豹朝淋血，烹龍莫泣脂。", "分君新甕盎，及我舊鴟夷。", "竹葉供浮蟻，春風入朶頤。", "扶衰拜嘉惠，時復一中之。"]'),
('3e82fa35-3a92-4fb0-872d-a310ffc406cc','懷宣州李司法','鄭會','宋','宋诗','song-poetry','','[]','憶着宣城郡，能詩李法曹。',48,'全唐诗/poet.song.193000.json','["憶着宣城郡，能詩李法曹。", "秋今已過半，夢亦罕相遭。", "風葉亂無數，雨螢飛不高。", "獨來窗下坐，燈影照離騷。"]'),
('0e7ec19f-1faa-471d-9dbc-af569cd6ee6d','寒夜懷鄭澤民','鄭會','宋','宋诗','song-poetry','','[]','布袍寒旋整，圖事少曾諧。',48,'全唐诗/poet.song.193000.json','["布袍寒旋整，圖事少曾諧。", "挈屋來游浙，修弓欲渡淮。", "家貧遲遣妹，母老苦爲懷。", "深夜青燈坐，思君命亦乖。"]'),
('3c14086e-5832-45bd-a910-435d3954eaea','寄江西友人','鄭會','宋','宋诗','song-poetry','','[]','浮雲浄盡倚欄干，西望南樓未得還。',32,'全唐诗/poet.song.193000.json','["浮雲浄盡倚欄干，西望南樓未得還。", "怕有舊人相借問，爲梅移屋近孤山。"]'),
('414e3566-c989-4246-b2da-8f40d0520065','寄棲賢渙上人','鄭會','宋','宋诗','song-poetry','','[]','棲賢橋下水流沙，開了菖蒲幾度花。',32,'全唐诗/poet.song.193000.json','["棲賢橋下水流沙，開了菖蒲幾度花。", "想得老師無別事，亂雲晴日補袈裟。"]'),
('e9daa3f9-7a68-477d-99d7-1255970a7045','寄熊秋堂','鄭會','宋','宋诗','song-poetry','','[]','醉踏青山憶舊游，兩年流落古杭州。',32,'全唐诗/poet.song.193000.json','["醉踏青山憶舊游，兩年流落古杭州。", "夢隨雲影忽東去，石上蘚花無限秋。"]'),
('58e88357-6878-4647-8adc-e86cd133001f','寄焦瑩中在南康','鄭會','宋','宋诗','song-poetry','','[]','冬青花落麥登秋，幾度相思欲買舟。',32,'全唐诗/poet.song.193000.json','["冬青花落麥登秋，幾度相思欲買舟。", "近日客來因問訊，又聞觸熱過池州。"]'),
('87132f58-e008-4ddd-8d61-8880ea25799d','酬余判院','鄭會','宋','宋诗','song-poetry','','[]','新篇如許好，欲和費沉思。',48,'全唐诗/poet.song.193000.json','["新篇如許好，欲和費沉思。", "相聚不爲淺，能吟獨未知。", "柳含春細細，梅待雪遲遲。", "重碧沽官酒，今當與說詩。"]'),
('c32e2a76-b1d9-48ce-8165-a7290d45ec50','答田耕叟','鄭會','宋','宋诗','song-poetry','','[]','五字推敲苦，君來尉所思。',48,'全唐诗/poet.song.193000.json','["五字推敲苦，君來尉所思。", "眼雖如舊識，心即要相知。", "屋冷雲歸早，窗深月過遲。", "過從無百步，清話綣論語。"]'),
('6bfa4c2b-5a1b-4ce2-8ef2-6040516fd734','聞黄叔敏雙陸因寄','鄭會','宋','宋诗','song-poetry','','[]','水晶簾動影傞傞，白玉棋盤金字窠。',32,'全唐诗/poet.song.193000.json','["水晶簾動影傞傞，白玉棋盤金字窠。", "贏得阿誰花十八，日長深院笑聲多。"]'),
('7b43a826-937e-4aa2-834e-1b919d79b25d','橘修鄉事','鄭會','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','壓囊紅溜滴真珠，配食江南赤鯉魚。',32,'全唐诗/poet.song.193000.json','["壓囊紅溜滴真珠，配食江南赤鯉魚。", "今日錢塘江上客，自憐吾亦愛吾廬。"]'),
('815ea528-21fc-4d66-9e5c-32f9f08e69bf','衢州道中','鄭會','宋','宋诗','song-poetry','','[]','生色薔薇插鬢斜，閑隨女伴摘新茶。',32,'全唐诗/poet.song.193000.json','["生色薔薇插鬢斜，閑隨女伴摘新茶。", "回頭見客低頭笑，却拾殘花貼面花。"]'),
('f87f114f-9138-4c0b-a871-6f55714d759c','寧都縣道中','鄭會','宋','宋诗','song-poetry','','[]','綠水橋頭小釣車，數椽敗屋柱槎牙。',32,'全唐诗/poet.song.193000.json','["綠水橋頭小釣車，數椽敗屋柱槎牙。", "年年賊火無人住，風落棠梨幾片花。"]'),
('24037f24-a61b-4e7b-b041-d699058f7ac1','瑞金縣道中','鄭會','宋','宋诗','song-poetry','','[]','野水深深小逕斜，舊時聞是富人家。',32,'全唐诗/poet.song.193000.json','["野水深深小逕斜，舊時聞是富人家。", "亂餘田地渾無主，近有流移來種麻。"]'),
('20b7b0ac-dddb-4115-aa50-dace6ecc3c57','九日奉新道中','鄭會','宋','宋诗','song-poetry','','[]','嫩寒獵獵酒旗斜，古路西風欲暮鴉。',32,'全唐诗/poet.song.193000.json','["嫩寒獵獵酒旗斜，古路西風欲暮鴉。", "何處飛來雙蛺蝶，也知籬落有黄花。"]'),
('bdf6ccd0-eeed-4d1e-8fb9-025a7711319a','與國軍道上','鄭會','宋','宋诗','song-poetry','','[]','時節近清明，雲官未放晴。',48,'全唐诗/poet.song.193000.json','["時節近清明，雲官未放晴。", "落花春緒懶，飛絮客情輕。", "新上誰家冢，深林宿處程。", "相看一巵酒，爲爾暫忘情。"]'),
('a8c3d8ff-f732-4a21-86a5-24013a3363cf','湖橋用朱申之韻','鄭會','宋','宋诗','song-poetry','','[]','小倚湖橋數暝鴉，竹籬深閉阿誰家。',32,'全唐诗/poet.song.193000.json','["小倚湖橋數暝鴉，竹籬深閉阿誰家。", "愛渠一架酴醿白，甚欲敲門覓數花。"]'),
('438302cf-9769-438a-aa69-4361fd4a7251','富陽江岸','鄭會','宋','宋诗','song-poetry','','[]','江行吾所愛，不敢厭長途。',48,'全唐诗/poet.song.193000.json','["江行吾所愛，不敢厭長途。", "薄日生花影，輕風老麥鬚。", "晚潮人趁渡，春旆客尋酤。", "却望青山遠，青山有鷓鴣。"]'),
('d443fa70-9db8-43e7-b7f8-6489b12c074e','夏日吳園','鄭會','宋','宋诗','song-poetry','','[]','斫藕敲瓜酒面涼，片雲如墨不成章。',32,'全唐诗/poet.song.193000.json','["斫藕敲瓜酒面涼，片雲如墨不成章。", "東風忽遣雨西去，相對兩烏行夕陽。"]'),
('99a44c1a-1cc3-45e5-8e59-76d237cf3680','黄叔敏許惠水梔子','鄭會','宋','宋诗','song-poetry','','[]','八觚臺子浄無塵，六尺屏風一欠伸。',32,'全唐诗/poet.song.193000.json','["八觚臺子浄無塵，六尺屏風一欠伸。", "忽憶西家水梔子，多時愁殺讀騷人。"]'),
('0f876b09-03b7-479a-87c2-f5f4a8768faf','陳舍人送蒲萄','鄭會','宋','宋诗','song-poetry','','[]','黑玉之柈白玉稜，龍須馬乳剪寒藤。',32,'全唐诗/poet.song.193000.json','["黑玉之柈白玉稜，龍須馬乳剪寒藤。", "自憐有母今塵土，持到黄泉喚不譍。"]'),
('3ef70097-08f4-482d-a92f-ad6ba062476d','定齋','鄭會','宋','宋诗','song-poetry','','[]','亂葉不停風衮衮，狂瀾既倒浪滔滔。',32,'全唐诗/poet.song.193000.json','["亂葉不停風衮衮，狂瀾既倒浪滔滔。", "碧潭深處無人見，歸盡浮雲月正高。"]'),
('8552e2ac-cd9b-48dc-8256-75a9a51297dc','竹月亭','鄭會','宋','宋诗','song-poetry','','[]','小欄干上夕陽紅，古樹根頭雪未融。',32,'全唐诗/poet.song.193000.json','["小欄干上夕陽紅，古樹根頭雪未融。", "落盡梅花人易老，主張楊柳是春風。"]'),
('fa231fce-9113-441e-bd74-a3a2c6f44913','西湖客舍','鄭會','宋','宋诗','song-poetry','','["\u897f\u6e56"]','數日秋風早，單衣補未圓。',48,'全唐诗/poet.song.193000.json','["數日秋風早，單衣補未圓。", "長貧身事缺，多病主人憐。", "賣藥僧歸寺，看山客借船。", "推窗正烟雨，坐看白鷗眠。"]'),
('b1167cfb-e2fb-4311-ae9f-585bb5261ad0','分寧縣齋','鄭會','宋','宋诗','song-poetry','','[]','日高窗下枕書眠，带得吟情到夢邊。',64,'全唐诗/poet.song.193000.json','["日高窗下枕書眠，带得吟情到夢邊。", "過鳥觸翻枝上雪，飛鴉驚破樹頭煙。", "百年世事聊供笑，千里鄉心最可憐。", "亦有門前數竿竹，短琴橫膝不須絃。"]'),
('4106c9de-70f9-4336-a414-5ecee6d69c68','南浦亭','鄭會','宋','宋诗','song-poetry','','[]','山含落日暮光紫，鴈带冰雪歸影單。',32,'全唐诗/poet.song.193000.json','["山含落日暮光紫，鴈带冰雪歸影單。", "柳岸一舟人不渡，蘆花風戰晚來寒。"]'),
('d30dee73-eae8-4a60-8485-f679a44bf423','豫章客樓','鄭會','宋','宋诗','song-poetry','','[]','薺菜花開雨未晴，章江煙柳正愁人。',32,'全唐诗/poet.song.193000.json','["薺菜花開雨未晴，章江煙柳正愁人。", "無錢可買東風醉，自寫唐詩過一春。"]'),
('abd7b594-5f86-4578-99b7-b1a7df98be6c','胡氏書房','鄭會','宋','宋诗','song-poetry','','[]','臘盡山中不見梅，閉門高枕夢瑶臺。',32,'全唐诗/poet.song.193000.json','["臘盡山中不見梅，閉門高枕夢瑶臺。", "午窗晴日蜂喧紙，忽有麻溪道士來。"]'),
('e53e3ead-a34f-457d-8a3c-501e70711957','題峴坡書院','鄭會','宋','宋诗','song-poetry','','[]','羊公碑字晉苔昏，中有襄人古淚痕。',64,'全唐诗/poet.song.193000.json','["羊公碑字晉苔昏，中有襄人古淚痕。", "憶作風煙漲塵土，自今日月照乾坤。", "維甌有客傷前哲，以峴名坡續後昆。", "且莫掀窗看鳬白，爲君王洗漢江渾。"]'),
('6b641d90-8046-42c6-b486-6e78e1e88553','一室','鄭會','宋','宋诗','song-poetry','','[]','坐眠惟一室，貧與病相依。',48,'全唐诗/poet.song.193000.json','["坐眠惟一室，貧與病相依。", "風急夜沽酒，月明秋搗衣。", "異鄉身是寄，久客事俱非。", "忽忽誰可語，滿庭黄葉飛。"]'),
('563a63fa-70e2-4ab6-8030-7ed3f543f9f5','吉州寓舍','鄭會','宋','宋诗','song-poetry','','[]','處世例營營，好山長自青。',48,'全唐诗/poet.song.193000.json','["處世例營營，好山長自青。", "鵲毛秋凈潔，鴿影夜竛竮。", "無客談時事，聽人講佛經。", "雖然非所好，亦足尉飄零。"]'),
('54cc80ba-91c0-47c0-9403-38358adddab8','齋中獨坐','鄭會','宋','宋诗','song-poetry','','[]','香殺柑花麝不如，晚窗重理讀殘書。',32,'全唐诗/poet.song.193000.json','["香殺柑花麝不如，晚窗重理讀殘書。", "饑烏只道無人在，偷覷盆池一個魚。"]'),
('577568a9-3d7d-41a5-9a7e-c68a537d1a55','寶藏寺雨中','鄭會','宋','宋诗','song-poetry','','[]','秋城雨氣白紛紛，不見青山只見雲。',32,'全唐诗/poet.song.193000.json','["秋城雨氣白紛紛，不見青山只見雲。", "古寺半欹僧去盡，亂鴉飛上五王墳。"]'),
('74a8942b-38c8-48bb-b3d7-7793aee51467','劉寺','鄭會','宋','宋诗','song-poetry','','[]','紹興妃子寺，步步白雲深。',48,'全唐诗/poet.song.193000.json','["紹興妃子寺，步步白雲深。", "叢冢荒難認，寒泉清到今。", "山高松有子，石老樹無心。", "寺主疎相見，如聞亦解吟。"]'),
('77703a6e-9587-4a59-bbf6-6298cddfc141','擬行行重行行','鄭會','宋','宋诗','song-poetry','','[]','行行重行行，憶君行路難。',84,'全唐诗/poet.song.193000.json','["行行重行行，憶君行路難。", "十步九縈折，一峰千巑岏。", "空山叫猿猱，老石藏㺥虦。", "美人隔千里，西遊何當還。", "鬢髮日已老，带眼日已寬。", "孤燈照殘夢，雨滴芭蕉寒。", "所思不可見，悒悒清夜闌。"]'),
('6baccc3a-8370-41a0-8270-b2f56c735def','續潘探花擣衣曲','鄭會','宋','宋诗','song-poetry','','[]','白石砧，秋沉沉。',164,'全唐诗/poet.song.193000.json','["白石砧，秋沉沉。", "家家擣衣燈下補，惟有妾家心最苦。", "妾初嫁來能幾時，良人從軍今不歸。", "去時楊花未飛絮，欲着春衫裁白苧。", "秋來暑盡白苧寒，遠征未必便可還。", "宮裘止是賜上將，良人猶在行伍間。", "擣衣擣衣寄將去，聞道分兵又西戍。", "茫茫莎草生寒塵，沙場不見愁殺人。", "堂前阿姑老，得君早歸好。", "擣衣擣衣空斷魂，因□上有雙淚痕。", "邊功未成君着力，妾身孤單君莫憶。"]'),
('d21f8b2a-479e-4e76-b435-db5580d7e9e1','天慶觀尋裘司直碑','鄭會','宋','宋诗','song-poetry','','[]','長廊鐘鼓靜無譁，白髮高人自煮茶。',32,'全唐诗/poet.song.193000.json','["長廊鐘鼓靜無譁，白髮高人自煮茶。", "可惜斷碑無覓處，石壇微雨落松花。"]'),
('7f709070-e2f2-435d-a286-31a8c555482b','送程峴坡過揚州','鄭會','宋','宋诗','song-poetry','','[]','輕衫濕雨過淮東，鶴背功名酒一中。',32,'全唐诗/poet.song.193000.json','["輕衫濕雨過淮東，鶴背功名酒一中。", "歇馬不須尋古事，隋家陵樹正秋風。"]'),
('508bb421-9406-46ad-844b-8d630b270b91','送孔炳先歸宜春','鄭會','宋','宋诗','song-poetry','','[]','微吟五箇字，客路惜年華。',48,'全唐诗/poet.song.193000.json','["微吟五箇字，客路惜年華。", "人世誰無別，子行吾憶家。", "濕雲生竹菌，晴雪噤梅花。", "明日煙波遠，孤舟自煮茶。"]'),
('75eaaa9f-b580-4e67-8770-e1ae2e68a72a','送金松槜歸永嘉','鄭會','宋','宋诗','song-poetry','','[]','可惜西風早，無因得放遲。',48,'全唐诗/poet.song.193000.json','["可惜西風早，無因得放遲。", "吹將客歸去，空有夢相隨。", "舊舍松根在，新坊酒價低。", "倘行天竺路，須爲訪留題。"]'),
('697d467a-a3e2-4ce7-93b8-2753e1643f16','壽蘇友橘  其一','鄭會','宋','宋诗','song-poetry','','[]','一春湖上看花枝，看到青青杏子肥。',32,'全唐诗/poet.song.193000.json','["一春湖上看花枝，看到青青杏子肥。", "家在江南身在浙，年年生日未曾歸。"]'),
('9fa6371c-506c-46a1-ab7a-bebd576d01a9','壽蘇友橘  其二','鄭會','宋','宋诗','song-poetry','','[]','人誰安逸浪中魚，事費經營網上蛛。',32,'全唐诗/poet.song.193000.json','["人誰安逸浪中魚，事費經營網上蛛。", "記得去年生日酒，去年無此白髭鬚。"]'),
('38dc4212-bcbc-48aa-8b2b-39dae7c666e3','壽蘇友橘  其三','鄭會','宋','宋诗','song-poetry','','[]','金輪王壽三千歲，銅狄人生五百年。',32,'全唐诗/poet.song.193000.json','["金輪王壽三千歲，銅狄人生五百年。", "茲事不須皆援古，無災無難即神仙。"]'),
('e33c1a3e-61c0-4e60-9bae-2afd1e87e444','梅雪堂','鄭會','宋','宋诗','song-poetry','','[]','素心甘澹泊，秉節性貞固。',60,'全唐诗/poet.song.193000.json','["素心甘澹泊，秉節性貞固。", "開堂撫垂雲，徘徊閲嘉樹。", "孤根倚絕壁，清光更囘互。", "生平鐵石腸，不受纖塵污。", "願結歲寒盟，相依共遲暮。"]'),
('bff597e7-67f1-4c26-9c6d-a74d418e3966','將抵家遇雨','鄭會','宋','宋诗','song-poetry','','[]','遄車偏值雨連天，疲馬難支又上船。',64,'全唐诗/poet.song.193000.json','["遄車偏值雨連天，疲馬難支又上船。", "樹杪鴉兵催急棹，渡頭漁火鎖寒烟。", "論心知己期將近，念子慈親望久懸。", "自笑歸裝無一物，就中强半是詩篇。"]'),
('f06b6b5e-82f9-42ba-b5c5-92b80a9c42bc','白衣寺','鄭會','宋','宋诗','song-poetry','','[]','白衣古寺瞰江流，隔斷紅塵不記秋。',32,'全唐诗/poet.song.193000.json','["白衣古寺瞰江流，隔斷紅塵不記秋。", "深羨老僧心入定，禪房花木四時幽。"]'),
('cd475fee-c44d-4969-b027-fbf8df6da970','句','鄭會','宋','宋诗','song-poetry','','[]','君未知人窮相事。',8,'全唐诗/poet.song.193000.json','["君未知人窮相事。"]'),
('852bdc8f-b10e-4bf8-8ae3-ab5399c063ef','三月某日有感而書','杜範','宋','宋诗','song-poetry','','[]','敏不可恃，鈍宜自强。',80,'全唐诗/poet.song.193000.json','["敏不可恃，鈍宜自强。", "詩酒荒嬉，恐暴汝良。", "我日衰惰，頼汝以張。", "安肆日偷，古訓洋洋。", "我與伯氏，短檠夜書。", "矻矻待旦，我所不如。", "每一念之，抆涕痛乎。", "嗣而昌之，其後人歟。"]'),
('c0d38f8b-7eef-4ec4-9bf4-b4e7a4a0ba3e','和訥齋題曉山亭','杜範','宋','宋诗','song-poetry','','[]','理粲萬象，孰妙孰徼。',180,'全唐诗/poet.song.193000.json','["理粲萬象，孰妙孰徼。", "卓彼南山，目游心討。", "露氣澄澈，浄不容掃。", "瑟瑟風松，剪剪煙篠。", "甘夢未覺，一聲晨鳥。", "恐隨賓送，歲月空老。", "整冠危坐，抱膝自笑。", "天際飛鴻，健翮矯矯。", "一念既徹，何遠不到。", "我卷我書，豈其弗考。", "萬動紛起，萬慮冥澡。", "斯物之格，斯理之奧。", "隨寓隨得，靡間昏曉。", "雲麓固夷，石壁非峭。", "目在而察，炯炯獨燎。", "有臨泰華，或視以渺。", "山豈不崇，乃見之小。", "扁亭者誰，有揭斯表。"]'),
('9b5696fe-6474-4743-834d-8e19998e1573','耕甫歸書約信二字爲別二首  其一','杜範','宋','宋诗','song-poetry','','[]','水失其防，一决莫止。',40,'全唐诗/poet.song.193000.json','["水失其防，一决莫止。", "人心惟危，殆亦若此。", "曾子之守，傳習在是。", "以約失之，蓋亦鮮矣。"]'),
('ac76b5bc-1d05-45e3-9259-1250d884988e','耕甫歸書約信二字爲別二首  其二','杜範','宋','宋诗','song-poetry','','[]','實之謂信，言巽行果。',40,'全唐诗/poet.song.193000.json','["實之謂信，言巽行果。", "言有不實，自喪厥我。", "誰其掩之，不善已播。", "人而無信，不知其可。"]'),
('a6bd5d13-4cde-4877-b3d9-0e5d1bc1d1db','夏夜雲月不明有感','杜範','宋','宋诗','song-poetry','','[]','天色未清霽，浮雲翳層空。',72,'全唐诗/poet.song.193000.json','["天色未清霽，浮雲翳層空。", "朦朧玉盤質，髣髴擘絮中。", "瓊宇本瑩徹，一髮不可容。", "胡爲受掩蓋，萬象歸冥蒙。", "誰能召風伯，掃氛有餘功。", "中天懸清光，娟娟萬里同。"]'),
('b2fd4d0e-00b6-4ffa-9f4d-768780200e22','病中和東里寺中作','杜範','宋','宋诗','song-poetry','','[]','陋質百不能，補敗倚師友。',144,'全唐诗/poet.song.193000.json','["陋質百不能，補敗倚師友。", "東里丈人行，幸忝巾屨後。", "君詩如秋霽，峭絕森碧岫。", "又如萬古壑，潺湲瀉寒溜。", "一手轉機軸，四顧無匹偶。", "明窗一披讀，張膽不論斗。", "願分有餘光，屢奪自醉酒。", "駑駘費剪拂，鞭策誰可久。", "徂暑變新凉，一氣分六九。", "逼仄塵區間，蒸鬰未改舊。", "心逐林泉佳，病滋面目醜。", "起來强力貧，寧敢繼富有。"]'),
('0bc141c3-7e4c-4f58-83b1-b4a5ab5a7c12','募兵','杜範','宋','宋诗','song-poetry','','[]','召募古來有，今者何其艱。',168,'全唐诗/poet.song.193000.json','["召募古來有，今者何其艱。", "文書急如雨，取辦都保間。", "百夫不當十，一夫費千鐶。", "恐被嗜利徒，無能禦國患。", "老母與少婦，蓬頭走江干。", "挽之不得留，悲泣聲徹天。", "母曰我壯子，婦曰我健夫。", "衣裳破無補，田園荒未鋤。", "一朝棄我去，饑寒我何如。", "我欲從汝行，生死同一隅。", "抑恐惰軍氣，累汝重汝辜。", "今業已分離，把袂略須臾。", "拭淚爲汝言，汝亦無我虞。", "戮力濟王功，期以斬强胡。"]'),
('b540e872-9d41-4f0c-8e11-de11a23a3736','戊辰冬和湯南萬韻  其一','杜範','宋','宋诗','song-poetry','','[]','我聞抱膝翁，高卧南中廬。',180,'全唐诗/poet.song.193000.json','["我聞抱膝翁，高卧南中廬。", "方其未遇時，邈若與世疎。", "起來扶漢業，肉骨成豐腴。", "青簡萬世名，寒窗一編書。", "出處寧異轍，此道誠非迂。", "嬾老天下士，被褐尚窮居。", "負米供一飽，晨昏擷園蔬。", "自知身有待，寧論食無魚。", "博洽貫萬理，收拾歸一途。", "翰墨瀉三峽，意氣橫九衢。", "才大用寧小，道肥身不臞。", "勳名會有時，天意非人圖。", "璧玉藏名山，抱璞初不渝。", "良工一顧盼，光彩照路隅。", "看君策駉馬，願言刈其芻。"]'),
('8a0a9231-f8d6-4ca8-9136-2ff1ec7e5043','戊辰冬和湯南萬韻  其二','杜範','宋','宋诗','song-poetry','','[]','春初走京華，秋杪歸舊廬。',180,'全唐诗/poet.song.193000.json','["春初走京華，秋杪歸舊廬。", "簡編廢已久，開卷澀且疎。", "誰能擊其蒙，石田或可腴。", "雁山有佳士，讀盡天下書。", "足跡半九州，不憚道里迂。", "陋邦何足臨，而亦來我居。", "相從一尊酒，未厭園中蔬。", "笑譚欣有合，浩若縱壑魚。", "人生惟所適，所適各有途。", "胸中苟不迷，到處皆通衢。", "簞瓢有真樂，顔氏何其臞。", "沒沒嗟我生，未知終焉圖。", "論交須論心，所論在不渝。", "願君示一語，令我反三隅。", "君無金玉音，請誦一束芻。"]'),
('f838ee89-4ca4-4d5f-a9b0-a2bf11a3cb3d','十二月初六日栖嬾和方山','杜範','宋','宋诗','song-poetry','','[]','携手喜初晴，夜光列星漢。',48,'全唐诗/poet.song.193000.json','["携手喜初晴，夜光列星漢。", "栖嬾壁上圖，昉於此乎看。", "詩翁爲抽思，宮徵手自案。", "一醉不敢辭，斗膽破崖岸。"]'),
('8d938797-7ab7-4d6f-9126-3247e719bc18','送子謹叔  其一','杜範','宋','宋诗','song-poetry','','[]','古道日凋弊，人心競險薄。',60,'全唐诗/poet.song.193000.json','["古道日凋弊，人心競險薄。", "風雨晦朝暮，平陸變溝壑。", "歸來尋故廬，六窗靜猶昨。", "殷勤時拂拭，埃塵易侵剝。", "此地寬且明，休哉有餘樂。"]'),
('2797e70c-5b1f-4de6-a4f1-f57e319b2e06','送子謹叔  其二','杜範','宋','宋诗','song-poetry','','[]','大聖不可作，立言百代尊。',60,'全唐诗/poet.song.193000.json','["大聖不可作，立言百代尊。", "開卷讀且想，凜凜儼若存。", "古今寧異轍，豈徒資討論。", "檢點作用處，聖愚從此分。", "記誦不足言，爲道忌多門。"]'),
('4510d3c9-2b42-4ba1-b980-3dba180f1218','送子謹叔  其三','杜範','宋','宋诗','song-poetry','','[]','大雅久不作，文士日以衆。',60,'全唐诗/poet.song.193000.json','["大雅久不作，文士日以衆。", "纘緝鬭新美，靡靡相潰澒。", "春禽轉巧舌，但可供好弄。", "取之以終身，隻字不可用。", "古來名節人，往往多樸重。"]'),
('35edbb08-b41f-44a6-8ff9-dd9917f1e5c5','送子謹叔  其四','杜範','宋','宋诗','song-poetry','','[]','少小從君遊，忽已各壯年。',60,'全唐诗/poet.song.193000.json','["少小從君遊，忽已各壯年。", "蒙銅未披發，憂孽故熏煎。", "羨君懷利器，吾宗秀而賢。", "刮摩盡結實，涵揉歸本源。", "聖處猛自力，人物方渺然。"]'),
('d744d1d3-26d1-4bd7-8b0f-01108cb6fb45','送子謹叔  其五','杜範','宋','宋诗','song-poetry','','[]','聚首日嬉戲，胡乃遽言別。',60,'全唐诗/poet.song.193000.json','["聚首日嬉戲，胡乃遽言別。", "囘首十年間，坐令肝膽裂。", "東陽古佳地，先民有遺烈。", "爲我一酹之，山寒水清絕。", "無以持贈君，高秋千里月。"]'),
('1996cd56-ba25-4310-90b6-f3dee6d5a31b','送石宰','杜範','宋','宋诗','song-poetry','','[]','朔風攪長林，凝冰封厚地。',288,'全唐诗/poet.song.193000.json','["朔風攪長林，凝冰封厚地。", "人嗟行路難，君行亦易易。", "句金號巖邑，日事紛萬蝟。", "羣情一齟齬，煩言四騰沸。", "長吏不足嚴，去之若下縋。", "俯仰十年間，轉足幾顛躓。", "君材萬斛鼎，屹然國重器。", "小試蒞茲邑，斬斬常正義。", "百鍊剛莫奪，豪猾歛手避。", "惠人鄭之僑，始亦遭怨詈。", "三年輿誦聞，人情見真僞。", "君來整弊俗，固有不得志。", "抗之如不克，浮言吁可畏。", "論定要以久，克終乃爲貴。", "謗讟變懽謠，君政本不異。", "字民有隠德，動人皆實意。", "嘉績今報成，坐洗十年愧。", "民俗豈相遠，己治人亦治。", "我本山澤臞，强顔領一尉。", "弱植媿匪材，久矣辱大芘。", "傾倒罄心腹，撫愛殊醜類。", "我亦爲知己，奔走常盡瘁。", "君今造清朝，行李挾佳氣。", "我方困塵役，何以逃吏議。"]'),
('cb866f1e-c758-4a6c-9508-eb9778bc3b2a','丁丑別金壇劉漫塘七首  其一','杜範','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','黄綺避世翁，萬乘輕商顔。',48,'全唐诗/poet.song.193000.json','["黄綺避世翁，萬乘輕商顔。", "翻然爲羽翼，國本安泰山。", "出處義與比，盛衰世相關。", "懷古誦考槃，令人欲長歎。"]'),
('6a6e9a2d-f36c-4190-92f5-b6c47b5e09f6','丁丑別金壇劉漫塘七首  其二','杜範','宋','宋诗','song-poetry','','[]','崇山鬰嵯峩，千章自交陰。',48,'全唐诗/poet.song.193000.json','["崇山鬰嵯峩，千章自交陰。", "培塿植松柏，斧斤日相尋。", "物小固不容，名大亦難任。", "智哉甯夫子，其愚非本心。"]'),
('d0db0888-1c7b-4749-b37e-b4ae0ab4c029','丁丑別金壇劉漫塘七首  其三','杜範','宋','宋诗','song-poetry','','[]','北風吹夏律，草木塵沙昏。',48,'全唐诗/poet.song.193000.json','["北風吹夏律，草木塵沙昏。", "枝葉曾未害，根本難具論。", "肉食謀何有，家食徒殷勤。", "誰能起東山，掃翳扶朝暾。"]'),
('150ea496-0ba9-40ab-8936-485bc2d698f8','丁丑別金壇劉漫塘七首  其四','杜範','宋','宋诗','song-poetry','','[]','川澤升爲雨，霈然周四郊。',48,'全唐诗/poet.song.193000.json','["川澤升爲雨，霈然周四郊。", "有水行地中，溉灌亦良勞。", "勢力固有限，戛哉加分毫。", "爲義分內耳，誰言薄雲高。"]'),
('e207d992-8b86-4068-a2a1-0b87b17d2f96','丁丑別金壇劉漫塘七首  其五','杜範','宋','宋诗','song-poetry','','[]','詞章道之華，於世非少補。',48,'全唐诗/poet.song.193000.json','["詞章道之華，於世非少補。", "施之匪其宜，文繡被泥土。", "自昔重立言，一語萬鈞弩。", "誰其厭來者，是非實千古。"]'),
('5040f4de-a8be-41e6-8077-43d6b72b6436','丁丑別金壇劉漫塘七首  其六','杜範','宋','宋诗','song-poetry','','[]','女蘿去長松，藉藉紛委地。',48,'全唐诗/poet.song.193000.json','["女蘿去長松，藉藉紛委地。", "矇瞍辭詔相，十步九顛躓。", "弱昧慙陋質，先生未終棄。", "再拜願有聞，服膺敢失墜。"]'),
('f0016926-e282-4ba3-97d5-3de8134291ab','丁丑別金壇劉漫塘七首  其七','杜範','宋','宋诗','song-poetry','','[]','人生玩歲月，世事變朝暮。',48,'全唐诗/poet.song.193000.json','["人生玩歲月，世事變朝暮。", "三年在門牆，一日泣岐路。", "窗前長新綠，生意自呈露。", "願君日强飯，安排濟時具。"]'),
('17869d9a-e113-43e9-af65-ff635d2c3bcc','喜雨','杜範','宋','宋诗','song-poetry','','[]','凄其望雲漢，旱饑何頻年。',168,'全唐诗/poet.song.193000.json','["凄其望雲漢，旱饑何頻年。", "去歲秋後雨，溝壑僅少年。", "春耕問菑畬，饁婦多嘉言。", "夏耘喜優渥，驛驛生翠煙。", "不雨寧幾日，已復憂虧愆。", "傷弓慨心事，過計乃不然。", "風雷變俄頃，膚寸速九天。", "夜坐聽傾倒，朝起望渺綿。", "時哉此甘霔，不後亦不先。", "我無負郭資，墨突非所憐。", "但願時豐登，有粟均里廛。", "歲晚稱壽觴，一笑生春妍。", "彼蒼其或者，副此心拳拳。", "拜賜盈百室，敬誦良耜篇。"]'),
('64b2926a-8392-4b83-84a1-f7e7dad598e0','己卯夏憂雨偶作','杜範','宋','宋诗','song-poetry','','[]','昨者憂不足，今者厭有餘。',96,'全唐诗/poet.song.193000.json','["昨者憂不足，今者厭有餘。", "垂垂匝曉夕，灧灧平澮渠。", "苗事方用壯，過潦非所虞。", "但慮盈與虧，理或相乘除。", "它日儻望霓，神貺俱墮虛。", "造物願有終，屯膏時其輸。", "自此大有年，大書不一書。", "飽飯樂田社，一官徒區區。"]'),
('06f91662-8fce-49a2-8842-092e855e7ad3','閑行溪西得梅數花喜甚偶成小詩呈諸趙兄','杜範','宋','宋诗','song-poetry','','[]','作意每不偶，邂逅與心會。',168,'全唐诗/poet.song.193000.json','["作意每不偶，邂逅與心會。", "疇昔問寒梅，李園不成醉。", "今夕亦何夕，見此萬花最。", "獨立如高人，凜凜塵世外。", "藤蘚半侵剝，風雪幾顛沛。", "蕞爾籬落間，勁氣奪松檜。", "下視桃李場，碌碌千百輩。", "古淡不入眼，何能供世嗜。", "苦心抱歲寒，天其知我矣。", "此行得此花，嶷然爲增氣。", "置之几席間，相對喜不寐。", "有果碩不食，明朝日南至。", "芽蘗或未知，爾乃太蚤計。", "三嗅味清絕，令人發長喟。"]'),
('16849e26-ee54-49d5-8514-99393d58fe57','方山和篇再和韻','杜範','宋','宋诗','song-poetry','','[]','慇懃里社間，談笑文字會。',168,'全唐诗/poet.song.193000.json','["慇懃里社間，談笑文字會。", "平生一尊酒，無慮千百醉。", "問梅窮澗岡，樂事此其最。", "風霜盡木末，冰雪封戶外。", "誰其念岑寂，自得以顛沛。", "歲寒二三友，已不數蒼檜。", "卓彼方山翁，自許行偕輩。", "古心味玄酒，於世百不嗜。", "少小誦佳篇，搜句亦奇偉。", "年來久不作，吾黨幾喪氣。", "珠璧忽墮前，疇昔曾夢寐。", "三詠結束語，坐令百感至。", "來者恐未然，往者非所計。", "汗青幾名節，徒起千載喟。"]'),
('8e6187cc-1df5-4721-a83c-002c3046d915','方山有求轉語之作并用韻二章  其一','杜範','宋','宋诗','song-poetry','','[]','觀物非外索，具眼以心會。',168,'全唐诗/poet.song.193000.json','["觀物非外索，具眼以心會。", "微陽花病槁，寧供等閑醉。", "我嘗課前作，無言乃爲最。", "譬彼清廟瑟，一唱弦越外。", "萬卉染春色，生意豈不沛。", "何物漏天機，一點映寒檜。", "我欲屋溪曲，種竹十數輩。", "疎影浸清淺，作此苦淡嗜。", "方山於此花，論交亦久矣。", "憔悴對冰雪，中有蓋世氣。", "向來多朋從，痛飲忘夜寐。", "舊事俱已非，尚善詩押至。", "俯就相唱酬，殆爲後來計。", "一花未足多，夫子亦何喟。"]'),
('41df955e-c428-4b13-a9a9-0b634ea2fdda','方山有求轉語之作并用韻二章  其二','杜範','宋','宋诗','song-poetry','','[]','四時冬復春，造化一機會。',168,'全唐诗/poet.song.193000.json','["四時冬復春，造化一機會。", "朔風空草木，餘枿猶病醉。", "梅花於其間，居殿復居最。", "三春在何許，不在粉鬚外。", "我嘗玩茲理，若决江河沛。", "冰壑卧寒松，雪嶺立老檜。", "見命謂受獨，落落一二輩。", "有此不改節，不與世同嗜。", "抱貞開化元，此花而已矣。", "整刷此精神，寸草亦生氣。", "嗟嗟迷復者，膠轕隨寤寐。", "萌蘗尋斧斤，豈知七日至。", "擊壤詠天根，巧歷不能計。", "持以印梅花，無語獨歎喟。"]'),
('23400845-9c81-4bad-84b4-221d0c294de7','叔虎辱與予遊最久其所爲詩文僅窺一二未獲搴珠璧之櫝而縱觀也行李來京都携方崖類藁携續集示予暇日隠几讀之斲巧抽新絢綵爛爛爲之洞心豁目不知君家所藏其富若是輒成古風以自詫奇觀因以爲謝','杜範','宋','宋诗','song-poetry','','[]','昔君遊我里，諸老皆競爽。',168,'全唐诗/poet.song.193000.json','["昔君遊我里，諸老皆競爽。", "今踰三十年，百事一非往。", "君今來京都，相對各槁項。", "清燈話疇昔，未語意先惘。", "橐中賸緗帙，挈來耀書榥。", "栒虡列羣編，金石振逸響。", "又如春水闊，縠瀾敷浩瀁。", "繡鞶飫耳聞，錦囊愜心賞。", "今夕亦何夕，塵塞爲披敞。", "吾衰亦久矣，欲勉不可强。", "尚記諸老言，種收同鹵莽。", "顧我困朝饑，羨君富秋穰。", "何日遂賦歸，相從問隴㽘。", "滯穗儻可拾，我亦歌擊壤。"]'),
('82286677-f648-43af-a4d7-00c6e279d18e','張上舍送望水偶成小詩','杜範','宋','宋诗','song-poetry','','[]','我家東南隅，去海不踰咫。',84,'全唐诗/poet.song.193000.json','["我家東南隅，去海不踰咫。", "乘潮厭鮮美，望水快珍脆。", "朅來雙溪上，河魚僅青鯉。", "泥滓漬膚肉，强食輒三噦。", "此物從何來，對之驚且喜。", "雖然餒敗質，尚餘江海味。", "令人憶故鄉，沽酒爲一醉。"]'),
('9bbf350e-da1c-4690-8714-1b6a293f124d','閑坐有感偶成古風簡劉會之高吉父康司理','杜範','宋','宋诗','song-poetry','','[]','虞夏幾百載，繼以周禮樂。',288,'全唐诗/poet.song.193000.json','["虞夏幾百載，繼以周禮樂。", "洋洋雅頌音，後亡前亦作。", "井疆貧富均，薄海詠康樂。", "姬公同聖賢，積累亦不薄。", "宜其垂萬代，整整守矩彠。", "寧知不數傳，板蕩已非昨。", "丘賦魯史書，田疇鄭謗作。", "滕君謾憂勤，畢戰空唯諾。", "盛古猶有憾，此豈易商榷。", "矧今千載後，而欲强復剝。", "州縣工罟穽，黔黎惴溝壑。", "世道日澆訛，禁厲不可縛。", "我嘗三太息，浮雲翳碧落。", "爲貧走塵埃，豈解拯民瘼。", "州家輕任使，千鈞委羸惡。", "勞瘁敢自愛，恐負此邦託。", "仁政安在哉，名是意已錯。", "治道去泰甚，此論東州確。", "人言寬一分，所望恕且約。", "一分寬未易，十分擾已博。", "嗟哉斯人生，日巧亦日削。", "俗吏事朱墨，暴吏事鞭扑。", "我把七篇書，人笑謂迂學。", "誰與輸此懷，濁浪渺垠堮。"]'),
('d1bf61b7-6eba-4082-8ec0-610977dbc552','奉祀禮畢飲福有感偶成','杜範','宋','宋诗','song-poetry','','[]','憶昔少年日，拜起隨父兄。',144,'全唐诗/poet.song.193000.json','["憶昔少年日，拜起隨父兄。", "飯羹集隣里，果粽羅豆登。", "坐有白髮翁，感歎或涕零。", "我時百不解，一飽追儕朋。", "歲月忽已晚，半生如飛霆。", "鬢影吹秋風，覽鏡良自驚。", "父兄不可見，黍稷恐非馨。", "跪拜蕆常禮，苦淚空填膺。", "呼兒共飲福，百感心未平。", "古今一俯仰，生死同夢醒。", "此去寧幾秋，况復較枯榮。", "收淚且舉爵，行行付交承。"]'),
('12038636-88be-42db-b982-0a2b340b9910','寬堂生辰見招坐中賦小詩爲壽','杜範','宋','宋诗','song-poetry','','[]','人以寬而安，道以寬而久。',84,'全唐诗/poet.song.193000.json','["人以寬而安，道以寬而久。", "蹄涔貯汙潢，滿除翻覆手。", "江海無津涯，天地等大受。", "寬故靜而一，是謂仁者壽。", "晴天泛風光，春意入花柳。", "一笑登公堂，寬德寓杯酒。", "愈寬則愈壽，松柏歲寒友。"]'),
('5f8d7f2a-6572-4deb-902c-0ae3b9aa4cb6','別陳常簿塤五首','杜範','宋','宋诗','song-poetry','','[]','古道湮不續，遺直聲以彰。',240,'全唐诗/poet.song.193000.json','["古道湮不續，遺直聲以彰。", "良藥見謂苦，不試徒有方。", "豈其蓋世名，可浣憂國腸。", "視天方夢夢，令人歌慨慷。", "心理同一轍，世學何多門。", "倡徒各有植，成性非兩存。", "習之到聖處，心小道自尊。", "工夫未易熟，毀譽何足論。", "空言漫浩渺，實行較分寸。", "爲官志何在，監州民可問。", "以此百紙忠，解彼千里慍。", "有守矧更賢，往哉同令聞。", "菜畦絕夜雨，麥壠摇春風。", "板輿奉歡笑，意與物態同。", "路才百里近，水可一夕通。", "君其戒徒御，駕言無匆匆。", "義交味逾淡，心敬跡自疎。", "球玉世所貴，車馬人交趨。", "性懶拙造請，獨抱此區區。", "贈別我何有，珍重千金軀。"]'),
('c3297d64-8e43-478c-ae5c-2e6113a8a666','良月遊水樂','杜範','宋','宋诗','song-poetry','','[]','久矣聞水樂，邂逅作此遊。',144,'全唐诗/poet.song.193000.json','["久矣聞水樂，邂逅作此遊。", "林立攢萬石，曲逕穿深幽。", "谽谺開古洞，下有清淺流。", "惜哉非古樂，噴薄皆人謀。", "流觴飲山綠，風鬢吹颼颼。", "欲歸興未盡，携手湖上樓。", "斜陽獻萬狀，浩以百目收。", "白鳥去復還，翩翩良自由。", "我本山林人，對此多慙羞。", "歲月不我與，宴閑其可偷。", "便合作歸計，老矣安所投。", "世事皆漫爾，政恐空白頭。"]'),
('bf287173-5b76-4e40-985c-a5210483a675','送羅年能赴興國','杜範','宋','宋诗','song-poetry','','[]','句金與君別，忽忽二十年。',204,'全唐诗/poet.song.193000.json','["句金與君別，忽忽二十年。", "君滋厲素節，我已羞華顛。", "轉物有玄機，掃翳還青天。", "羣耳共聳聽，明詔方改元。", "篤意召諸老，高爵升衆賢。", "執麾不可挽，問君胡爲然。", "一氣纔作新，萬卉皆爭妍。", "雪霜誰謂無，松柏良自堅。", "操心不厭危，知機常慮先。", "承流惠疲氓，調俗暢新絃。", "送日徒京塵，班春勝著鞭。", "顧我足尚縶，羨君翮方翩。", "數里已云隔，千里其可前。", "有懷空感惻，何時解拘攣。", "卓哉漫塘翁，邈在雲山邊。", "煩君招衡門，爲我致問言。", "萬牛應莫回，世事如風烟。"]'),
('940d56b0-cb2f-4514-9baa-9d2840f82035','湯南萬求詩贈別遂用其和韓總卿韻','杜範','宋','宋诗','song-poetry','','[]','清朝方振飭，羣彥盡收攬。',264,'全唐诗/poet.song.193000.json','["清朝方振飭，羣彥盡收攬。", "萬化轉機軸，一氣變舒慘。", "歲寒天漠漠，日暮雲澹澹。", "古志可今覆，遠考異近覽。", "世味甘甜蜜，國計未嘗膽。", "馿技或易窮，羊質徒大闞。", "冒沒忘險塗，吁嗟入玄窞。", "志士抱忠篤，封事寫憂憯。", "已動凝前旒，又隔充耳紞。", "有獻非美芹，有味真苦欖。", "誰其鄙肉食，政恐忘饁嗿。", "一別幾十年，重會生萬感。", "舊歡痛莫追，久交味逾淡。", "羨君粲詞華，綵霞生暮晻。", "顧我已衰晚，鬚雪羞髦髧。", "猛虎躍山谷，寧甘落圈檻。", "靈龜通鬼神，肯自朶頤頷。", "看彼苑上花，何如澗下馣。", "幽廬對江山，逸興寄鉛槧。", "我欲同君歸，何由遂此敢。", "茅茨勝金屋，飯羹飽玉糝。", "願言寄新詩，春意起蓮菼。"]'),
('83d089b5-5ce8-44a2-9b78-c4c10abf2709','仲夏朔汰卒羣鬨驚擾居民內外凜凜撫而賚之而後少定人情憂畏警夜愈嚴一夕霈雨羣心頓甦張倅作喜雨詩見示因和其韻','杜範','宋','宋诗','song-poetry','','[]','居家多惰拙，爲國常隠憂。',264,'全唐诗/poet.song.193000.json','["居家多惰拙，爲國常隠憂。", "有時發魯嘆，乃或遭楚咻。", "壞證至束手，錯事皆從頭。", "收汙挑怨憤，作勞睨嬉遊。", "變成生悍卒，禍已延數州。", "胡然近輦轂，豈不聞高侯。", "大决多所傷，小安其可偷。", "悍心未熨帖，轉手即寇仇。", "嗟哉逢不辰，老矣何所投。", "人力豈足恃，天意或爲謀。", "連夕蒸霮䨴，崇朝洗歊烰。", "巷陌收燥坌，河渠漲濁流。", "仰首戴恩育，歡心誰怨尤。", "國步自茲穩，吾志將何求。", "高人贈我詩，妙語清於秋。", "口誦殊未已，頭痛頓已瘳。", "欣然萬宇氣，快以一筆收。", "仁隣幸可卜，舊好今自修。", "願言爲明時，却顧思遠猷。", "王度殊未飭，人情過則休。", "朽索難繫馬，機心或驚鷗。", "君方抱經濟，我當歸樊丘。"]'),
('1206f6f5-5e75-4a8e-a40c-191fbac6a564','送趙寬堂二首  其一','杜範','宋','宋诗','song-poetry','','[]','馬塍眩朱白，孤山自疎影。',60,'全唐诗/poet.song.193000.json','["馬塍眩朱白，孤山自疎影。", "冰雪幾歲寒，誰解爲渠領。", "李園百樹花，人與凡木屏。", "濕蘚囘春風，猿鶴并刷整。", "爲我一酹之，往事莫重省。"]'),
('6800b2bc-ed2f-4904-abc0-1125187ab047','送趙寬堂二首  其二','杜範','宋','宋诗','song-poetry','','[]','兩片南山雲，偶爾連空飛。',60,'全唐诗/poet.song.193000.json','["兩片南山雲，偶爾連空飛。", "一去向空谷，一留伴殘暉。", "招招浙江渡，激激風吹衣。", "仰頭有鴻鵠，孰使心事違。", "何時黄山邊，把酒話昨非。"]'),
('4b69fdaa-c5d7-4923-8caf-c35c4669782a','送湯仲能國正以直言去國','杜範','宋','宋诗','song-poetry','','[]','朔風剪木末，碩果懸孤危。',60,'全唐诗/poet.song.193000.json','["朔風剪木末，碩果懸孤危。", "邈矣冥飛鴻，異哉聞鳴鴟。", "暮雲結愁陰，送君江之湄。", "去者挽莫留，留者良自悲。", "何當謝塵鞅，鼓枻相追隨。"]'),
('8c985c0c-d285-46fc-96f4-c3a002e3a60b','花翁將歸婺女因爲江西遊有長篇留別社中次韻送之','杜範','宋','宋诗','song-poetry','','[]','曠士隘宇宙，孰爲君家山。',180,'全唐诗/poet.song.193000.json','["曠士隘宇宙，孰爲君家山。", "逸興渺湖海，孰遣君意還。", "胡然動行色，便欲生慘顔。", "新篇寫襟素，和章就詞班。", "亦念塵坱客，肯照窗几間。", "懷舊徒感愴，搜語愧冥頑。", "兩年重憂患，悲涕不勝潸。", "一身纏疢疾，形骸頓已孱。", "籲天凡幾疏，無路扣九關。", "望絕鍾鼎貴，分甘茅衡跧。", "薾然一疲駑，不願十二閑。", "送君爲心折，把酒慙量慳。", "行行速京洛，去去難追攀。", "莫上八詠樓，且宿雙溪灘。", "爲問赤松子，世道何其艱。"]'),
('52231125-b228-4be1-a7ab-a0b1ff596998','靈峰','杜範','宋','宋诗','song-poetry','','[]','造物幻奇傑，立石環堅城。',84,'全唐诗/poet.song.193000.json','["造物幻奇傑，立石環堅城。", "拔地數千尺，變見百怪形。", "兩夫屹當關，左右排戈兵。", "崛起萬古雄，護此鐘鼓聲。", "我來自塵寰，一見心目驚。", "把酒對此奇，坐使世念輕。", "明朝下山去，此石留吾膺。"]'),
('f3588ab9-e07f-4a8f-b9e3-b1962321f096','雁蕩','杜範','宋','宋诗','song-poetry','','[]','東南富山水，傑氣鍾雁峰。',228,'全唐诗/poet.song.193000.json','["東南富山水，傑氣鍾雁峰。", "巨靈排屭贔，妙力開鴻濛。", "斷崖據險絕，峭壁凌寒空。", "分岑獻萬狀，轉盼無一同。", "或疊如錦纈，或鑄如青銅。", "或前如舞鳳，或却如飛鴻。", "或伏如卧虎，或矯如游龍。", "並如兄語弟，差如兒對翁。", "銳如筆露穎，岐如剪開鋒。", "二湫分大小，二靈儼西東。", "古語聊近似，天巧難形容。", "我久埋世埃，幸此拔天風。", "應接費耳目，磈磊羅心胸。", "有僧本儒家，伴我追雲蹤。", "攀躋不知勞，指引殊未窮。", "胡然便語別，問之以涕從。", "爲渠游興盡，生我歸意濃。", "出計無草草，回塗復匆匆。", "還此未了緣，邂逅須有逢。"]'),
('4a40ba6a-1a68-4e27-a36b-c71461b7abe3','送耕甫弟赴補','杜範','宋','宋诗','song-poetry','','[]','所性常存存，危者惟人心。',108,'全唐诗/poet.song.193000.json','["所性常存存，危者惟人心。", "子才秀吾宗，一歕凡馬瘖。", "俊快恐易蹶，謹勿輕千金。", "賢關集多士，轡策方駸駸。", "功名亦漫爾，培護在資深。", "我嘗評京華，真是穢濁林。", "繩約稍自寬，一縱不可尋。", "蚤夜念倚門，翼翼如有臨。", "亟歸慰慈抱，毋浪花邊吟。"]'),
('cbf673f7-19d7-4b3d-b607-b006441e386b','送夏肯父赴補','杜範','宋','宋诗','song-poetry','','[]','之子問行李，策足游上都。',96,'全唐诗/poet.song.193000.json','["之子問行李，策足游上都。", "晚風吹客袂，話別聊躊躇。", "朝家渴多士，璧水來英儒。", "子志橫四海，亦復隨羣趨。", "磨礪强國策，它時剪驕胡。", "卓彼漫塘翁，一壑老壯圖。", "萬牛挽不前，世事付長吁。", "君欲訪隠所，爲問今何如。"]'),
('0f960ad7-e93b-4026-9267-0ce91937a338','龔叔虎秋實堂','杜範','宋','宋诗','song-poetry','','[]','人心分內外，學道謹趨捨。',168,'全唐诗/poet.song.193000.json','["人心分內外，學道謹趨捨。", "巧令世所賢，木訥人謂野。", "至聖垂大訓，夫豈欺我者。", "陽和發天葩，爛其映春斝。", "一朝隨狂風，殆不如土苴。", "秋至萬寶成，結束槁葉下。", "一一抱天根，真理不容假。", "持以薦豆籩，潔誠神所嘏。", "孔門德行科，卓爾先游夏。", "漢世躬行人，未肯遜班馬。", "照影空自妍，心事形面赭。", "美璞藏至用，不琢存大雅。", "詩篇匪君重，閉戶自汛灑。", "余言亦已多，尚口不如啞。"]'),
('65147268-a357-4f75-b345-fb35a82d3dbc','五八叔席上詠江梅水仙','杜範','宋','宋诗','song-poetry','','[]','難兄冰雪姿，難弟金玉相。',60,'全唐诗/poet.song.193000.json','["難兄冰雪姿，難弟金玉相。", "一夷與一惠，共此歲晚香。", "凌波孤山下，不染塵𡏖場。", "故山尚無恙，愈覺風味長。", "夜闌更秉燭，簷雪聲鏘鏘。"]'),
('81d303b5-ad37-4938-b659-47a1c8f6f5f6','雪中成十一韻','杜範','宋','宋诗','song-poetry','','[]','入冬多癘氣，陽洩月令暢。',132,'全唐诗/poet.song.193000.json','["入冬多癘氣，陽洩月令暢。", "隠雷聲間作，萬蟄驚塞向。", "數日凝重陰，雲同寒威壯。", "飛瓊遍天宇，色界鋪寶藏。", "前此亦屢白，玉瑞此其創。", "緘運孰主張，一雪壓千瘴。", "紛紛富家兒，羔酒醉金帳。", "誰思道丐者，雙脚紅玳樣。", "顧我雖甚貧，可挾尚有纊。", "蚤起願年豐，共飽拜天貺。", "天意然不然，獨立爲楚愴。"]'),
('bdc012ee-88d6-4d7c-83f9-1d2189078a71','園丁得二小花以獻坐中屬梅津龜翁賦之且以寄處靜索詞仍有白戰寸鐵之禁自非不喫煙火誰解作此架空生活處靜詞先至梅津詩繼之皆清絕可味輒用梅津韻奉呈諸丈殆類癡人强絕粒未免又喫漿也一笑','杜範','宋','宋诗','song-poetry','','[]','歲功巧結束，物與七反丹。',96,'全唐诗/poet.song.193000.json','["歲功巧結束，物與七反丹。", "應嫌青女妒，摇落空人寰。", "耀釵雲髻裏，點粉黛眉間。", "香色亦幾何，小有即大還。", "艷陽費浮花，微陽惜真韻。", "月窟占奇芬，天根關大分。", "冰雪又催年，自此接新運。", "泰華與秋毫，巨細非定論。"]'),
('1c4e7074-98f4-4e9c-a799-5e2849b8d43b','耕甫弟寄示秋懷二章冗不能皆和次韻後章謾見愛助之意','杜範','宋','宋诗','song-poetry','','[]','杜曲傳詩書，百年植門戶。',108,'全唐诗/poet.song.193000.json','["杜曲傳詩書，百年植門戶。", "汝少秀而賢，中上期可語。", "胡然織錦機，未半已投杼。", "謝彼遊冶徒，前功尚可補。", "墮身泥滓中，起穢實自取。", "細讀玉汝章，此意可近古。", "凡物甘以壞，其成在堅苦。", "要須心自鞭，勿以言浪許。", "它時觀厥成，一笑相爾汝。"]'),
('6e852c0a-e7f5-4a9f-aa0b-51be51b4c4c1','中秋夜客退觀月謾成','杜範','宋','宋诗','song-poetry','','[]','檻外不數丈，深窅藏丘壑。',96,'全唐诗/poet.song.193000.json','["檻外不數丈，深窅藏丘壑。", "璧月懸中天，玉露下叢薄。", "尺水澄秋光，龜魚共予樂。", "所樂亦伊何，飲水良自覺。", "恍若歸故山，灑然謝羈絡。", "明發將何之，塵埃又如昨。", "行也誰使之，有此一大錯。", "幸保寸心在，舉頭問碧落。"]'),
('2dbff8a6-846a-496d-9f7c-3728a4e919fa','書于立齋自戒併示諸子','杜範','宋','宋诗','song-poetry','','[]','晦以昭明德，怯以成勇功。',84,'全唐诗/poet.song.193000.json','["晦以昭明德，怯以成勇功。", "用拙巧莫尚，持靜動攸宗。", "惟柔養真剛，自下升高崇。", "虛可使實積，小乃與大通。", "守約博有歸，味淡甘無窮。", "萬里以是觀，一心須自融。", "戒哉驕與盈，外强中空空。"]'),
('e7231311-ee6a-48ee-82e1-30ff4718f51f','登山述懷','杜範','宋','宋诗','song-poetry','','[]','抆淚別妻子，登山望歸舟。',168,'全唐诗/poet.song.193000.json','["抆淚別妻子，登山望歸舟。", "舟遠望不及，巖溜鳴咿嚘。", "足繭坐絕頂，晚色忽已稠。", "凄其杜宇聲，問我胡爲留。", "撫襟獨浩嘆，淚下不可收。", "三年足別離，此淚良有由。", "區區駒隙中，爲形役不休。", "爲形役尚可，爲人役何求。", "淵明獨何人，我乃如拘囚。", "親老方倚門，甘旨誰供羞。", "子幼未知學，擇師誰與謀。", "鬼蜮閃光怪，虎豹嘷昏幽。", "世路委叢棘，吾道若綴旒。", "豈無知我者，應謂我心憂。"]'),
('a49a5f7c-ba70-4a56-bb18-4e1e5fbd2daf','和劉會之野堂韻','杜範','宋','宋诗','song-poetry','','[]','草草春又過，凄晦風雨夕。',120,'全唐诗/poet.song.193000.json','["草草春又過，凄晦風雨夕。", "三年烏傷夢，不斷一區宅。", "台山在何許，空有塵滿屐。", "英英江夏公，老龍蟠古澤。", "尋勝著幽宇，搜奇列佳石。", "可齋不出門，亦復爲渠役。", "酒酣對崔嵬，寸管凌千尺。", "念我蕭寺中，遠贈煩走力。", "隠几讀妙句，緬懷賓主席。", "何當謝吏網，足躡堂上客。"]'),
('1ed4c39d-ceaf-49ea-b9d4-0ace73d2b56d','詠芙蓉與菊花','杜範','宋','宋诗','song-poetry','','[]','秋光濃欲滴，結束東籬花。',96,'全唐诗/poet.song.193000.json','["秋光濃欲滴，結束東籬花。", "糝糝紛點綴，戢戢相參差。", "淵明太好事，言樂酌流霞。", "誰云制頹齡，爲與霜爭華。", "映水開芙蓉，麗色如春葩。", "謾以拒爲名，青女不能加。", "持此問淵明，何乃吝齒牙。", "門外風如箭，黄落滿天涯。"]'),
('82f83727-1df0-4cab-bc19-a36b88bf110c','再用韻','杜範','宋','宋诗','song-poetry','','[]','浮艷誇春苑，貞耐還秋花。',96,'全唐诗/poet.song.193000.json','["浮艷誇春苑，貞耐還秋花。", "有菊與芙蓉，誰能分等差。", "金蕊含朝暉，丹臉粲夕霞。", "素商太冷淡，歲晚生光華。", "詩人抱幽獨，東籬愛天葩。", "可惜亭亭姿，誤以脂粉加。", "知音須子期，知味須易牙。", "臨風慨千古，雲海浩無涯。"]'),
('199fb697-8ee1-4a21-9f0b-de34848c1405','三用韻謝孫花翁趙寬堂趙貴方見和','杜範','宋','宋诗','song-poetry','','[]','金飈蕩天末，清泠聚茲花。',96,'全唐诗/poet.song.193000.json','["金飈蕩天末，清泠聚茲花。", "凜然傲且拒，霜天肩正差。", "好事共一觀，目眩五色霞。", "但此慰寂寞，那復矜榮華。", "誰無蘭蕙姿，誰無桃杏葩。", "秋邊竟誰語，短瓶插交加。", "但知愛風味，何必加齒牙。", "未能輸一醉，有興浩無涯。"]'),
('2e9f7b64-c82e-4a5c-bbb3-47afb42c3748','夜讀花翁詩什有感漫成鄙句拜呈藉以求教癡目駭見異寶揣摩贊歎徒犯古人衒嗤之戒耳','杜範','宋','宋诗','song-poetry','','[]','士有當世志，誰肯專詩名。',156,'全唐诗/poet.song.193000.json','["士有當世志，誰肯專詩名。", "自古巧文字，與道關廢興。", "傾座聽君語，雄辨窮粗精。", "目中無全牛，肯綮技未經。", "胡爲趁風月，候蟲相與鳴。", "靜夜誦佳什，泠然如夢醒。", "瘦語自腴澤，險句自穩平。", "譬彼有源水，隨流作幽清。", "奇抱歎皓首，敗屋挑寒燈。", "天運豈其然，人力非所能。", "我讀淵明詩，悠悠千古情。", "銜觴豈好飲，采菊非餐英。", "何時共臯益，賡歌在虞庭。"]'),
('6a18e3b7-267a-4531-9954-f179e0860109','國正丈和章齊物之論掃去軌轍超然形外所進高矣讀之敬歎不自揣再用前韻爲謝併以求教','杜範','宋','宋诗','song-poetry','','[]','鐘鼎非狥利，山林非狥名。',156,'全唐诗/poet.song.193000.json','["鐘鼎非狥利，山林非狥名。", "古來豪傑士，不待文王興。", "得時舒氣燄，宇宙生光精。", "失時卷機軸，圭蓽韜緯經。", "神龍冬亦蟄，蟋蟀秋乃鳴。", "飲醇未同醉，啜醨還獨醒。", "泛觀疑自戾，反視不失平。", "人言惠與夷，寧知和非清。", "膏沃照幾室，火傳非兩燈。", "但使本根在，毋誇知力能。", "協一雖奧理，不齊本物情。", "聊借莊生語，一吐胸中英。", "看君鼓天翼，事業揚帝庭。"]'),
('9bf17847-77b3-4b9a-a9dc-bc75de2acccc','和鄭府判韻','杜範','宋','宋诗','song-poetry','','[]','萬里扶摇整飛翮，自是凌雲九霄客。',64,'全唐诗/poet.song.193000.json','["萬里扶摇整飛翮，自是凌雲九霄客。", "黄槐白紵秋風高，借君彈壓添顔色。", "奉檄校文真誤推，多才視我蚿與夔。", "竭力詎敢辭鈍遲，寒芒在上方輝輝。"]'),
('516d421c-57ca-4897-b65a-8d69f20cb549','次宗司法雲字韻','杜範','宋','宋诗','song-poetry','','[]','我來縠水償披雲，秋堂靄靄生春薰。',64,'全唐诗/poet.song.193000.json','["我來縠水償披雲，秋堂靄靄生春薰。", "落筆盤空鬭神速，刮眼一破平生聞。", "自笑黏黐日凭案，抽思索句曾未半。", "弱步何由附天驥，肝膽輪囷慙寸管。"]'),
('673874ae-ae49-4c76-98f3-65cc55378a54','和鄭府判秋闈行','杜範','宋','宋诗','song-poetry','','[]','秋雲黄，日月忙，登選才俊收詞章。',224,'全唐诗/poet.song.193000.json','["秋雲黄，日月忙，登選才俊收詞章。", "操觚搦翰換鐘鼎，往往冰炭交中腸。", "柯山多士稱海內，勇氣洗盡古戰場。", "笑揮筆陣示整暇，灑灑胸中書傳香。", "此邦昔日龍頭客，前後相輝九霄翮。", "山川孕秀不乏人，想已津津動顔色。", "題輿左嶽得儒英，行整速步趨天庭。", "金薤琳瑯耀光彩，不學砌下寒蛩鳴。", "蓋世功名人共許，赤手欲搏南山虎。", "蹔來秋院鎮文場，坐使千袍同鼓舞。", "我昔貧困如匡衡，隣燈夜照心崢嶸。", "區區薄宦亦謾爾，役役塵埃愧此生。", "淺學幽深雖未燭，到耳獨能辨絲竹。", "從今著意聽文鳴，會使嚶嚶出幽谷。"]'),
('a5e14e55-8219-4ec7-9b5f-621195a00c5e','又和鄭府判韻','杜範','宋','宋诗','song-poetry','','[]','荆璞照耀非常珍，天衢整步凌通津。',128,'全唐诗/poet.song.193000.json','["荆璞照耀非常珍，天衢整步凌通津。", "與人軒闢破畦畛，滿懷拍拍無非春。", "我如櫪驥異遠道，志在千里身未到。", "朅來此地尋文盟，平生心事爲傾倒。", "飽德醉義樂有餘，况有蘭玉芬庭除。", "諧笑云云殊未厭，盤飧夜半勞兵厨。", "依依此情那忍去，自恨塵鞍難久駐。", "佇看飛詔自天來，殿前賸作摩空賦。"]'),
('69954a70-4bf8-42e9-9117-89883d25898d','漢中行','杜範','宋','宋诗','song-poetry','','[]','思昔漢中殆，羯奴自荒逖。',348,'全唐诗/poet.song.193000.json','["思昔漢中殆，羯奴自荒逖。", "驅侵警邊陲，腥臊污華國。", "官守蒙胡塵，宮廟入胡域。", "姦回執國命，地土輕棄擲。", "倒懸頭足互，妖氛日月黑。", "念之不忍言，言之淚沾臆。", "壽皇雄武姿，一洗曾莫得。", "祖宗固有靈，何以重此慼。", "忠賢固有心，何以久阻抑。", "忍恥坐薪亦幾年，生聚教訓亦纖悉。", "昨者飛詔天上來，積穢坐欲一朝滌。", "忘形感憤泣東南，氣生果銳吞西北。", "似聞元戎已啟行，官軍所到無勍敵。", "倒戈橫尸四十里，搴旗獲馬六千匹。", "長安遺老今尚在，壺漿筐篚輸悃愊。", "勇威義氣有如此，鼎魚鬭沸真假息。", "事雖未必合所聞，要之天地當開闢。", "池魚一日羊角上，此理從來有通塞。", "世人信古不信今，動把國事作嘲赥。", "胡憯不念涵煦恩，坐看行人鬭道側。", "嗟予少小則古昔，有志未就苦弱植。", "茅簷獨對參斗橫，百感交情節屢擊。", "男兒出世豈無爲，七尺非供螻蟻食。", "當年幕庭三誦人，乃有洙泗詩禮客。"]'),
('1f9c3622-8585-4583-a05a-809d09c9aa95','黄兄宇出示湯丈追和春日詩適有會余情者次韻','杜範','宋','宋诗','song-poetry','','[]','君不見西山凜凜百世師，忍窮受餓終采蕨。',134,'全唐诗/poet.song.193000.json','["君不見西山凜凜百世師，忍窮受餓終采蕨。", "又不見醜謬遺臭幾千載，當年方丈厭肥滑。", "孰得孰失試大觀，較若五味辨甘辣。", "冶容媚世吁可憐，羞面顧影自塗抹。", "名利物我爭錙銖，語笑詡詡已衷甲。", "方嗟天際暮雲深，還見牆陰春草茁。", "旨哉君詩良起予，重把心事爲君說。", "百年功名亦漫爾，塵路投蹤何日脫。"]'),
('5b8d84b7-e89b-4633-91a0-e781a480acce','再次沈節推送春韻','杜範','宋','宋诗','song-poetry','','[]','子規泣訴春山頭，芳草連天不盡愁。',96,'全唐诗/poet.song.193000.json','["子規泣訴春山頭，芳草連天不盡愁。", "紫陌遊人在何處，空有顰眉人倚樓。", "溪上悠悠棹木蘭，溪邊落紅紛斑斑。", "嗟哉片片逐流水，新篁忽長千琅玕。", "多少閑愁推不去，欲問春歸杳無處。", "少年知已負心期，尊酒從今樂事稀。"]'),
('1a420e36-c143-4d6c-83d1-9a4ec339c2dd','歸自明遠醉中作','杜範','宋','宋诗','song-poetry','','[]','觴豆論交今豈無，肺肝相與古來少。',176,'全唐诗/poet.song.193000.json','["觴豆論交今豈無，肺肝相與古來少。", "我今宦游雙溪上，一見爲僚盡傾倒。", "吏塵終日何沒沒，休澣有盟方皦皦。", "點檢春事今幾何，殘紅滿地紛不掃。", "明遠奇觀雄此邦，倚欄一望雲縹緲。", "潑眼爭光堤面流，傷心不盡天涯草。", "文楸得失亦漫爾，投壺成敗供一笑。", "酒酣耳熱聲烏烏，語到難言心悄悄。", "一切置之姑勿道，四時風月殊未了。", "鬢華知復爲誰老，我輩心事要論討。", "尚喜後會今有期，誰其識之有鷗鳥。"]'),
('bfde0337-00d2-4a43-8ec5-71d711e50bde','七夕歌','杜範','宋','宋诗','song-poetry','','[]','象緯昭垂各度躔，牛女之說從何年。',137,'全唐诗/poet.song.193000.json','["象緯昭垂各度躔，牛女之說從何年。", "博物有志張茂先，客槎親見織與牽。", "坐令千載習繆傳，遂將濁欲穢清玄。", "詩史實錄百世賢，亦以俚語形歌篇。", "君不見昭陽夜靜玉欄邊，誰知漁陽萬騎橫戈鋋。", "何如鳳簫縹緲緱山巔，舉手辭世乘雲軿。", "我欲浩歌痛飲秋風前，仰視星斗奕奕紛羅駢。", "安得壯士橫笛一聲吹上徹九天。"]'),
('777645da-2ab5-4e06-a977-ba32ac6ed68e','詹世顯老丈舂米爲贈時有張老之子携其父詩求月助即以詹米轉饋之詹丈以詩送米和其詩','杜範','宋','宋诗','song-poetry','','[]','歸來兩見春載耜，老矣陳人愧髦士。',128,'全唐诗/poet.song.193000.json','["歸來兩見春載耜，老矣陳人愧髦士。", "書生活計常若拙，瓶粟屢空固其理。", "石莊好義無不爲，獨將飽腹念朝饑。", "擔石赬肩米叩戶，要轉兒啼成歡嬉。", "此賜何敢望此老，况有新詩非草草。", "再拜爲之驚且慙，錦章玉粲鬭新好。", "我貧猶有稻粱謀，更有貧士需麥舟。", "爲君乞與君然否，樂施曷計誰家留。"]'),
('96625a67-3ddc-4d7b-b7a0-f9cad4d22ee9','新秋','杜範','宋','宋诗','song-poetry','','[]','大火西流日，秋風戶到時。',48,'全唐诗/poet.song.193000.json','["大火西流日，秋風戶到時。", "斷痕依淺水，疊翠別高枝。", "氣每隨時改，人應共物萎。", "百年同一夢，身後欲何爲。"]'),
('4c674f0a-5ea1-4b5c-8528-ef938ebed55c','電','杜範','宋','宋诗','song-poetry','','[]','玉女開天笑，驪龍弄月珠。',48,'全唐诗/poet.song.193000.json','["玉女開天笑，驪龍弄月珠。", "照眸千壑滿，應手一絲無。", "晻映同雲表，行移轉海隅。", "田夫占北極，明日雨平鋪。"]'),
('7a85a552-b351-42bd-aafb-bb19fb05a5e5','和澧州喜雨韻','杜範','宋','宋诗','song-poetry','','[]','秋色在何許，浮嵐疊翠間。',48,'全唐诗/poet.song.193000.json','["秋色在何許，浮嵐疊翠間。", "江清雙鳥渡，天闊片雲閑。", "雅量肩文舉，新詩壓子山。", "更深聽遠溜，哦詠答濺濺。"]'),
('a0177fdb-5cc4-4da4-b299-2bdcb4771ce1','十五日十九兄到家小飲有詩和之','杜範','宋','宋诗','song-poetry','','[]','晚色煙霞好，寒山雪月明。',48,'全唐诗/poet.song.193000.json','["晚色煙霞好，寒山雪月明。", "賞心聞鵲喜，醉臉任狸形。", "銀燭輝蓬戶，冰花爍膽瓶。", "讀君斷腸句，孤雁欲吞聲。"]'),
('62fe018d-790b-411a-9d5b-9c7bb2670194','是夜聞十六兄雪中有作次韻','杜範','宋','宋诗','song-poetry','','[]','晚山棲半白，晚岫勒斜紅。',48,'全唐诗/poet.song.193000.json','["晚山棲半白，晚岫勒斜紅。", "草草三杯裏，悠悠一笑中。", "喜君才磊磈，顧我意蒙茸。", "伯仲壎箎處，空嗟不與同。"]'),
('419cb9fc-b2c8-4a98-83dc-643a1a5aec8c','次鄭府判金字韻','杜範','宋','宋诗','song-poetry','','[]','巇嶇來北固，邂逅識南金。',48,'全唐诗/poet.song.193000.json','["巇嶇來北固，邂逅識南金。", "未覺人間役，欣同物外心。", "燈花殘夜半，桂子落秋深。", "細聽朱絃曲，寥寥大雅音。"]'),
('e6fbd184-1516-49d9-b800-f987bdf30e77','和十四兄靈巖偶作','杜範','宋','宋诗','song-poetry','','[]','松關開野寺，山色凈藜牀。',48,'全唐诗/poet.song.193000.json','["松關開野寺，山色凈藜牀。", "戰局誰爭勝，夸聲或大當。", "有人觀物靜，得句滿囊香。", "鷗鷺盟猶在，閑中作此忙。"]'),
('87a03760-818d-4a7d-94d5-3b19a04a61c7','次會再和','杜範','宋','宋诗','song-poetry','','[]','古殿後多竹，虛簷前可牀。',48,'全唐诗/poet.song.193000.json','["古殿後多竹，虛簷前可牀。", "炎歊於此却，胸次要人當。", "自足蕭蕭意，時來細細香。", "曲肱無一事，閑爲屬詩忙。"]'),
('c1765116-fef2-4fdd-a30d-39f27b09f695','和十九兄梅韻二首  其一','杜範','宋','宋诗','song-poetry','','[]','空谷寒花好，荒村野路長。',48,'全唐诗/poet.song.193000.json','["空谷寒花好，荒村野路長。", "有懷尋往事，無語攪枯腸。", "老氣猶無恙，幽姿只自香。", "喜君歌白雪，茂對此新陽。"]'),
('9b5c9482-379f-45a9-a978-41eb112a52df','和十九兄梅韻二首  其二','杜範','宋','宋诗','song-poetry','','[]','語別星霜久，懷人道里長。',48,'全唐诗/poet.song.193000.json','["語別星霜久，懷人道里長。", "江山高著眼，文字飽撐腸。", "窮壑生新態，寒梅带舊香。", "它年當記憶，有雁過衡陽。"]'),
('6b420273-e842-4f18-b2d0-ee3663d6befd','九月二十六日觀水','杜範','宋','宋诗','song-poetry','','[]','滔滔隨岫遠，𤅣𤅣浸沙寒。',48,'全唐诗/poet.song.193000.json','["滔滔隨岫遠，𤅣𤅣浸沙寒。", "萬古去不極，幾人來此看。", "放乎知有本，逝者若爲難。", "瞪目斜陽裏，雙鷗下碧瀾。"]'),
('7b08709a-17ab-46c3-93ec-929cc663ae2c','道傍見梅','杜範','宋','宋诗','song-poetry','','[]','一樹棲殘雪，不禁春夜霜。',48,'全唐诗/poet.song.193000.json','["一樹棲殘雪，不禁春夜霜。", "香飄非寶篆，粉褪厭時粧。", "且合收餘白，應難待晚黄。", "自便籬落好，榛棘不相妨。"]'),
('5c4422ff-f13f-467e-94ff-793191a149c1','別宛陵同官','杜範','宋','宋诗','song-poetry','','[]','遊宦見交情，惟憂間易生。',48,'全唐诗/poet.song.193000.json','["遊宦見交情，惟憂間易生。", "文書祇自了，意氣若爲傾。", "幸已符金斷，終然爲玉成。", "官僚有如此，共保歲寒盟。"]'),
('991b2bbf-6211-4312-97cb-7409d0081694','途中','杜範','宋','宋诗','song-poetry','','[]','官身驚昨夢，山店是回程。',48,'全唐诗/poet.song.193000.json','["官身驚昨夢，山店是回程。", "郡事關新舊，人心屬送迎。", "塵衫纔幸脫，野服要須成。", "世路如川險，歸途却自平。"]'),
('7a4548b5-ece0-4500-bbe8-4ee0efc8164e','有感','杜範','宋','宋诗','song-poetry','','[]','捧檄來茲邑，勞勞兩載餘。',48,'全唐诗/poet.song.193000.json','["捧檄來茲邑，勞勞兩載餘。", "親庭千里隔，家信十分疎。", "有婦聞多病，諸兒盡廢書。", "低簷秋雨滴，點點正愁予。"]'),
('91d4b2cf-cb4b-4d37-b48b-eb233f100596','和楊兄五言二首  其一','杜範','宋','宋诗','song-poetry','','[]','羈栖餘兩載，塵擾費三思。',48,'全唐诗/poet.song.193000.json','["羈栖餘兩載，塵擾費三思。", "愧匪江陵掾，空多東野詩。", "佩囊無限富，擊鉢已嫌遲。", "細讀停雲句，多應負所期。"]'),
('823baa12-8947-4e98-ac52-cb960e471c1b','和楊兄五言二首  其二','杜範','宋','宋诗','song-poetry','','[]','納履終朝役，挑燈獨夜思。',48,'全唐诗/poet.song.193000.json','["納履終朝役，挑燈獨夜思。", "功名非我事，風月負君詩。", "菽水謀多拙，山林計未遲。", "江村梅正好，珍重歲寒期。"]'),
('049424cd-5ca6-4ae6-a98b-17679a2ffa71','趙山甫居玉壺盡得湖山之勝醉後和其韻二章  其一','杜範','宋','宋诗','song-poetry','','[]','占盡春光好，湖山一覽餘。',48,'全唐诗/poet.song.193000.json','["占盡春光好，湖山一覽餘。", "著身蓬島裏，縱目畫屏如。", "我計還知錯，君謀定不疎。", "它年同到此，卜築莫躊躇。"]'),
('fe5b98ef-6c63-43d6-adb8-b726f24d157d','趙山甫居玉壺盡得湖山之勝醉後和其韻二章  其二','杜範','宋','宋诗','song-poetry','','[]','相見雖無幾，相觀却有餘。',48,'全唐诗/poet.song.193000.json','["相見雖無幾，相觀却有餘。", "清襟無這樣，塵世有誰如。", "文理須教密，濃醺且放疎。", "論文何日再，欲別更躊躇。"]'),
('8713555f-52d5-4256-beae-1facc9e51e65','舟早行將至三界偶成','杜範','宋','宋诗','song-poetry','','[]','辭京塵漸遠，入越思逾清。',48,'全唐诗/poet.song.193000.json','["辭京塵漸遠，入越思逾清。", "雨壑溪方漲，風帆去又輕。", "天光浮水闊，山色带雲橫。", "更問鄉關路，從今尚幾程。"]'),
('46c98270-da4b-4d54-8774-a6bc7e412555','捉筆次前韻  其一','杜範','宋','宋诗','song-poetry','','[]','小雨添溪滑，新晴散野清。',48,'全唐诗/poet.song.193000.json','["小雨添溪滑，新晴散野清。", "寸襟如水闊，一槳共雲輕。", "坦坦道皆直，縈縈徑自橫。", "天衢從此卜，何用問前程。"]'),
('3530516e-46ea-4ba6-ab05-28f1b47275b2','捉筆次前韻  其二','杜範','宋','宋诗','song-poetry','','[]','晨炊浮早渡，午夜過錢清。',48,'全唐诗/poet.song.193000.json','["晨炊浮早渡，午夜過錢清。", "越國移舟便，曹娥上堰輕。", "人言三界近，共指一山橫。", "古剡明朝到，籃輿數去程。"]'),
('c46ac38b-7c17-43f3-bef9-72f9f4ceb234','捉筆次前韻  其三','杜範','宋','宋诗','song-poetry','','[]','厭見塵泥汩，喜看沙水清。',48,'全唐诗/poet.song.193000.json','["厭見塵泥汩，喜看沙水清。", "魚攢偎日暖，鷗去帖波輕。", "寒渡人來少，閑舟岸與橫。", "不須催去槳，溪曲不論程。"]'),
('13561b25-51d1-4a05-9631-365994d1be94','和孫司門寄寬堂詩  其一','杜範','宋','宋诗','song-poetry','','[]','官喜文書少，塵迷歲月遷。',48,'全唐诗/poet.song.193000.json','["官喜文書少，塵迷歲月遷。", "豈無車可出，儻有約宜堅。", "傍水尋疎影，裁詩續舊編。", "孤山須竟日，去莫買游船。"]'),
('66d25408-dd8d-47e9-a4da-f6ea71947b8e','和孫司門寄寬堂詩  其二','杜範','宋','宋诗','song-poetry','','[]','靖節非沉湎，行藏豈漫遊。',48,'全唐诗/poet.song.193000.json','["靖節非沉湎，行藏豈漫遊。", "幾多經濟具，可付醉吟休。", "志在存周鼎，悲能學楚囚。", "流風千載想，我欲賦登樓。"]'),
('f0eb3084-bbc3-43ce-b9e2-188a12e2f8ff','和吳準齋所賡劉石澗詠湖山之樂因見示韻','杜範','宋','宋诗','song-poetry','','[]','勝賞付飛觴，詩人妙嚼芳。',48,'全唐诗/poet.song.193000.json','["勝賞付飛觴，詩人妙嚼芳。", "荷君相抆拭，容我共清凉。", "湛俗人空老，偷閑策最長。", "高峰應更好，何日曳桄榔。"]'),
('896e781d-3825-47e8-bbbd-a5c747acf2a4','戲賦段橋風箏','杜範','宋','宋诗','song-poetry','','[]','段橋牽紙鷂，兒戲亦關心。',48,'全唐诗/poet.song.193000.json','["段橋牽紙鷂，兒戲亦關心。", "風快應難挽，雲高徑欲侵。", "人誇無限力，身直不多金。", "說與須知道，明朝不似今。"]'),
('a985adda-d4a9-47ae-89ef-024eb06383eb','水簾谷','杜範','宋','宋诗','song-poetry','','[]','巨崖森四立，谺洞費前瞻。',48,'全唐诗/poet.song.193000.json','["巨崖森四立，谺洞費前瞻。", "鳥道穿危磴，虬松奮老髯。", "巖高全似砌，水小不成簾。", "半生纔此見，雖倦未應嫌。"]'),
('417b0e8f-4bd3-442a-b97c-aa134f43e452','賦夏肯父所性堂','杜範','宋','宋诗','song-poetry','','[]','心外非吾有，區間忝爾生。',48,'全唐诗/poet.song.193000.json','["心外非吾有，區間忝爾生。", "道原無欠剩，物與共流行。", "繩甕誰言辱，旂常未足榮。", "反躬深體認，莫浪付詩情。"]'),
('a07dbdf9-da7f-4090-a58a-2938d8ff3acf','酬謝韓仲和見贈','杜範','宋','宋诗','song-poetry','','[]','丹心空自照，白首欲何成。',48,'全唐诗/poet.song.193000.json','["丹心空自照，白首欲何成。", "踏地方求實，箋天敢爲名。", "樹深秋水浄，山遠暮雲輕。", "索我文書外，論交深友生。"]'),
('47c8acd9-399b-487f-8328-1680f8e80c68','挽王侍郎二首  其一','杜範','宋','宋诗','song-poetry','','[]','地靈鍾國秀，臚唱壓時名。',48,'全唐诗/poet.song.193000.json','["地靈鍾國秀，臚唱壓時名。", "虎觀堅廉節，螭坳振直聲。", "志隨時暫鬰，身與道俱榮。", "人羨腰金日，於公孰重輕。"]'),
('1a270ba4-83dc-461e-bc79-8dfba5ba11a0','挽王侍郎二首  其二','杜範','宋','宋诗','song-poetry','','[]','里枌敷蔭樾，晝繡借輝光。',48,'全唐诗/poet.song.193000.json','["里枌敷蔭樾，晝繡借輝光。", "誘接嘗登席，摳趨屢負牆。", "故山欣弭節，華屋痛帷堂。", "歲晚凋松柏，令人重慨傷。"]'),
('ac631726-193d-443c-8595-edb2794ad049','挽鍾保義','杜範','宋','宋诗','song-poetry','','[]','竇館名猶在，燕山事有光。',48,'全唐诗/poet.song.193000.json','["竇館名猶在，燕山事有光。", "解衣非楚纊，指廩異齊棠。", "映日庭蘭蔚，餘風宰木香。", "翠珉垂世勸，寧復事雕章。"]'),
('090acac2-dadc-41ce-bf1a-3681d84d0209','挽劉監丞二首  其一','杜範','宋','宋诗','song-poetry','','[]','諸老凋零盡，公胡不少留。',48,'全唐诗/poet.song.193000.json','["諸老凋零盡，公胡不少留。", "麈談裁後進，山立儼前脩。", "逸館休黄髮，爲邦付黑頭。", "甌閩看蔽芾，有淚正難收。"]'),
('0ae66c28-f8d3-4805-8873-e561f789f43d','挽劉監丞二首  其二','杜範','宋','宋诗','song-poetry','','[]','奕世詩書遠，三劉姓字香。',48,'全唐诗/poet.song.193000.json','["奕世詩書遠，三劉姓字香。", "鄉評高宿望，里社借餘光。", "蓮浦秋堂晚，松岡夜室長。", "典刑無復見，南望獨凄凉。"]'),
('232decde-b442-4216-8d87-787bb6472d91','挽葉子儀二首  其一','杜範','宋','宋诗','song-poetry','','[]','性質孰無偏，工夫豈易鎸。',48,'全唐诗/poet.song.193000.json','["性質孰無偏，工夫豈易鎸。", "人誰知此學，我獨謂公賢。", "耿耿存憂世，悠悠付逝川。", "一經端有屬，拭目看家傳。"]'),
('d147f325-070d-4c96-abe6-b48006017be2','挽葉子儀二首  其二','杜範','宋','宋诗','song-poetry','','[]','當年共短檠，心事熟論評。',48,'全唐诗/poet.song.193000.json','["當年共短檠，心事熟論評。", "豈我非同志，於公不用情。", "幾多才莫試，有此恨難平。", "舊友凋零盡，悲哉伐木聲。"]'),
('dbfdbae8-050b-43b5-a779-9f910ac638dc','挽項監鎮','杜範','宋','宋诗','song-poetry','','[]','男兒志四方，世事苦難量。',48,'全唐诗/poet.song.193000.json','["男兒志四方，世事苦難量。", "蚤逐功名誤，空令歲月荒。", "倦遊歸故里，幽興肯新堂。", "當日多知己，諸公孰在亡。"]'),
('5b1af4b4-2b88-4ca1-bf42-9417ab2e3604','太師平章喬文惠公挽歌詞三首  其一','杜範','宋','宋诗','song-poetry','','[]','奕世諸賢輔，清朝得老成。',48,'全唐诗/poet.song.193000.json','["奕世諸賢輔，清朝得老成。", "諫兵秦蹇叔，憂國漢蕭生。", "更化人皆仰，調元位獨亨。", "天遲諸葛死，尚欲致昇平。"]'),
('57b31e0d-f46c-4083-ae90-6e4ec48fb074','太師平章喬文惠公挽歌詞三首  其二','杜範','宋','宋诗','song-poetry','','[]','名在洪鈞上，身遊綠野中。',48,'全唐诗/poet.song.193000.json','["名在洪鈞上，身遊綠野中。", "社方娛白傅，城遽閉滕公。", "國勢關輕重，君恩著始終。", "堪嗟典刑盡，羣木刺寒空。"]'),
('04da475a-ec29-41e0-b19d-1d316f77f9a8','太師平章喬文惠公挽歌詞三首  其三','杜範','宋','宋诗','song-poetry','','[]','憶在烏傷日，驚騰鶚薦辭。',48,'全唐诗/poet.song.193000.json','["憶在烏傷日，驚騰鶚薦辭。", "自憐拘法守，何以答心知。", "零露黄花暗，凄風畫翣悲。", "遥瞻孔山路，無計送靈輀。"]'),
('9a628798-b191-42ba-8164-1501cfb3f9ae','挽周迪功二首  其一','杜範','宋','宋诗','song-poetry','','[]','書種開風氣，儒聲動海涯。',48,'全唐诗/poet.song.193000.json','["書種開風氣，儒聲動海涯。", "一門團義聚，千里擇名師。", "重卦終須卜，留耕已可菑。", "賢書初入貢，玉樹影參差。"]'),
('fe1cdd31-b0d0-4bf1-bd43-796e08e718bd','挽周迪功二首  其二','杜範','宋','宋诗','song-poetry','','[]','憶昔癡兒幸，聯君季氏姻。',48,'全唐诗/poet.song.193000.json','["憶昔癡兒幸，聯君季氏姻。", "兩家成契闊，一夢記酸辛。", "鄉譽聞君子，銘章又古人。", "落花愁暮雨，凄冷不成春。"]'),
('c135f5b2-036c-48f6-ad52-e922f3e544f7','挽張監丞','杜範','宋','宋诗','song-poetry','','[]','我兄同昔席，我亦接青班。',48,'全唐诗/poet.song.193000.json','["我兄同昔席，我亦接青班。", "不盡明時用，空令老淚潸。", "筍聯纔胄監，竹使只鄉關。", "時豈無知己，吁嗟世路難。"]'),
('3ff5d5c4-2741-4e0f-bcc0-0708340d491f','挽趙漕二首  其一','杜範','宋','宋诗','song-poetry','','[]','蔚蔚郎闈望，皇皇使節輝。',48,'全唐诗/poet.song.193000.json','["蔚蔚郎闈望，皇皇使節輝。", "競時俱勇往，懷寶獨言歸。", "皂蓋人方惜，黄粱夢已非。", "蕭山遺老在，誰使涕交揮。"]'),
('608f3e96-b44a-4974-9853-e4868aaf3b99','挽趙漕二首  其二','杜範','宋','宋诗','song-poetry','','[]','歛袵從童丱，巢枝幸里閭。',48,'全唐诗/poet.song.193000.json','["歛袵從童丱，巢枝幸里閭。", "塵蹤誰抆拭，餘論借吹噓。", "得意鳴珂地，驚嗟素錦車。", "直言公不死，蘭玉秀階除。"]'),
('104869cc-31d2-4999-94bb-6ca78cb7ae06','趙學士挽詩','杜範','宋','宋诗','song-poetry','','[]','鼎盛彈冠地，胡然袖手居。',48,'全唐诗/poet.song.193000.json','["鼎盛彈冠地，胡然袖手居。", "自怡還自足，誰毀又誰譽。", "花竹人安在，芸蘭慶有餘。", "華塗驚素錦，行道盡欷歔。"]'),
('bff515e0-c21c-41a2-ab51-1173ddecfff0','挽陳漢英','杜範','宋','宋诗','song-poetry','','[]','庠塾崇師道，鄉閭重典刑。',48,'全唐诗/poet.song.193000.json','["庠塾崇師道，鄉閭重典刑。", "麟經開晚學，鶚表動天庭。", "頭未終朝黑，衫能幾日青。", "文章難得力，愁絕峴山塋。"]'),
('13ec251a-3d61-4b44-b6cf-efe87daa06d8','新秋二首  其一','杜範','宋','宋诗','song-poetry','','[]','少昊行秋正疾驅，灑然凉色已侵膚。',64,'全唐诗/poet.song.193000.json','["少昊行秋正疾驅，灑然凉色已侵膚。", "翠空碧水涵高下，淡靄蒼煙半有無。", "風露已經生慘戚，菰蒲且欲慰斯須。", "誰將霜竹橫雲外，似有悲聲與恨俱。"]'),
('395ff60e-bb53-4c5a-b652-add73f79ffee','新秋二首  其二','杜範','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一葉階前落淺黄，已知秋色渡長江。',64,'全唐诗/poet.song.193000.json','["一葉階前落淺黄，已知秋色渡長江。", "百骸假合寧長健，萬慮叢生未肯降。", "荒草露寒飛蝶盡，暮山煙带白鷗雙。", "倚欄獨立渾無語，時把殘篇對小窗。"]'),
('198182ae-19ce-4ad8-846d-4e173c02d324','春雨甲子而潤澤不違時夏已更秋方慮乾涸一夕沛然優渥矣喜而寫情','杜範','宋','宋诗','song-poetry','','[]','甲子謠言未足聽，沛然甘澤以時行。',64,'全唐诗/poet.song.193000.json','["甲子謠言未足聽，沛然甘澤以時行。", "平田不藉開渠水，野老誰思逐婦聲。", "黄倒積雲承露重，青翻長浪簸風輕。", "賤夫一飽誠爲幸，更祝傾河灑甲兵。"]'),
('9da4f786-8ab6-433f-a6c9-87f9d0bdd537','繼和嚴君壁上韻','杜範','宋','宋诗','song-poetry','','[]','山舍榱楹朽蠹餘，朅來小圃作閑居。',64,'全唐诗/poet.song.193000.json','["山舍榱楹朽蠹餘，朅來小圃作閑居。", "推移寧免人間世，灑落還同心地初。", "鷗鷺齊盟忘物我，薜蘿交翠映簪裾。", "恭惟不負傳心印，已把浮生付六如。"]'),
('cc7fe42e-9b77-45f9-9d10-bc1b7989a323','丁卯九月十夜觀月','杜範','宋','宋诗','song-poetry','','[]','草露團團夜氣濃，一天明月半彎弓。',64,'全唐诗/poet.song.193000.json','["草露團團夜氣濃，一天明月半彎弓。", "光涵萬頃澄秋霽，影落千山接翠空。", "毫髮不迷孤照處，膽肝盡露廣寒宮。", "回廊獨步渾無覺，似是泠然駕遠風。"]'),
('b0882a94-3cfa-4cc8-9aa7-c8833b2d0a6d','己巳登玉峰亭二首  其一','杜範','宋','宋诗','song-poetry','','[]','與君携手上巒坡，多少塵襟盡刮磨。',64,'全唐诗/poet.song.193000.json','["與君携手上巒坡，多少塵襟盡刮磨。", "一鳥橫邊秋靄淡，片雲歸處夕陽多。", "潮來萬里翻明練，山簇千峰列翠螺。", "此地不堪歸去早，欠看明月漲金波。"]'),
('cd1e6358-476a-4c3a-8c2d-76e42027d46d','己巳登玉峰亭二首  其二','杜範','宋','宋诗','song-poetry','','[]','杖藜無事歷危坡，一片清寒鏡面磨。',64,'全唐诗/poet.song.193000.json','["杖藜無事歷危坡，一片清寒鏡面磨。", "極目盡時知水闊，置身高處見秋多。", "此時不著登山屐，到處還成測海螺。", "遥想高人閑物外，故應不與世同波。"]'),
('7a0b0fa2-4137-44e4-aeab-03a591645083','八月十一夜風月可愛自前屋覓酒不得而歸小詩呈百六十叔','杜範','宋','宋诗','song-poetry','','[]','晚煙輕拂亂山橫，落日纔收月已明。',64,'全唐诗/poet.song.193000.json','["晚煙輕拂亂山橫，落日纔收月已明。", "萬頃孤光低闊野，一天寒色带疎星。", "交情要與秋容淡，携手難禁夜氣清。", "慣識醉中風月好，不知風月更宜醒。"]'),
('4866f3c1-4c53-49ae-9e61-374eb3828ccf','次韻草堂','杜範','宋','宋诗','song-poetry','','[]','心事崔嵬日不如，愁端叢起蔓難圖。',64,'全唐诗/poet.song.193000.json','["心事崔嵬日不如，愁端叢起蔓難圖。", "殘山剩水鳥聲怨，落日微雲雁影孤。", "妙句聳聞驚昨夢，寒窗細讀慰來蘇。", "許身已在羲皇上，降志猶能念昔吾。"]'),
('36b0e17e-5a78-482a-bfc3-22f58d901fe4','偶屬成嵬字韻錄呈六十叔二首  其一','杜範','宋','宋诗','song-poetry','','[]','溪頭徙倚對崔嵬，世上塵愁安在哉。',64,'全唐诗/poet.song.193000.json','["溪頭徙倚對崔嵬，世上塵愁安在哉。", "峭壁千尋翻素練，深崖萬古鬭雄雷。", "空餘鳥跡無人到，應有山靈怪我來。", "偶爾相逢成勝槩，平生襟抱此中開。"]'),
('04d845b5-d4b5-4d92-8e48-62a33e168850','偶屬成嵬字韻錄呈六十叔二首  其二','杜範','宋','宋诗','song-poetry','','[]','莫令胸次著崔嵬，萬事於人何有哉。',64,'全唐诗/poet.song.193000.json','["莫令胸次著崔嵬，萬事於人何有哉。", "欲向懸崖看積雨，幾經空谷撼奔雷。", "山花無思開還落，溪鳥忘機去復來。", "此地逍遥吾足矣，解愁春甕不須開。"]'),
('2299f9e5-96f5-443c-bbcd-54c45a80461b','清真褚道士携羅丈唱和訪余求詩予非能詩者辭不獲力拙次韻能不以狂斐疵我否','杜範','宋','宋诗','song-poetry','','[]','遠尋幽侶對清閑，落筆煙霞寫壯觀。',64,'全唐诗/poet.song.193000.json','["遠尋幽侶對清閑，落筆煙霞寫壯觀。", "不染紅塵隨處適，獨將青眼箇中看。", "雲飛碧落無心到，月浸清波徹底寒。", "遥想銜杯當日意，灑然新沐欲彈冠。"]'),
('68e58d81-5bb9-440c-b1d2-8ea726160bfa','和宗司法與鄭府判韻  其一','杜範','宋','宋诗','song-poetry','','[]','毫端收盡九秋清，凡目容窺巨海驚。',64,'全唐诗/poet.song.193000.json','["毫端收盡九秋清，凡目容窺巨海驚。", "別駕錦囊誇李賀，參軍石鼎續彌明。", "珠璣錯落交輝映，金石鏗鏘迭奏成。", "迷道願君相指似，敢辭駑鈍策孤征。"]'),
('bf2f4ed1-86aa-434d-b87f-d404372187e3','和宗司法與鄭府判韻  其二','杜範','宋','宋诗','song-poetry','','[]','候蟲嘖嘖泣秋清，節物還令壯士驚。',64,'全唐诗/poet.song.193000.json','["候蟲嘖嘖泣秋清，節物還令壯士驚。", "人在九原誰可作，月橫千里自增明。", "詩壇尚幸從盟約，句法于今識老成。", "自愧枯腸如罄室，只愁有債未寬征。"]'),
('da97ac64-198e-4a32-a918-648ffa4cb276','又和鄭府判侯字韻','杜範','宋','宋诗','song-poetry','','[]','野人漫學事王侯，宦牒相從得俊遊。',64,'全唐诗/poet.song.193000.json','["野人漫學事王侯，宦牒相從得俊遊。", "著眼丹鉛常午夜，轉頭萸菊已深秋。", "幾多陳迹成今古，莫對清尊話去留。", "自幸趨隅陪玉麈，如今何止識荆州。"]'),
('3ace7086-1d21-40a2-86a5-d4d8f1d1a2cf','復用韻以見別情','杜範','宋','宋诗','song-poetry','','[]','插架牙籤富鄴侯，戲將翰墨此中遊。',64,'全唐诗/poet.song.193000.json','["插架牙籤富鄴侯，戲將翰墨此中遊。", "紫萸黄菊家家酒，巨軸長篇字字秋。", "談笑不堪增戀遊，簡書無奈怕淹留。", "人生聚散真萍梗，咫尺應能見九州。"]'),
('dd5bee3b-2e48-4799-9cb1-e96a8f4f5fe6','別張簿兄弟','杜範','宋','宋诗','song-poetry','','[]','弱柳含風拂路隅，一尊話別意躊躕。',64,'全唐诗/poet.song.193000.json','["弱柳含風拂路隅，一尊話別意躊躕。", "相看未了百年事，有約無忘千里書。", "到手功名還漫浪，褆身德業念居諸。", "願君一語勤相贈，拜賜從今儻不虛。"]'),
('52983b2e-51c9-4c52-a985-90f08f916964','戊寅夏和趙十七兄招提偶作','杜範','宋','宋诗','song-poetry','','[]','故山携手愜心期，里社從遊即舊規。',64,'全唐诗/poet.song.193000.json','["故山携手愜心期，里社從遊即舊規。", "十雨五風深望歲，一尊重會只催詩。", "多君格力開壇社，得句精神見睫眉。", "匹馬秋風思遠道，此盟常恐憶它時。"]'),
('ead16690-5172-4e1c-85e0-13dbac23808d','遊擘翠','杜範','宋','宋诗','song-poetry','','[]','新晴山色浄襟裾，世上塵埃一點無。',64,'全唐诗/poet.song.193000.json','["新晴山色浄襟裾，世上塵埃一點無。", "飛瀑驚奔爭澒洞，層崖屹立鎮崟嶇。", "亂流平處沙可數，頑石叢中草不枯。", "醉後偶來觀物變，要知到處是工夫。"]'),
('5aaa094a-f170-4813-a1da-853e5f14f422','和沈節推韻','杜範','宋','宋诗','song-poetry','','[]','點檢春光向幾多，埋頭官事暗中過。',64,'全唐诗/poet.song.193000.json','["點檢春光向幾多，埋頭官事暗中過。", "蕭蕭鬢影霜先入，匝匝襟塵鏡未磨。", "盟會誰令寒晉楚，篇詞自幸識陰何。", "休文多病風流甚，紅藥尊前獨醉歌。"]'),
('f2ab7e67-232a-49f3-acec-4d59c3e44a15','次陳友韻','杜範','宋','宋诗','song-poetry','','[]','企望隣邦百里賒，一時文物數名家。',64,'全唐诗/poet.song.193000.json','["企望隣邦百里賒，一時文物數名家。", "驚人議論鏗蒼佩，落筆詞章粲彩霞。", "此日相逢真有幸，何年重會恐無涯。", "顧余何以爲君別，多愧新詩屢拜嘉。"]'),
('eef45f8e-ff23-4dd9-b09d-3eefb2bdb3e4','歸自漕司試院到桐廬晚偶成','杜範','宋','宋诗','song-poetry','','[]','歸棹便風泝古流，一杯獨酌興悠悠。',64,'全唐诗/poet.song.193000.json','["歸棹便風泝古流，一杯獨酌興悠悠。", "夕陽蘸水金窩沸，暮靄籠山紫幕浮。", "牧笛村村分路入，漁帆浦浦带煙收。", "丹青此處難爲手，更有羈情不奈秋。"]'),
('d575379d-1a26-4da5-b50f-ee85aebd2c04','再依韻復足五十六字以見一時無聊之態非詩也','杜範','宋','宋诗','song-poetry','','[]','人間總是一虛空，過眼流光過耳風。',64,'全唐诗/poet.song.193000.json','["人間總是一虛空，過眼流光過耳風。", "方見露芽牆下茁，又嗟霜葉嶺頭紅。", "身來作吏雙溪上，誰使衝寒一寺中。", "急雪隨風穿瓦過，强呵凍手作詩窮。"]'),
('a7cf7e9e-acb9-488f-a2b2-57c6440fd852','十二月初六日出郊途中值雪偶成小律詩','杜範','宋','宋诗','song-poetry','','[]','宦塵役役走長塗，歲晚離家只自吁。',64,'全唐诗/poet.song.193000.json','["宦塵役役走長塗，歲晚離家只自吁。", "風入破輿寒徹骨，雪穿疎幌亂沾鬚。", "橫陳瑞色今如許，定擬豐年可大書。", "州縣徒勞何敢憚，萬家溫飽即吾廬。"]'),
('40b1548b-204d-4c19-b6cc-c51efe153a1d','恭謝侍讀仁皇訓典徹章御賜杜工部紫宸殿詩退朝口號并鞍馬香茶  其一','杜範','宋','宋诗','song-poetry','','[]','於赫仁皇訓典垂，寬慈實德太平基。',64,'全唐诗/poet.song.193000.json','["於赫仁皇訓典垂，寬慈實德太平基。", "鴻圖植遠文孫紹，燕翼謀深烈祖貽。", "寶曆初更思善治，瑶編久閲撫良規。", "平平王道今猶昔，海宇雍熙庶可期。"]'),
('13cd5c64-f899-41d8-876b-2c84102f4e1b','恭謝侍讀仁皇訓典徹章御賜杜工部紫宸殿詩退朝口號并鞍馬香茶  其二','杜範','宋','宋诗','song-poetry','','[]','丹地從容接細氈，豈徒口耳漫周旋。',64,'全唐诗/poet.song.193000.json','["丹地從容接細氈，豈徒口耳漫周旋。", "帝王家法由心法，典策言傳以道傳。", "章徹誦筵天意悅，恩隆賜典露華鮮。", "禮文稽古皆成憲，主德由斯志罔愆。"]'),
('800ad548-5391-4ce2-9c08-66761fb2df7e','恭謝侍讀仁皇訓典徹章御賜杜工部紫宸殿詩退朝口號并鞍馬香茶  其三','杜範','宋','宋诗','song-poetry','','[]','微臣何幸厠經帷，寵渥便蕃亦例施。',64,'全唐诗/poet.song.193000.json','["微臣何幸厠經帷，寵渥便蕃亦例施。", "鸞鳳驚飛高晉帖，夔龍會送借唐詩。", "靈蕪甘露排憂困，駿馬雕鞍念老羸。", "自愧無功難稱塞，孤臣耿耿只天知。"]'),
('8c119504-37ca-48a3-9091-d8975c900982','得雪稱賀馬上得五十六字','杜範','宋','宋诗','song-poetry','','[]','昨夜同雲猶未合，曉來一色變山河。',64,'全唐诗/poet.song.193000.json','["昨夜同雲猶未合，曉來一色變山河。", "料應天上梅花早，吹落人間柳絮多。", "酒興自憐今老矣，詩腸無奈此情何。", "銀杯逐馬天階路，何似寒江伴釣蓑。"]'),
('90ad9526-5648-4b29-a8d5-155321f30dfd','窗前竹','杜範','宋','宋诗','song-poetry','','[]','拔地停空翠削成，與凡草木不同榮。',64,'全唐诗/poet.song.193000.json','["拔地停空翠削成，與凡草木不同榮。", "無心到彼難教曲，有節防身只自清。", "本是孤根穿草壤，誰令弱杪上雲程。", "礙簷敲瓦宜芟去，好伴寒松澗壑聲。"]'),
('53263477-c9cd-47fb-87d3-cec5b1c68b5e','聞喜宴和御詩','杜範','宋','宋诗','song-poetry','','[]','清朝策士屬新元，四海英髦意氣軒。',64,'全唐诗/poet.song.193000.json','["清朝策士屬新元，四海英髦意氣軒。", "自是冕旒崇直道，亦令韋布效忠言。", "鹿苹初洽君恩重，鳳藻俄頒帝語溫。", "此日微臣陪鎬宴，更慙蘭省濫搜掄。"]'),
('90ab5e9f-2939-43d9-bf98-5f50a8f9dd01','舟中偶成小詩','杜範','宋','宋诗','song-poetry','','[]','泛溪深處暮山晴，乍脫塵埃耳目醒。',64,'全唐诗/poet.song.193000.json','["泛溪深處暮山晴，乍脫塵埃耳目醒。", "水面浮天相與碧，波心浸月兩爭明。", "淺流礙石灘灘急，曲岸鋪沙渚渚清。", "人靜夜闌舟未艤，微吟顧影不勝情。"]'),
('48014093-fe33-4fb6-8868-0aa3a49782fe','和楊兄兩詩  其一','杜範','宋','宋诗','song-poetry','','[]','魯教寂寥鄒辨已，異端塞路日殷繁。',64,'全唐诗/poet.song.193000.json','["魯教寂寥鄒辨已，異端塞路日殷繁。", "寶絲遠緝千年緒，古鑑新磨一世昏。", "正道以身爲屏翰，真儒於此見淵源。", "緘來遺像知君意，百世師模儼若存。"]'),
('fb0fdafb-a116-4ecd-a2fd-278a034fc738','和楊兄兩詩  其二','杜範','宋','宋诗','song-poetry','','[]','望斷家山兩地懸，白雲何處涕潸然。',64,'全唐诗/poet.song.193000.json','["望斷家山兩地懸，白雲何處涕潸然。", "吏塵歲月知無幾，宦海風濤幸有邊。", "已是雪霜催歲晚，又還花柳放春妍。", "起予妙語令深省，碧眼相看話百年。"]'),
('5887957b-ad1c-46a8-a236-206f3262841e','準齋誨人亹亹不倦某每侍几席灑然若執熱之濯清風一日語及唱和新篇繼復緘示聯章巨軸皆相與切磋之意某輒忘其荒陋次韻二章借以求教不敢言詩也幸赦不敏而鎸誨之  其一','杜範','宋','宋诗','song-poetry','','[]','著身閙市厥惟艱，渺渺狂瀾蕩不還。',64,'全唐诗/poet.song.193000.json','["著身閙市厥惟艱，渺渺狂瀾蕩不還。", "心莫轉移真匪石，德常安重有如山。", "談經不踵諸儒後，辨理尤嚴一字間。", "傾耳名言深猛省，半生日月總成閑。"]'),
('420323ec-7926-4195-8438-799430179f22','準齋誨人亹亹不倦某每侍几席灑然若執熱之濯清風一日語及唱和新篇繼復緘示聯章巨軸皆相與切磋之意某輒忘其荒陋次韻二章借以求教不敢言詩也幸赦不敏而鎸誨之  其二','杜範','宋','宋诗','song-poetry','','[]','倦游愈覺世途艱，遠矣淳風未易還。',64,'全唐诗/poet.song.193000.json','["倦游愈覺世途艱，遠矣淳風未易還。", "車去出門多異轍，塵來瞇目失前山。", "差殊只在毫釐際，迷復都來反覆間。", "珍重先生相指似，忙中自有本來閑。"]'),
('0e115ed4-bb8b-4a2d-8da7-3e7858c8063b','伏蒙賜和復用韻二章拜呈可謂出醜衒媸惟自敘鄙懷併以見區區敬慕之意姑惟教之是所願也  其一','杜範','宋','宋诗','song-poetry','','[]','道在行藏自古艱，爲貧偶出未能還。',64,'全唐诗/poet.song.193000.json','["道在行藏自古艱，爲貧偶出未能還。", "一從舉手遮西日，已恐移文在北山。", "身入微官韁鎖裏，心慚大隠市朝間。", "浮雲富貴非吾事，便有功名亦等閑。"]'),
('888401db-e337-4958-8177-4ce0a4a3487f','伏蒙賜和復用韻二章拜呈可謂出醜衒媸惟自敘鄙懷併以見區區敬慕之意姑惟教之是所願也  其二','杜範','宋','宋诗','song-poetry','','[]','學道辛勤歷萬艱，精神見性本無還。',64,'全唐诗/poet.song.193000.json','["學道辛勤歷萬艱，精神見性本無還。", "齊眉自可供瓢樂，携手何須去鹿山。", "謂介謂通非所在，不夷不惠處其間。", "自憐塵俗心猶在，即席摳衣願少閑。"]'),
('d7829b4d-1377-4ec2-b5b6-fad61a40aa6d','和花翁盆梅','杜範','宋','宋诗','song-poetry','','[]','絕澗移來近市園，又還移入賣花盆。',64,'全唐诗/poet.song.193000.json','["絕澗移來近市園，又還移入賣花盆。", "體蟠一簇皆心匠，膚裂千梢尚手痕。", "試問低回隨俗態，何如峭直抱孤根。", "歲寒風節應無恙，魯兀須知自有尊。"]'),
('256470ae-4ff3-433f-8289-ef0caee2814d','和花翁自詠','杜範','宋','宋诗','song-poetry','','[]','愚拙天真未易全，如翁自許豈其然。',64,'全唐诗/poet.song.193000.json','["愚拙天真未易全，如翁自許豈其然。", "剩將詩句酬花債，只把春衣辦酒錢。", "僅六尺牀皆樂地，方千里旱自豐年。", "瞿曇老子都曾學，曾學爲儒也學仙。"]'),
('06e3c530-ea58-496d-b52f-6d4b91246a75','和貴方韻','杜範','宋','宋诗','song-poetry','','[]','萬物由來備一身，要教純熟在持循。',64,'全唐诗/poet.song.193000.json','["萬物由來備一身，要教純熟在持循。", "莫嫌惡濁浮埃界，自做分明實地人。", "培養確知心是聖，工夫豈費筆如神。", "羨君精進追前哲，愧我衰頹落世塵。"]'),
('31b95c00-dc96-4fbf-aee6-8727e3d0670c','借韻呈寬堂','杜範','宋','宋诗','song-poetry','','[]','坦然寬德是居身，又有疲甿要拊循。',64,'全唐诗/poet.song.193000.json','["坦然寬德是居身，又有疲甿要拊循。", "鏡浄不過方寸地，海涵何止百千人。", "呻吟望賜多溝壑，晚閃爲霖幾怪神。", "膏澤未能周海宇，祝公先靜一州塵。"]'),
('17f0e38a-d8fe-4b7e-93d7-e6dd0cfadd40','次花翁冬日三詩  其一','杜範','宋','宋诗','song-poetry','','[]','料理新陽在此朝，休文但覺带寬腰。',64,'全唐诗/poet.song.193000.json','["料理新陽在此朝，休文但覺带寬腰。", "懶將漫刺巡門到，病怕時人舉酒邀。", "强裹青衫空自累，滿簪白髮不相饒。", "冥心久矣隨天付，九轉還丹不用燒。"]'),
('0244772d-af29-4c62-9f90-4246c0d442a9','次花翁冬日三詩  其二','杜範','宋','宋诗','song-poetry','','[]','人心天理兩相關，無奈花翁盡日閑。',64,'全唐诗/poet.song.193000.json','["人心天理兩相關，無奈花翁盡日閑。", "麗服靚粧紛拜節，弊衣短策自怡顔。", "已聞瞥爾尋幽去，又見陶然向市還。", "住世世塵塵不染，梅花好處即孤山。"]'),
('d89c19c5-25da-4b53-b174-3d39b419941d','次花翁冬日三詩  其三','杜範','宋','宋诗','song-poetry','','[]','翛然僧舍一柴扉，淡泊如君眼底稀。',64,'全唐诗/poet.song.193000.json','["翛然僧舍一柴扉，淡泊如君眼底稀。", "山澤肯爲仙骨瘦，襟懷自得遯身肥。", "有詩盈帙遮空橐，無酒留賓辦典衣。", "一棹稽山風雪裏，便應興盡雪中歸。"]'),
('fb9d5ad0-c464-4a96-8f2c-e2381fcc7a93','次花翁喜雪快晴韻','杜範','宋','宋诗','song-poetry','','[]','何人急急走靈符，扶醒摐摐十萬夫。',64,'全唐诗/poet.song.193000.json','["何人急急走靈符，扶醒摐摐十萬夫。", "隘巷未收穿履迹，短簷已倚曬書儒。", "日開雪色如翻手，景屬詩家費撚鬚。", "起望四山新入畫，翠屏半是粉成圖。"]'),
('e93ef089-ccbd-4e9a-83e2-c759680878fd','次花翁第二雪','杜範','宋','宋诗','song-poetry','','[]','創見飛瓊粲晚華，已聞得句壓劉叉。',64,'全唐诗/poet.song.193000.json','["創見飛瓊粲晚華，已聞得句壓劉叉。", "亂隨風勢斜穿戶，誰在雲端巧雨花。", "惱殺饑烏尋屋角，寒驚宿雁失汀沙。", "此時清絕難酬賞，羔酒誰言勝鳳茶。"]'),
('de69db90-f68d-4bf8-b8a5-4a4f00e26a5a','次花翁第三雪','杜範','宋','宋诗','song-poetry','','[]','擁衾無事可相干，急報飛瓊急起看。',64,'全唐诗/poet.song.193000.json','["擁衾無事可相干，急報飛瓊急起看。", "推戶已成千頃白，倚欄未覺十分寒。", "三逢瑞景開心目，幾費詩翁琢腎肝。", "妙句鼎來方對客，共吟驚喜欲忘餐。"]'),
('7ab02ba7-90d0-48b4-b4eb-22902861f136','次花翁自笑韻','杜範','宋','宋诗','song-poetry','','[]','村翁活計謝田莊，肯與時人較短長。',64,'全唐诗/poet.song.193000.json','["村翁活計謝田莊，肯與時人較短長。", "餘事詩篇陵鮑謝，太平胸次到黄唐。", "以通爲隠渾無礙，有樂償貧似略當。", "自笑此生成鶻突，誰知鶻突正難量。"]'),
('76c1d1b5-b8d7-4d98-9f4e-4b57ff240de9','次趙貴方九里松獨行韻','杜範','宋','宋诗','song-poetry','','[]','道機已熟絕防閑，縱步來尋興裏山。',64,'全唐诗/poet.song.193000.json','["道機已熟絕防閑，縱步來尋興裏山。", "殘雪點衣消酒醉，晚風吹鬢带詩還。", "妙年羨子歡悰足，走宦愁予樂事慳。", "安得相從塵網外，快將如意碎青珊。"]'),
('ff5b2547-bdf9-4897-9fdb-53d8ff9fc3ba','羅年能赴興國前詩未作嘗於醉中謾成亦併達之','杜範','宋','宋诗','song-poetry','','[]','一笑重逢二十年，自憐鏡影已華顛。',64,'全唐诗/poet.song.193000.json','["一笑重逢二十年，自憐鏡影已華顛。", "謾言世上誰知我，落在人間恐愧天。", "理到平時無一事，行須實處著千鞭。", "但教千里民安樂，莫使虛名爲世傳。"]'),
('9d4a714f-3e84-4df3-9a4e-0b37e209968d','又送湯國正五十六字','杜範','宋','宋诗','song-poetry','','[]','一尊濁酒送君行，慘澹江雲似我情。',64,'全唐诗/poet.song.193000.json','["一尊濁酒送君行，慘澹江雲似我情。", "已是園林堆落葉，更添風雨掃殘英。", "直存吾道曾何病，公在人心爲不平。", "我久念歸歸未得，羨君趲得去帆輕。"]'),
('2e06ff9b-5fb3-4eb6-9ab9-7096ceb1213f','南鄉舟中偶成','杜範','宋','宋诗','song-poetry','','[]','日斜遠浦閟朱光，煙抹前山濕翠粧。',64,'全唐诗/poet.song.193000.json','["日斜遠浦閟朱光，煙抹前山濕翠粧。", "自有著身丘壑分，故應遣我水雲鄉。", "便於世上誇鍾鼎，何似田間飽稻粱。", "手把黄花相問訊，秋風不改舊時香。"]'),
('2bb3955f-c8ad-4b99-a580-2d352d62bafc','和耕甫弟梅','杜範','宋','宋诗','song-poetry','','[]','數點冰葩與雪宜，有人著眼水邊籬。',64,'全唐诗/poet.song.193000.json','["數點冰葩與雪宜，有人著眼水邊籬。", "從渠疎影初傳句，自此清吟未有詩。", "曾到孤山飛鶴處，恰思偃樹跨鯨時。", "李園莫負春風約，應有當年未折枝。"]'),
('b17a111e-a556-4c72-831e-08fcadf07df8','冬至展墓偶成','杜範','宋','宋诗','song-poetry','','[]','至日衝寒掃墓墟，凄然一拜一欷歔。',64,'全唐诗/poet.song.193000.json','["至日衝寒掃墓墟，凄然一拜一欷歔。", "蓼莪恨與雲無際，常棣愁催雪滿裾。", "誤落世塵驚日月，謾牽吏鞅廢詩書。", "回頭更看諸兒姪，門戶支撐正要渠。"]'),
('4500061b-b13d-4a41-b4fd-9239bf300afc','鄭寧夫携詩什訪余併有贈篇聞其浙右之行詩以送','杜範','宋','宋诗','song-poetry','','[]','何人剝啄扣雲關，袖有新詩數百篇。',64,'全唐诗/poet.song.193000.json','["何人剝啄扣雲關，袖有新詩數百篇。", "宮徵自調相和應，珠璣不揀盡光圓。", "昌黎薦士慙無路，東野盤空枉笑天。", "聞道二親猶未葬，知誰著眼爲渠憐。"]'),
('91136d5d-3793-4676-b47e-37de07572f7d','承見再和用韻','杜範','宋','宋诗','song-poetry','','[]','簇簇枝頭綴淺黄，鼻通四遠熟留藏。',64,'全唐诗/poet.song.193000.json','["簇簇枝頭綴淺黄，鼻通四遠熟留藏。", "秋於對樹疑添色，雨不多時怕減香。", "花事索人非易管，詩情得酒爲新嘗。", "叢芳德色驚人句，影下重吟駐夕陽。"]'),
('1b99205c-6788-475b-91e8-b729e46cf6b3','挽曹處士二首  其一','杜範','宋','宋诗','song-poetry','','[]','年纔四十未云遲，勇謝文場意已奇。',64,'全唐诗/poet.song.193000.json','["年纔四十未云遲，勇謝文場意已奇。", "獨抱古心欣有得，肯同時好浪相追。", "迴神自是平生學，徹底還看處死時。", "援筆大書真力士，紛紛醉夢若纏悲。"]'),
('620f1d8c-bcf6-4dc3-8c91-e123fde569db','挽曹處士二首  其二','杜範','宋','宋诗','song-poetry','','[]','持身非介亦非通，閑處工夫不墮空。',64,'全唐诗/poet.song.193000.json','["持身非介亦非通，閑處工夫不墮空。", "石室隠居雖我獨，鳳岡文社與人同。", "道鎸一族多名士，惠浹千家有後功。", "潜德自昭何待發，矧茲大筆詔無窮。"]'),
('ec1f4428-31a8-451d-a3ac-fe13e1557104','徐倅尊人挽詩二首  其一','杜範','宋','宋诗','song-poetry','','[]','教子成名豈偶然，存心積善契蒼天。',64,'全唐诗/poet.song.193000.json','["教子成名豈偶然，存心積善契蒼天。", "獨工學問馳清譽，旁習陰陽得異傳。", "煞有哀榮身後事，不差生死夢中言。", "欲占厚德看銘誌，七十之期過一年。"]'),
('877220ea-6d78-4f60-8322-42306bce5ef6','徐倅尊人挽詩二首  其二','杜範','宋','宋诗','song-poetry','','[]','論子論交事契深，同年同里又同心。',64,'全唐诗/poet.song.193000.json','["論子論交事契深，同年同里又同心。", "登堂未展龐公拜，夢奠俄驚尼父吟。", "自古陰功天所予，如公遐福世同歆。", "老成漸漸凋零盡，空有潸然淚滿襟。"]'),
('21cf816c-44dd-41b3-b7eb-9923e421c845','丘知府挽詩','杜範','宋','宋诗','song-poetry','','[]','弟兄鼎譽人爭羨，富貴隨時報未均。',64,'全唐诗/poet.song.193000.json','["弟兄鼎譽人爭羨，富貴隨時報未均。", "領閣清班非不遇，持麾重選遽成塵。", "世誇人物今何在，志在詩書竟莫伸。", "笑語詼諧猶在耳，忽聞遠訃恐非真。"]'),
('c5144463-c36a-497d-ac31-d8c59408d103','挽陳將仕','杜範','宋','宋诗','song-poetry','','[]','事到蓋棺方始定，言于陋巷乃爲公。',64,'全唐诗/poet.song.193000.json','["事到蓋棺方始定，言于陋巷乃爲公。", "試看傾郭盈襟淚，盡是忘餐振廩功。", "榮貴但知崇己欲，文章未必濟民窮。", "如君厚積人誰忌，惟恐君家積未豐。"]'),
('16396e2b-15e6-4923-993a-d1bdc4a9f286','挽黄脩職','杜範','宋','宋诗','song-poetry','','[]','宰士當年棣萼情，世科心許白頭登。',64,'全唐诗/poet.song.193000.json','["宰士當年棣萼情，世科心許白頭登。", "詩書早已傳家學，場屋誰知負夜燈。", "老矣尚餘英氣在，嗟哉獨慕善人稱。", "一經分付曾何憾，看取于門自此興。"]'),
('a936082e-722f-4892-a360-bd3120cdad72','挽李處士','杜範','宋','宋诗','song-poetry','','[]','确犖羣山兀海隅，芬川蔚有吉人居。',64,'全唐诗/poet.song.193000.json','["确犖羣山兀海隅，芬川蔚有吉人居。", "施仁一念周鄉井，稱善同聲溢里閭。", "教子垂芳心有待，榮親養老意何如。", "貤恩漫爾撐門戶，肯負當年一束書。"]'),
('f0dfc35f-3e48-4ebe-ae3d-b43accadad6d','挽趙漕閤中','杜範','宋','宋诗','song-poetry','','[]','丘公四海大名垂，有女來嬪閥閲宜。',64,'全唐诗/poet.song.193000.json','["丘公四海大名垂，有女來嬪閥閲宜。", "蘋藻自供寒女事，琴書未許世人知。", "舟移夜壑方遺恨，劍合平津自有時。", "膝上一經勳已策，吁嗟不賦板輿詞。"]'),
('18fcb794-3cfc-4399-ace3-d93e4e7dce49','挽□□','杜範','宋','宋诗','song-poetry','','[]','韜光自古常難見，友道于今幸可論。',64,'全唐诗/poet.song.193000.json','["韜光自古常難見，友道于今幸可論。", "勳業但看江左相，才名已識下邽門。", "壯哉蘭若當時志，已矣雲山此日原。", "到底百年同一夢，山林鐘鼎尚何言。"]'),
('e1fd491f-2e9f-4cd0-8337-e238798365a3','挽翟親','杜範','宋','宋诗','song-poetry','','[]','時運遭逢亦偶然，著鞭莫訝祖生先。',64,'全唐诗/poet.song.193000.json','["時運遭逢亦偶然，著鞭莫訝祖生先。", "閉門終負三冬用，脂篋徒誇十部賢。", "玉樹幸能光舊德，爵羅寧復歎當年。", "生平未快荆州願，有淚空令落九泉。"]'),
('7d564f26-fb93-4761-b145-cb2efeebf173','酥溪寺舍窗前有黄金間璧玉竹可愛謾作二十字不許撞題','杜範','宋','宋诗','song-poetry','','[]','中土太淡素，東皇染半節。',24,'全唐诗/poet.song.193000.json','["中土太淡素，東皇染半節。", "此君已不羣，此種更奇絕。"]'),
