('b861cef2-7630-4fb4-8a22-be16730d7a96','寄題蘆洲','杜範','宋','宋诗','song-poetry','','[]','幽人作計築幽居，傍水爲亭手植蘆。',32,'全唐诗/poet.song.193000.json','["幽人作計築幽居，傍水爲亭手植蘆。", "何愛世間閑草木，只緣胸次有江湖。"]'),
('3217bbf8-2e5e-4537-8bbb-212cf3a887be','貽富室翁','杜範','宋','宋诗','song-poetry','','[]','葱療丹田麥療饑，葱羹麥飯兩相宜。',32,'全唐诗/poet.song.193000.json','["葱療丹田麥療饑，葱羹麥飯兩相宜。", "請君試上城頭望，多少人家午未炊。"]'),
('c3dc87b1-dbad-4b5e-af66-3146313a271f','仙山知寺志剛示余以浸碧唱和詩漫繼其韻','杜範','宋','宋诗','song-poetry','','[]','窮年奔走繚鄉隅，暫此憑欄意已殊。',64,'全唐诗/poet.song.193000.json','["窮年奔走繚鄉隅，暫此憑欄意已殊。", "一水光明平處現，四山容色淡中鋪。", "莫羞塵鬢臨冰鑑，自有靈原照玉壺。", "浸碧主人應領會，試言此碧有耶無。"]'),
('d37f9e8c-da36-450d-9e24-0b118c187a2f','林倅到迓之途中小詩','杜範','宋','宋诗','song-poetry','','[]','簡書奔走日衝衝，偶此郊行興易濃。',64,'全唐诗/poet.song.193000.json','["簡書奔走日衝衝，偶此郊行興易濃。", "雨意醖成春野意，雲容點就曉山容。", "繭絲貯色桑條上，餠餌吹香麥隴中。", "忽憶故園歸去好，雲山知隔幾千重。"]'),
('6449ed09-1c85-4564-a20e-63e1fcc51ffd','和林簿二詩  其一','杜範','宋','宋诗','song-poetry','','[]','憂喜從來巧聚門，刖人有足未爲尊。',64,'全唐诗/poet.song.193000.json','["憂喜從來巧聚門，刖人有足未爲尊。", "人生何用家萬石，世事還輸酒一尊。", "荒徑賦歸人已遠，急流勇退意猶存。", "功名千古成何事，眼底榮枯不足論。"]'),
('9d85acf6-f784-456a-8f00-6b1773330a5c','和林簿二詩  其二','杜範','宋','宋诗','song-poetry','','[]','宦途元自險於山，我輩孤寒分外難。',64,'全唐诗/poet.song.193000.json','["宦途元自險於山，我輩孤寒分外難。", "蕭寺羨君成勝概，新詩爲我解愁端。", "自歎落落無三語，底事區區爲一官。", "初夏北窗新枕簟，碧梧晝影正清團。"]'),
('1f3c7e65-4cc1-475c-844b-829ff39c9fe9','大雨喜成小詩呈百里','杜範','宋','宋诗','song-poetry','','[]','顒顒萬目望穹蒼，連日雷車走阿香。',64,'全唐诗/poet.song.193000.json','["顒顒萬目望穹蒼，連日雷車走阿香。", "不用甕中留蜥蜴，已聞野外舞商羊。", "霶𩃱施澤盈千澮，䆉稏收功可萬箱。", "令尹愛民天所相，三年境內樂穰穰。"]'),
('e6519aeb-99f0-4fed-a955-956c75554123','空明洞','杜範','宋','宋诗','song-poetry','','[]','莫訝青山小，山因洞得名。',24,'全唐诗/poet.song.193000.json','["莫訝青山小，山因洞得名。", "仙人騎鶴去，留蹟在空明。"]'),
('93bfa786-2ea1-40d0-ad34-49e46451551b','玉壺即事','杜範','宋','宋诗','song-poetry','','[]','雨過條風著柳芽，淡黄淺綠嫩如花。',64,'全唐诗/poet.song.193000.json','["雨過條風著柳芽，淡黄淺綠嫩如花。", "陂湖漾漾初侵路，蜂燕紛紛各理家。", "带郭園林仙苑近，送春船舫繡簾遮。", "芸窗倦倚何山翠，暖靄輕籠日脚斜。"]'),
('0f98b849-48e2-44de-9d90-3d3509615bd6','天柱峰','杜範','宋','宋诗','song-poetry','','[]','探幽不知疲，前賞方未極。',252,'全唐诗/poet.song.193000.json','["探幽不知疲，前賞方未極。", "晨行越高嶺，拔地見峭石。", "有如萬菡萏，玲瓏倚秋碧。", "東西忽異狀，顧步忘所歷。", "一峰柱中天，壁立千仞直。", "旁無寸土勢，始覺造化力。", "凜凜蒼鐵姿，漠漠太古色。", "俯疑霹靂怒，仰視元氣黑。", "溟波齧南維，在昔因盪激。", "伊誰拔山來，作此顛倒側。", "諸峰左右輳，參差列矛戟。", "或如削層霞，薰蒸半天赤。", "或如簸大旗，千騎皆辟易。", "或穎如書空，或攫如戲翼。", "或如龍夭矯，兩石陷其脊。", "噀雨空洞中，幽響日夜滴。", "捫蘿展奇眺，百態墮胸臆。", "眼光亂崖竅，日氣光映射。", "似聞多靈秘，路絕天所惜。", "側身下篁篠，倦坐屢脇息。", "沈思融結初，令人嘆開闢。"]'),
('3ee39b97-0818-443c-a36f-40405f1f97cb','句','杜範兄','宋','宋诗','song-poetry','','[]','鶑鳴求友聲。',6,'全唐诗/poet.song.193000.json','["鶑鳴求友聲。"]'),
('f21b5f1b-e363-4da4-bd05-400fe5189027','李養源自號蒙泉求詩于東平包某作此以贈之','包恢','宋','宋诗','song-poetry','','[]','水象童蒙，以出伊始。',240,'全唐诗/poet.song.193000.json','["水象童蒙，以出伊始。", "泉乃白水，出自艮止。", "天一初生，純一清明。", "厥初始達，猶元而亨。", "當其蒙稚，涓涓猶細。", "及其漸進，混混未止。", "如玉與珠，不曰白乎。", "如冰與雪，湛不可污。", "反求諸己，心正如是。", "有生之初，純白純懿。", "養之於蒙，作聖之功。", "大人不失，與赤子同。", "聖如夫子，皜莫尚已。", "湼而不緇，洞徹表裏。", "溥博淵泉，浩浩淵淵。", "皓如銀河，月流星連。", "仰觀先聖，本同一性。", "自始失養，遂終失正。", "氣或雜之，內欲蔽伊。", "官或不思，外引遠而。", "蒙反成失，白反變黑。", "黑水西流，清渭南隔。", "君在家庭，習若少成。", "異彼污世，同流濁涇。"]'),
('17badfc6-2f5e-4bfd-b271-05c928ff2973','臨江閤皂李仲章以省軒求詩','包恢','宋','宋诗','song-poetry','','[]','心之精明，不遠伊邇。',240,'全唐诗/poet.song.193000.json','["心之精明，不遠伊邇。", "胸中若正，瞭焉眸子。", "舉目有證，莫切於視。", "孰名曰省，少目取義。", "目當少時，湛湛精睟。", "其光神全，其見專致。", "老目爲耆，則與少異。", "非徒以目，而分老稚。", "惟目如少，有可取譬。", "實省在心，省當如是。", "如開雙明，洞見萬類。", "心難常存，省不可替。", "心難常覺，省不可離。", "心本善者，孰非純懿。", "心不善者，孰非私利。", "省與不省，善惡關繫。", "省者如醒，不省如醉。", "省者如寢，不省如寐。", "省者如活，不省如斃。", "果能自省，卓然奮勵。", "暗室不欺，屋漏不愧。", "如目萬象，無有掩蔽。", "一不自省，冥然罔記。", "外物交引，內無紛熾。"]'),
('f7e3d7d5-d7fd-46ed-8acf-38f37f0b5421','贈饒仲信靜鏡','包恢','宋','宋诗','song-poetry','','[]','乾不一動，靜專動直。',210,'全唐诗/poet.song.193000.json','["乾不一動，靜專動直。", "坤不一靜，靜翕動闢。", "艮不一止，動靜以時。", "本體如是，偏主則非。", "惟學初機，貴以靜入。", "以至終養，貴以靜習。", "本體既然，動靜一如。", "乾坤合德，無二無餘。", "心爲天君，尊無倫比。", "聖賢言心，初無論擬。", "心比於鏡，佛說云然。", "鏡雖有光，孰擬心天。", "鏡光則死，心光則活。", "活則不滯，死則不豁。", "佛法寂滅，匪乾匪坤。", "若復本心，非彼能昏。", "人以欲動，非動之性。", "所以貴靜，自動自靜。", "其道光明，無物可並。", "惟省盡倫，是爲全人。", "眼高四海，至此乃真。"]'),
('ae67187e-a148-4fd6-a742-c0d11d54b485','留忠齋山茨','包恢','宋','宋诗','song-poetry','','[]','身何止不獲，其背誰得窺。',240,'全唐诗/poet.song.193000.json','["身何止不獲，其背誰得窺。", "心何存不測，其鄉孰能知。", "身心尚無迹，屋廬更何即。", "變動元不居，問君欲奚適。", "放之彌太虛，宇宙總我廬。", "收之付野草，山茨斂吾居。", "宇宙非窮大，山茨豈云細。", "身心非以形，隨寓靡有異。", "此道淡不厭，淡中味何窮。", "萬物孰能動，真樂此室中。", "或疑天下儒，久遊蓬萊島。", "豈伊素草茅，但以蓋茅好。", "達者舍此誰，若將終身茨。", "仁宅本同歸，問舍非自私。", "宇宙浩如許，藏用如謹獨。", "山固屹不移，茨敝當再覆。", "覆可久自娛，庭草聽自如。", "茅茨或不翦，古聖興不殊。", "樂山見仁人，如茨看榮貴。", "此屋雖似卑，誰識最高致。"]'),
('60085338-f90a-4e43-82fa-3928873c558c','贈寫神丘照堂','包恢','宋','宋诗','song-poetry','','[]','嘗觀孝子圖，畫子事母事。',120,'全唐诗/poet.song.193000.json','["嘗觀孝子圖，畫子事母事。", "聞君畫最工，事母孝亦至。", "人稱汝畫奇，未知事母慈。", "我今爲拈出，欲以勵孝思。", "畫不在丹青，照不在眼睛。", "方寸不可亂，昭昭在心明。", "畫到精一處，人人定相如。", "但疑心本一，奚爲面差殊。", "我心猶赤子，我貌極老衰。", "君雖欲畫我，安能作嬰兒。"]'),
('26a45218-9a86-4054-8571-b5a425fb5c7b','送蒙齋赴召六首  其一','包恢','宋','宋诗','song-poetry','','[]','大鈞正旋轉，坱圠方無垠。',108,'全唐诗/poet.song.193000.json','["大鈞正旋轉，坱圠方無垠。", "乾坤用六子，乃使天下春。", "震子實爲長，龍蟄屈不伸。", "不一動則止，一動化萬新。", "嘉熙再仁孝，斯時召斯人。", "宇宙在乎手，萬化生於身。", "機關一開闔，斬新出精神。", "日月無點翳，太虛絕纖塵。", "毫髮靡遺恨，誰能疵大醇。"]'),
('2ef58ba3-f8a6-49f1-b97a-79ebe0cc15bf','送蒙齋赴召六首  其二','包恢','宋','宋诗','song-poetry','','[]','廣大中精微，如崇下履卑。',72,'全唐诗/poet.song.193000.json','["廣大中精微，如崇下履卑。", "川流本敦化，溥博時出之。", "剛毅發秋凜，寬裕融春熙。", "聰明靡偏照，密察不失時。", "權度心爲甚，聖人良在茲。", "思睿睿作聖，無思無不思。"]'),
('f7bde8bb-4c85-4957-be2f-44b61b07430c','送蒙齋赴召六首  其三','包恢','宋','宋诗','song-poetry','','[]','乾坤常簡易，險阻知最精。',240,'全唐诗/poet.song.193000.json','["乾坤常簡易，險阻知最精。", "堯舜何艱難，難在知人明。", "孔子每所患，因予猶改更。", "險如彼山川，無如世人情。", "明天而昧人，古人所譏評。", "卓哉子陸子，高具雙眼睛。", "氣貌纔一顧，肺肝見如傾。", "或但因傳聞，能見人生平。", "萬象悉呈露，如揭日月行。", "何畏乎功令，堯舜爲法程。", "所惡利口覆，孔子爲權衡。", "欲希象山翁，此目不可盲。", "衆欺恐寡信，多僞難皆誠。", "虛受而實責，無容偏且輕。", "張陳門下客，莫非天下英。", "後至所居國，皆能居公卿。", "濟世才最急，泰道非徒亨。", "下視甕盎內，成雷聚蚊蝱。", "鳥須九霄鵬，魚必東海鯨。", "爲己與爲國，灼知在先生。"]'),
('46c9c9b4-9edf-402d-ab31-6fec310f5e77','送蒙齋赴召六首  其四','包恢','宋','宋诗','song-poetry','','[]','扶顛而持危，在天下大勢。',156,'全唐诗/poet.song.193000.json','["扶顛而持危，在天下大勢。", "撥亂而存亡，在國家大計。", "一司一事間，未足繫興替。", "馬援爲郡守，尚不屑煩細。", "惟大姓黠羌，不容有違戾。", "况爲公與卿，不思大經濟。", "今大姓黠羌，幾倍過漢世。", "中有根木存，猶在加護衛。", "大都如弈棋，敗局如已逝。", "如有一勝著，敗乃以勝繼。", "巽當知衡權，是乃德之制。", "果哉末之難，圓神妙龜筮。", "願言其吉凶，大闢天地閉。"]'),
('4e530759-3a05-4fb0-9d29-08750eeb2f26','送蒙齋赴召六首  其五','包恢','宋','宋诗','song-poetry','','[]','嘗聞魏仲英，謂仕欲行志。',180,'全唐诗/poet.song.193000.json','["嘗聞魏仲英，謂仕欲行志。", "後宮權豪等，損去志乃遂。", "如云皆不可，隠身是爲智。", "此志雖可稱，一節非道備。", "不聞政適人，格心第一義。", "如未可與權，當道豈易致。", "齊王好貨色，孟子不少刺。", "導之百姓同，王道真易易。", "自實學不明，言與實難離。", "何能格一非，適以滋衆僞。", "最是講說多，虛文只成贅。", "經或不如史，禍福可趨避。", "下至不害伯，猶能救時弊。", "此可觀世變，言之橫涕淚。", "道本無不通，君子當不器。"]'),
('c972188c-ada8-4059-aada-a953ecc79b49','送蒙齋赴召六首  其六','包恢','宋','宋诗','song-poetry','','[]','四世凡五公，貴盛古自昔。',156,'全唐诗/poet.song.193000.json','["四世凡五公，貴盛古自昔。", "於我如浮雲，光前在仁宅。", "仰觀我絜齋，江漢濯之白。", "下視世所羨，腰黄眼前赤。", "度越此流輩，人何啻千百。", "希舜鹿野居，介然有如石。", "嘗爲耳目人，天子屢前席。", "義難若是恝，命豈可終逆。", "非如一小官，去就惟我適。", "况當有道時，丘自不與易。", "世方厄三空，實當有長策。", "心肝奉至尊，憂勞敢云斁。", "行矣金玉聲，智勇全趙璧。"]'),
('4854774b-e17a-46d3-8227-21d267b18135','雨後觀新荷','包恢','宋','宋诗','song-poetry','','[]','中夜平旦爾，浄把天宇洗。',120,'全唐诗/poet.song.193000.json','["中夜平旦爾，浄把天宇洗。", "此時氣之清，隠映如有體。", "挹之莫可得，揮之不能靡。", "外不隔毛髮，內透徹心髓。", "輕清孰爲天，天也不離此。", "因行過東湖，荷葉恰新美。", "柔莖柄圓蓋，嫩綠出清泚。", "下承之浮萍，鋪錦雜青紫。", "洒洒無一塵，生意正濟濟。", "欲辯已忘言，無聲臭至矣。"]'),
('459f1ffd-0998-4d97-8023-61d05d6306d3','四明决獄由寧海道中','包恢','宋','宋诗','song-poetry','','[]','山童首少髮，石老脊多骨。',72,'全唐诗/poet.song.193000.json','["山童首少髮，石老脊多骨。", "上猶劍戟關，下沒沙磧窟。", "曾無好步行，常有失足驚。", "前若逢峻拒，後如迫使傾。", "所幸甚艱難，平生備嘗試。", "險阻誰能知，乾坤元簡易。"]'),
('10b9191f-bd86-4a59-9f13-788146a66923','觀泉','包恢','宋','宋诗','song-poetry','','[]','泉動湧聯珠，泉靜湛片玉。',72,'全唐诗/poet.song.193000.json','["泉動湧聯珠，泉靜湛片玉。", "淵源出以時，動靜清可掬。", "憑欄冰雪寒，斂袵毛髮肅。", "內以洗我心，外以刮我目。", "偶離京塵來，對此歌不足。", "詠歸五六人，猶疑自沂浴。"]'),
('86bf3c1e-fa76-4507-a7b5-6ad439f5f880','壽家君克堂先生','包恢','宋','宋诗','song-poetry','','[]','良月四之日，景物何多奇。',288,'全唐诗/poet.song.193000.json','["良月四之日，景物何多奇。", "露洗宇四靜，月抹天一涯。", "景星助月夜，光入清溪湄。", "奎星照江南，人文良在茲。", "昔爲西長庚，夢與斯人期。", "今爲南極老，微雲淡龐眉。", "際此小春日，勝彼芳春時。", "桃梅妙生意，微吐三五枝。", "野垂黄金穟，人飽白玉粢。", "芙容花成城，拔然凌霜姿。", "暮開紅菡萏，朝發白蜀葵。", "菊見正中色，瀟然疎竹籬。", "不共衆芳競，獨與晚歲宜。", "時異物孤特，人生復何疑。", "我翁在物表，清吟徹骨肌。", "不以世間利，容易得涴伊。", "今年七十二，浩然元不衰。", "孤坐小閣上，臺融融熙熙。", "布衾紙帳間，瑩若冰雪姿。", "自從知止後，何思復何爲。", "但願主益聖，比肩皆臯夔。", "東南盛仁氣，不戰屈四夷。", "豐穰歲相似，赤子無啼饑。", "得老太平世，仁壽非吾私。"]'),
('38cdf1cf-fe5f-41c0-9b27-201fc88cc0d4','馬上口占感梅感事二首  其一','包恢','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅兄隨遇處，在水涯山巔。',228,'全唐诗/poet.song.193000.json','["梅兄隨遇處，在水涯山巔。", "或有近行路，不惹人愛憐。", "儼如敬而遠，惟恐迫我前。", "或有近人居，不傍門戶邊。", "仍多向貧家，不爲華屋牽。", "香不祈人聞，芳不取世妍。", "似此性孤潔，秋毫絕縈纏。", "彼有不知者，乃謂花莫先。", "折之貯玉瓶，已是傷其天。", "更大開苑囿，和根以之遷。", "反指榮得地，带露淚自漣。", "浸違山林意，豈其本性然。", "和羹尚不願，其餘安足言。", "但願復反本，同盟松竹堅。", "西湖之孤山，猶嫌朝市喧。", "上對玉輝山，下臨珠媚淵。", "外此唯雪月，往來許周旋。", "三友共一笑，歲寒同百年。", "雖與世落落，自分安其偏。"]'),
('21ed92d4-eae0-4023-ad57-197296f7b0d3','馬上口占感梅感事二首  其二','包恢','宋','宋诗','song-poetry','','[]','巡歷郡邑間，人若未厭棄。',288,'全唐诗/poet.song.193000.json','["巡歷郡邑間，人若未厭棄。", "夾道爭向觀，疑我形孰似。", "得之道聽餘，咸謂物吐氣。", "老姦與宿贓，神奪而心悸。", "預知犯難逃，已多速奔避。", "先嘗受其賕，今皆償之既。", "非懾使者來，安得自知畏。", "予默揆諸心，斯言未深契。", "一切氣不美，先儒說有味。", "彝倫若盡去，太半爲鬼魅。", "禽獸爭食人，殆盈野盈市。", "迹其所作爲，殆惡過異類。", "不潔食不飽，甚焉官與吏。", "慘酷以濟之，甚若豺虎噬。", "豈直如得情，哀矜至流涕。", "刑法用當窮，根本惕若厲。", "豈謂猶有民，能喜使者至。", "或鞠躬焚香，或遠送旗幟。", "望來漳民情，願留泉民意。", "此猶碩果然，不食生可覬。", "惟知有罪者，患不速去離。", "何啻千百輩，施行纔一二。", "自嘆水一杯，孰救炎火熾。", "傷心復傷心，竟夕不能寐。"]'),
('d408adb3-68eb-47d3-83f4-fd71c0b97b2f','餞山泉吳守','包恢','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','泉從九江來，發自廬山趾。',216,'全唐诗/poet.song.193000.json','["泉從九江來，發自廬山趾。", "不啻如渭清，時出到旴水。", "淵淵媚如珠，甘飲足千里。", "何妨遇山下，一時險而止。", "不礙以亨行，果行險自弭。", "真利用禦寇，上下順而理。", "方當執熱中，以濯豁有喜。", "且當正渴時，得飲快如洗。", "旴人望膏潤，戀戀正未已。", "顧如歲大旱，用汝甘霖比。", "不容私一方，宇內並傾企。", "盈科放四海，有本如是耳。", "安得長流旴，混混以終始。", "河南已治平，河內難留矣。", "好將世俗污，盡洗入清泚。", "溥博澤周流，功成大如此。", "却歸山泉間，育德德孰擬。", "作聖以爲期，善養功更偉。"]'),
('ca94f9b3-3d7e-4dfa-aea8-5b96fd515b96','謝朱汀守惠古風','包恢','宋','宋诗','song-poetry','','[]','民何業於鹽，由生在水國。',288,'全唐诗/poet.song.193000.json','["民何業於鹽，由生在水國。", "因之利其利，資生本無責。", "未能損與之，盡絕豈爲得。", "後世與古異，以此命爲脈。", "如寬之一分，不禁之太迫。", "上下亦相安，何至遽相阨。", "柰何籠之盡，一線路亦塞。", "乘以風氣惡，遂至大作慝。", "舟聚至數十，衆聚動數百。", "殺越人於貨，禍烈恣慘刻。", "誰謂在王畿，有此凶焰赫。", "深爲腹心憂，非但股肱厄。", "聖上欲並生，猶未忍誅謫。", "欲如渤海郡，但以安作則。", "中外多賢良，選及僕罔測。", "豈非老不死，可以賊擊賊。", "初非欲勝之，化誘盡籌畫。", "頑冥終不回，不免出兵革。", "猶非殺爲威，止欲就擒獲。", "竟未始血刃，獻囚不獻馘。", "精別分死生，不失我心測。", "或不以事觀，浮言肆虛嚇。", "語穽險且危，聞者轉相惑。", "非望復非才，宜不見浮格。"]'),
('88eed24f-08f8-458c-b82d-77b72914c096','病中答客','包恢','宋','宋诗','song-poetry','','[]','客侈言告予，二月春爛如。',288,'全唐诗/poet.song.193000.json','["客侈言告予，二月春爛如。", "後過前不及，於今正豐腴。", "况復晴暄久，行樂人聯車。", "時鳥啼葫蘆，酤酒醉且呼。", "遊子偕遊女，爭先耀街衢。", "被惱訴無處，半是顛狂徒。", "昔人秉燭遊，過時欲何娛。", "恨公獨抱病，與時不相扶。", "容膝斗大室，呻吟何時蘇。", "奇花將衰謝，綠葉將扶疎。", "聞鳥聲輒善，能似五柳無。", "予謂客所羨，眩於形色歟。", "競千紅萬紫，錦繡不足鋪。", "變千態萬狀，綵繪不可圖。", "無一非形色，乃生理緒餘。", "耳目不能思，心冥獨荒蕪。", "形形色色者，根本何取諸。", "藏用而顯仁，顯微元不殊。", "徒見形色者，不識精在粗。", "抑豈知造物，不知彼在吾。", "中和萬物育，皆備我不誣。", "造物莫窮極，形色纔斯須。", "物既惟我造，何嘗離須臾。", "見即常自見，非二常與俱。"]'),
('ac0f1a0c-a3b0-4c79-948c-5f8e0bda606c','病中口占','包恢','宋','宋诗','song-poetry','','[]','人於不病時，豈知病時惡。',288,'全唐诗/poet.song.193000.json','["人於不病時，豈知病時惡。", "重如加刀鋸，輕亦急束縛。", "寒如大冬冰，熱則盛夏鑠。", "四肢外猶解，五臟內似剝。", "石卧身經難，木瘦氣削弱。", "痛苦千萬端，堅忍力不角。", "貴勢富强身，不能與我博。", "若非禍自求，安受外氣虐。", "一息秋毫間，不來不可度。", "百憂一不興，百念一不作。", "萬事不到胸，萬卷束高閣。", "學在身外者，無一可倚託。", "坎中維寸心，不亂猶獨覺。", "清明尚如在，志氣神自握。", "如圍城未陷，主帥守彌確。", "如敝屋未顛，主翁立尤卓。", "或悠然以遊，何懼以何怍。", "人能處未病，如病乃良藥。", "生本自憂患，死反由安樂。", "恃吾身安强，氣馬恣奔薄。", "精炎火焚林，物溺水赴壑。", "醲醉酒池竭，姣淫欲海涸。", "魄壞魂何存，神去氣宜索。", "盛年已衰翁，槁形止虛殻。"]'),
('39f7db9c-fee1-430d-9d81-1736b8208914','和陳七峰七詩韻  其一','包恢','宋','宋诗','song-poetry','','[]','濁世九黄河，太虛一明鏡。',48,'全唐诗/poet.song.193000.json','["濁世九黄河，太虛一明鏡。", "混混皆隨流，炯炯誰獨醒。", "崛起孤峰高，盡把衆山領。", "根基既超然，培植功且更。"]'),
('fb99ec54-cafe-4b44-b9e6-1af341fabb0d','和陳七峰七詩韻  其二','包恢','宋','宋诗','song-poetry','','[]','乾坤露端倪，宇宙幾奇怪。',48,'全唐诗/poet.song.193000.json','["乾坤露端倪，宇宙幾奇怪。", "萬化俱成章，一視靡有界。", "即此爲真文，於外本無待。", "所願學如何，豈不信茲在。"]'),
('add9bc72-d9d4-4f92-979d-c7c778468418','和陳七峰七詩韻  其三','包恢','宋','宋诗','song-poetry','','[]','洞然一止水，浪靜仍風恬。',48,'全唐诗/poet.song.193000.json','["洞然一止水，浪靜仍風恬。", "心微在精一，動凶由二三。", "根深自生色，形神猶飲酣。", "一毛猶有倫，聲臭無容參。"]'),
('eb77a48d-ee63-4993-9b73-1efa2f6bc0dd','和陳七峰七詩韻  其四','包恢','宋','宋诗','song-poetry','','[]','上達何外暴，真樂非幽園。',48,'全唐诗/poet.song.193000.json','["上達何外暴，真樂非幽園。", "凡有動於境，恐皆離乎天。", "我自淡不厭，彼徒爭相喧。", "峰高果峻極，無論百千年。"]'),
('506b5131-7d78-46a2-953d-34e5591769fe','和陳七峰七詩韻  其五','包恢','宋','宋诗','song-poetry','','[]','百千始一年，漫分三百六。',48,'全唐诗/poet.song.193000.json','["百千始一年，漫分三百六。", "來信非有餘，往屈詎不足。", "形有消猶水，德常久如玉。", "世間無神仙，但戒小結束。"]'),
('ff92a5d4-0fb5-469c-93c3-dababc55db4e','和陳七峰七詩韻  其六','包恢','宋','宋诗','song-poetry','','[]','形相猶吾廬，主者自有執。',48,'全唐诗/poet.song.193000.json','["形相猶吾廬，主者自有執。", "執乃所性存，不計年百十。", "廬則有壞時，似井廢不汲。", "能原始要終，修短非緩急。"]'),
('ec0a0433-7176-4cb6-b68e-3b4f19a528ca','和陳七峰七詩韻  其七','包恢','宋','宋诗','song-poetry','','[]','萬分川流異，一本大化同。',48,'全唐诗/poet.song.193000.json','["萬分川流異，一本大化同。", "小閉即俱塞，大徹何不通。", "大人猶赤子，少成同老翁。", "今古任異世，不息將何窮。"]'),
('25806082-8dda-4ccf-a1bf-9ba5a9de7cb4','和吳伯成七夕韻','包恢','宋','宋诗','song-poetry','','[]','老火不知老，尚欲驕新秋。',144,'全唐诗/poet.song.193000.json','["老火不知老，尚欲驕新秋。", "金稚力未勝，如兒方唧啾。", "稍養浩然氣，終當凌斗牛。", "巧夕乞巧者，稚兒輩可羞。", "老拙眼尚明，却笑羣目幽。", "造物真大巧，容得智力不。", "巧亦不自知，變化神鬼驚。", "夏將烘爐鑄，至秋成金城。", "金城包宇宙，萬寶藏難明。", "今夕且對月，酌酒與子盟。", "仁熟如美種，由我獨善耕。", "金聲而玉振，秋乃集大成。"]'),
('78dbb8ba-a2c3-41af-94c3-6a0b593d2ec5','歌晏恭人平寇偉績','包恢','宋','宋诗','song-poetry','','[]','策勳賞賜轉更强，壯士不知是女郎。',384,'全唐诗/poet.song.193000.json','["策勳賞賜轉更强，壯士不知是女郎。", "嘗聞此語人罕見，婦女誰及如張良。", "有嘗因郡謀亂逆，自將千人乘無防。", "此其代夫有反掌，所尤難者有婦孀。", "或傾家産率部曲，或善騎射多殺傷。", "有如二孀乃能爾，勝幾丈夫陣堂堂。", "誰知慶曆丞相後，有女晏氏生閨房。", "女婦曾氏作內則，中守大節嚴於霜。", "平時如坤自柔靜，一旦遇變何方剛。", "紹定己丑汀寇起，所至殘滅勢孔張。", "愚者束手只待殞，懦者魄喪仆且僵。", "男子紛紛類若是，何望孀有鐵石腸。", "晏氏獨如負將略，通身是膽智滿囊。", "慨然以義誓境內，黄牛山上寨可場。", "其上可屯數萬衆，列爲五寨如五鄉。", "一時郡縣幾千里，已多成墟渺爲荒。", "屹然此寨乃獨立，雖極險阻如康莊。", "龍鬚山頭有草木，草可藥箭木可鎗。", "亟令先賊盡採取，兵器犀利鋒莫當。", "且自捐廩凡數十，半年可足山上糧。", "以是賊雖千萬衆，不能敵我計策長。", "殆似天地自設險，非城非池如金湯。", "殆是女中千人傑，非山非寨人煌煌。", "此功雖大豈望報，恭人之封未足償。"]'),
('6cd3464b-b289-41e5-bf81-1d2de7b0f2b4','天台石橋','包恢','宋','宋诗','song-poetry','','[]','石橋龍行甲台山，吼雷噴雪透玉關。',64,'全唐诗/poet.song.193000.json','["石橋龍行甲台山，吼雷噴雪透玉關。", "石梁擬倫固未易，龍湫埒美猶良艱。", "風神凜凜聳毛骨，如在天外非人間。", "昔聞今見未曾有，遊人何嗟行路難。"]'),
('313430e6-c264-4422-9d8d-202f1f78c2e4','趙宗判請遊巖溪','包恢','宋','宋诗','song-poetry','','[]','三山來由北巖溪，三十里近何崛奇。',408,'全唐诗/poet.song.193000.json','["三山來由北巖溪，三十里近何崛奇。", "地闢天開幾千朞，神藏鬼祕人莫窺。", "竹溪黄溪何派支，太白子厚名始垂。", "未知此溪發其誰，河潢自天磐石資。", "含霜奪日森旌麾，巖電銀海增雙輝。", "出千古秘此一時，潭間歸來爲發揮。", "寶藏驟興福所希，溪宜有靈潜自嗤。", "非公遇我我遇伊，昔無今始有己知，宜爲知己加護持。", "成鼎可絕魅與魑，遊騎可馳驥與騏。", "兩山插天天猶低，如城夾地地莫巇。", "混混中間流天池，往來深藏龍與螭。", "巨石萬狀磊不羈，奇木萬種名莫推。", "始度石梁堂少棲，方見主人心遠而。", "此身恍在何天涯，非人間世如驚疑。", "須臾緩步行委蛇，雙龍之湫氣杳微。", "進前宿雲雲欲迷，疊嶂高張熊虎旗。", "鳬潀石門互變移，翠密玉練冰雪飛，壁立萬仞文公題。", "愈上愈高青雲齊，書堂屹立天然基。", "如有千巖萬壑姿，一覽俱盡無纖遺，主人惠我何多爲。", "時方六月三伏期，但覺清冷生冰肌。", "清境清賞何加茲，更醉似酒醇不醨。", "飽水飽石渾不饑，更飽一德充肝脾。", "大帥如古刺史規，溪變爲好政可追。", "僕如柳子有許疵，溪改爲愚嘗自悲。"]'),
('4cde3d18-e601-424b-81b2-2574fc2969af','蓮花','包恢','宋','宋诗','song-poetry','','[]','暴之烈日無改色，生於濁水不受汙。',64,'全唐诗/poet.song.193000.json','["暴之烈日無改色，生於濁水不受汙。", "疑如嬌媚弱女子，乃似剛正奇丈夫。", "有色無香或無實，三種俱全爲第一。", "實裏中懷獨苦心，富貴花非君子匹。"]'),
('39b80d91-ddce-45cd-85e8-895e381d61d5','溫州雙峰寺','包恢','宋','宋诗','song-poetry','','[]','兩水旁流合，雙峰對立分。',48,'全唐诗/poet.song.193000.json','["兩水旁流合，雙峰對立分。", "未窺龍鼻面，且過雁山門。", "玉練泉流石，天低露濕雲。", "經過隨分好，猶未副前聞。"]'),
('c7d629d2-e352-4995-a85e-fd1ecef61876','和陸伯微韻二首  其一','包恢','宋','宋诗','song-poetry','','[]','百薦鋒難敵，伊誰是特知。',48,'全唐诗/poet.song.193000.json','["百薦鋒難敵，伊誰是特知。", "近嘗繙戇說，久惜負胸奇。", "整頓須教早，招來已恨遲。", "英豪施異說，勳業定相隨。"]'),
('56f29224-97d0-4da9-8bc0-fd5b64e62ceb','和陸伯微韻二首  其二','包恢','宋','宋诗','song-poetry','','[]','我坐深山底，炎涼總不知。',48,'全唐诗/poet.song.193000.json','["我坐深山底，炎涼總不知。", "任他人正閙，嗟世事無奇。", "菽盡歡難遂，芹思獻尚遲。", "薦堂終萬里，還許走相隨。"]'),
('5b7cdd6f-1f05-4097-ad54-5039ec9e1d5f','挽吳準齋','包恢','宋','宋诗','song-poetry','','[]','朝市逃名利，清明照日邊。',48,'全唐诗/poet.song.193000.json','["朝市逃名利，清明照日邊。", "隆冬霜裏柏，盛夏火中蓮。", "純行渾無玷，嘉言賸有傳。", "歸全復何憾，吾黨獨呼天。"]'),
('053685df-7f82-4e22-9a64-cb7dde6edf4e','鴈蕩靈巖','包恢','宋','宋诗','song-poetry','','[]','展旗天柱立，寶印伏獅雄。',48,'全唐诗/poet.song.193000.json','["展旗天柱立，寶印伏獅雄。", "瀑噴千珠碎，窗開四牖空。", "爭奇排怪石，獨秀出孤峰。", "龍鼻泉流出，如何造物工。"]'),
('e25a2d28-d7ee-4842-b54a-aeedc01facf8','過峽山寺','包恢','宋','宋诗','song-poetry','','[]','庾嶺分來峙兩山，夾山成峽水成灣。',64,'全唐诗/poet.song.193000.json','["庾嶺分來峙兩山，夾山成峽水成灣。", "上林下石森雙障，南海西江屹一關。", "水若龍藏涵碧色，山如虎伏出蒼顔。", "人來人往消何許，誰似山長與水閒。"]'),
('7bbb1714-0ac4-4685-9727-042bf9d50f46','江陰風寒地有感','包恢','宋','宋诗','song-poetry','','[]','西浙因曾究竟看，澄江端的是風寒。',64,'全唐诗/poet.song.193000.json','["西浙因曾究竟看，澄江端的是風寒。", "戶門人合爲防密，南北天非立限寬。", "誤認孤軍成僻小，誰思緊處是辛酸。", "願興重鎮加經理，忍見寥寥守備單。"]'),
('4d5bdf0b-1427-4999-8fc4-151f02464d40','同陳守遊碧落洞二首  其一','包恢','宋','宋诗','song-poetry','','[]','攬轡驅馳始得閒，便陪五馬訪名山。',64,'全唐诗/poet.song.193000.json','["攬轡驅馳始得閒，便陪五馬訪名山。", "恍如境出青霄外，真是身遊碧落間。", "地闢天開非假鑿，崖高壁立自成關。", "奇奇怪怪難名狀，獨荷元龍許附攀。"]'),
('e81e09f1-afb7-41c6-8fd8-31a3c63410f4','同陳守遊碧落洞二首  其二','包恢','宋','宋诗','song-poetry','','[]','乳滴珠垂石綴旒，冰清醽綠水鳴球。',64,'全唐诗/poet.song.193000.json','["乳滴珠垂石綴旒，冰清醽綠水鳴球。", "龍宮鳳穴排蒼壁，燕壘蜂房湧碧琉。", "公愛彼山巖石峻，我貪此洞冷泉幽。", "無雙奇觀難窮處，便欲留身就隠休。"]'),
('acf6d692-3960-40dd-b4b2-c522485eb284','和陳翔卿韻','包恢','宋','宋诗','song-poetry','','[]','碧落宜遊遂速奔，千奇萬勝果中存。',64,'全唐诗/poet.song.193000.json','["碧落宜遊遂速奔，千奇萬勝果中存。", "天鍾神秀雙瑶室，地闢高深兩玉門。", "下有紺寒流水徑，上垂遠古斷山痕。", "獨憐地近人何遠，久共沿流探本根。"]'),
('413fe194-f309-4c81-9c45-89a54e2baa15','再和二首  其一','包恢','宋','宋诗','song-poetry','','[]','洞要窮源入莫閒，初頭底事做成山。',64,'全唐诗/poet.song.193000.json','["洞要窮源入莫閒，初頭底事做成山。", "開先水獨爲乾始，判後山方立地間。", "氣濁下流泥作土，滓堅中結石成關。", "奇哉故迹皆堪驗，何日重來更共攀。"]'),
('d8827233-a6ec-4e57-88b2-6625029b25d9','再和二首  其二','包恢','宋','宋诗','song-poetry','','[]','石爲雲蓋上垂旒，水作冰壺一擊球。',64,'全唐诗/poet.song.193000.json','["石爲雲蓋上垂旒，水作冰壺一擊球。", "似筍反生懸碧玉，如簪倒插掛青瑠。", "外猶虎踞風回嘯，內若龍蟠氣轉幽。", "尚想初時開闢意，何時更共爾游休。"]'),
('9709c1bd-dd7f-40ce-b8cc-cc8038e40c85','和戴石屏見寄韻二首  其一','包恢','宋','宋诗','song-poetry','','[]','海邦太守常時有，海上詩翁間世奇。',64,'全唐诗/poet.song.193000.json','["海邦太守常時有，海上詩翁間世奇。", "自賦歸來石屏去，不煩繩削草堂知。", "高情豈爲時情改，浩氣難隨血氣移。", "句老律精何酷似，昔題蜀相孔明祠。"]'),
('2b75208b-d4de-4a3d-b04e-59c5c18bf6e7','和戴石屏見寄韻二首  其二','包恢','宋','宋诗','song-poetry','','[]','草茅恨我非時樣，五馬駑材無寸奇。',64,'全唐诗/poet.song.193000.json','["草茅恨我非時樣，五馬駑材無寸奇。", "千里赤城皆欲殺，一雙青眼獨蒙知。", "每懷設榻迎徐意，尚擬扁舟訪戴時。", "炯炯此心常晤對，思公輒復誦公詩。"]'),
('324f49b7-7107-4211-bc8d-18a1655a04e4','挽陳和仲二首  其一','包恢','宋','宋诗','song-poetry','','[]','至寶幢邊寶器鍾，含光承影狀難窮。',64,'全唐诗/poet.song.193000.json','["至寶幢邊寶器鍾，含光承影狀難窮。", "明明山立千峰表，湛湛鄞清萬派中。", "鍊不回容精匪石，灼無變澤氣如虹。", "誰疑湖海豪猶在，安得樓高更卧龍。"]'),
('e528cbe3-19b2-4d3f-aeaa-3fe53359c452','挽陳和仲二首  其二','包恢','宋','宋诗','song-poetry','','[]','川流近海學易至，源出慈湖派獨清。',64,'全唐诗/poet.song.193000.json','["川流近海學易至，源出慈湖派獨清。", "進佩龍泉秋水洌，退懷驪頷夜珠明。", "介真不以三公易，枉自無容一尺輕。", "年未半生紆遠道，哀哉何限不平鳴。"]'),
('36e8e221-1b6d-4e83-aefa-3ac76144a3c0','寄題武夷橘林小隠','包恢','宋','宋诗','song-poetry','','[]','武夷山下出清泉，觀象宜知果行緣。',64,'全唐诗/poet.song.193000.json','["武夷山下出清泉，觀象宜知果行緣。", "小隠藏修人似玉，大書題品筆如椽。", "峰高屹立天成柱，溪靜光浮月滿船。", "箇是我心真境界，元非六六彼中天。"]'),
('155efdea-56ad-48d7-8269-8d7eff712fd6','送旴江吳守以言歸二首  其一','包恢','宋','宋诗','song-poetry','','[]','圓機珠活走盤中，已試權奇妙變通。',64,'全唐诗/poet.song.193000.json','["圓機珠活走盤中，已試權奇妙變通。", "武庫精嚴鋒莫敵，智囊沉密計難窮。", "先聲已早聞風采，後實如新見事功。", "計日未多功不少，復剛方長轉春風。"]'),
('f5edca98-a3a0-44fa-ac21-78af502af3c4','送旴江吳守以言歸二首  其二','包恢','宋','宋诗','song-poetry','','[]','斬新政令別規模，迎刃恢恢解有餘。',64,'全唐诗/poet.song.193000.json','["斬新政令別規模，迎刃恢恢解有餘。", "去就雖輕心自若，佞賢乍變事如何。", "糴爲民患祈從免，社植根深惡始除。", "似此欲爲尚何限，歸歟千里競攀車。"]'),
('97df2aa3-1054-49e3-9bf1-c39a8dd678af','同李文溪遊通天竅','包恢','宋','宋诗','song-poetry','','[]','石如紅玉間烏金，上與天通直下臨。',64,'全唐诗/poet.song.193000.json','["石如紅玉間烏金，上與天通直下臨。", "中似室廬猶短淺，外多窟宅却幽深。", "公真清獻遊同昔，我匪元公趣異今。", "但幸附名鎸在石，當堅一介不移心。"]'),
('0c87bc80-ca45-4fa9-b2e9-2f0215f99ea3','江心寺','包恢','宋','宋诗','song-poetry','','[]','心無倚着絕沉浮，力破回瀾巋獨留。',64,'全唐诗/poet.song.193000.json','["心無倚着絕沉浮，力破回瀾巋獨留。", "遠過金山推碧玉，屹如砥柱立中流。", "木猶桂在月中植，人似身來鏡裏遊。", "况是清秋方浄練，真成銀漢着孤舟。"]'),
('899255f1-ebc0-4dc6-b077-b8f9202dfe58','謝王洪伯惠酒炭米五首  其一','包恢','宋','宋诗','song-poetry','','[]','君許身比稷，視饑真己如。',24,'全唐诗/poet.song.193000.json','["君許身比稷，視饑真己如。", "免吾學顔帖，乞米李大夫。"]'),
('c6a0dc62-819c-4d6b-8474-d6eddd998f59','謝王洪伯惠酒炭米五首  其二','包恢','宋','宋诗','song-poetry','','[]','飽我德更勤，青州兩從事。',24,'全唐诗/poet.song.193000.json','["飽我德更勤，青州兩從事。", "酣飲愧無言，未嘗識奇字。"]'),
('1d307e2a-83b8-4486-b1c0-f6a2be56d264','謝王洪伯惠酒炭米五首  其三','包恢','宋','宋诗','song-poetry','','[]','杜陵四海志，不忍寒颼颼。',24,'全唐诗/poet.song.193000.json','["杜陵四海志，不忍寒颼颼。", "投我一紅爐，果勝千金裘。"]'),
('c3785569-795c-4a62-8817-1e78aa91fda5','謝王洪伯惠酒炭米五首  其四','包恢','宋','宋诗','song-poetry','','[]','風雪太清白，顧懷似斯人。',24,'全唐诗/poet.song.193000.json','["風雪太清白，顧懷似斯人。", "超然萬松表，一洗肝胆新。"]'),
('8f6dce5f-3a6c-4bad-a0fb-c32662ec2199','謝王洪伯惠酒炭米五首  其五','包恢','宋','宋诗','song-poetry','','[]','昨蒙記雲萍，得得覩台星。',24,'全唐诗/poet.song.193000.json','["昨蒙記雲萍，得得覩台星。", "君宜厚自重，絕似前金陵。"]'),
('11df3b20-5608-4ede-97f7-58864dc81e51','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其一','包恢','宋','宋诗','song-poetry','','[]','非卿橋不立，誰是杜武庫。',24,'全唐诗/poet.song.193000.json','["非卿橋不立，誰是杜武庫。", "下浦未更新，過者幾驚顧。"]'),
('23586a50-0804-4cbf-ab71-ea711285270e','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其二','包恢','宋','宋诗','song-poetry','','[]','月卿派天河，星橋歎誰可。',24,'全唐诗/poet.song.193000.json','["月卿派天河，星橋歎誰可。", "如彼行道人，病責涉在我。"]'),
('38ce316d-29ab-4901-bc3e-776c8c8af1f2','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其三','包恢','宋','宋诗','song-poetry','','[]','邁古大夫名，後成大前造。',24,'全唐诗/poet.song.193000.json','["邁古大夫名，後成大前造。", "千崖秋氣高，落成偕父老。"]'),
('05ab339f-a404-4bd7-94c6-20bdfa7f27d6','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其四','包恢','宋','宋诗','song-poetry','','[]','江湖道四達，坎險橫危機。',24,'全唐诗/poet.song.193000.json','["江湖道四達，坎險橫危機。", "一旦席上遇，惠大政豈非。"]'),
('94fafdbf-9f10-469a-b753-a8a7329d4e9a','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其五','包恢','宋','宋诗','song-poetry','','[]','乾易以知險，履坦期同躋。',24,'全唐诗/poet.song.193000.json','["乾易以知險，履坦期同躋。", "誓彼不復過，一笑駟馬題。"]'),
('666d59e3-f029-4d11-bc3a-0e85fd116666','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其六','包恢','宋','宋诗','song-poetry','','[]','臨淵似平陸，徐行若安土。',24,'全唐诗/poet.song.193000.json','["臨淵似平陸，徐行若安土。", "推此以扶顛，屹然中流柱。"]'),
('68430fc8-5c30-4bdd-a192-cb6038088b7d','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其七','包恢','宋','宋诗','song-poetry','','[]','長纔二百尺，婉若千里隔。',24,'全唐诗/poet.song.193000.json','["長纔二百尺，婉若千里隔。", "天下悅出塗，旁午任行客。"]'),
('e883b6c2-70fa-414a-8e95-dd007014b942','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其八','包恢','宋','宋诗','song-poetry','','[]','規自趙日久，成令方能之。',24,'全唐诗/poet.song.193000.json','["規自趙日久，成令方能之。", "捄溺由己溺，信惟君子知。"]'),
('a7e2e017-fcfa-421d-afd0-1422047113ea','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其九','包恢','宋','宋诗','song-poetry','','[]','指麾談笑間，朗若月出雲。',24,'全唐诗/poet.song.193000.json','["指麾談笑間，朗若月出雲。", "放之準四海，經濟要屬君。"]'),
('80547aef-e29b-4b28-bab2-e92efe21b3e5','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其一○','包恢','宋','宋诗','song-poetry','','[]','成須千年固，鉅石不可摧。',24,'全唐诗/poet.song.193000.json','["成須千年固，鉅石不可摧。", "惟君心如石，迺是爲梁材。"]'),
('92578125-aa10-4c22-a72a-b397c72afc48','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其一一','包恢','宋','宋诗','song-poetry','','[]','盤龍友龍成，山與巖峻峙。',24,'全唐诗/poet.song.193000.json','["盤龍友龍成，山與巖峻峙。", "今如添卧龍，壯觀萃於是。"]'),
('aa555b80-b8eb-425f-affc-a0234c522a88','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其一二','包恢','宋','宋诗','song-poetry','','[]','事難處如易，役大辦若細。',24,'全唐诗/poet.song.193000.json','["事難處如易，役大辦若細。", "才力運有餘，大川更誰濟。"]'),
('bcef2513-1513-4987-a6d6-963ffd37464e','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其一三','包恢','宋','宋诗','song-poetry','','[]','往來欲休息，亦可樂自然。',24,'全唐诗/poet.song.193000.json','["往來欲休息，亦可樂自然。", "上觀雲飛鳥，下看魚泳川。"]'),
('f99b375c-96c3-4c07-a5ad-ef618722b748','酬袁守方秋崖遺寶带橋詩以顧我老非題柱客知君材是濟川功爲韻十四首  其一四','包恢','宋','宋诗','song-poetry','','[]','亭若龍兩翼，欲躍勝高空。',24,'全唐诗/poet.song.193000.json','["亭若龍兩翼，欲躍勝高空。", "濟人幾千百，緒餘不言功。"]'),
('cc24a56d-334c-4d1b-b46f-02047bf3db31','金溪道中六首  其一','包恢','宋','宋诗','song-poetry','','[]','春意藏山川，如童蒙未發。',24,'全唐诗/poet.song.193000.json','["春意藏山川，如童蒙未發。", "一朝興勃然，觸處爭英傑。"]'),
('4e54ab24-6c68-4a84-b09c-3d96e39127ea','金溪道中六首  其二','包恢','宋','宋诗','song-poetry','','[]','濃煙籠遠岫，望眼如昏花。',24,'全唐诗/poet.song.193000.json','["濃煙籠遠岫，望眼如昏花。", "欲暮還欲雨，行人始離家。"]'),
('95cf45cc-433a-40c7-8e09-9fc6de501041','金溪道中六首  其三','包恢','宋','宋诗','song-poetry','','[]','遠山沒雲煙，不辨形與色。',24,'全唐诗/poet.song.193000.json','["遠山沒雲煙，不辨形與色。", "茫如天下垂，前路不可得。"]'),
('f5b3ce11-1905-4b3a-8f29-97f19bc07781','金溪道中六首  其四','包恢','宋','宋诗','song-poetry','','[]','木落葉棲風，陣陣着肌體。',24,'全唐诗/poet.song.193000.json','["木落葉棲風，陣陣着肌體。", "應憶故園花，欲開爲寒止。"]'),
('f97639bf-45b8-40d8-b545-a2af5bf2b522','金溪道中六首  其五','包恢','宋','宋诗','song-poetry','','[]','路傍逢古梅，元是舊相識。',24,'全唐诗/poet.song.193000.json','["路傍逢古梅，元是舊相識。", "花萼知幾多，萼萼相顧惜。"]'),
('699b28b0-b8cb-4866-930e-35849782cc5a','金溪道中六首  其六','包恢','宋','宋诗','song-poetry','','[]','出門逢行人，經緯真如織。',24,'全唐诗/poet.song.193000.json','["出門逢行人，經緯真如織。", "織成幅員長，皆是名利力。"]'),
('b2198061-d817-4240-9154-52c4c3fb2d38','偶成五首  其一','包恢','宋','宋诗','song-poetry','','[]','六月渾如九月清，霽天月色冷幽屏。',32,'全唐诗/poet.song.193000.json','["六月渾如九月清，霽天月色冷幽屏。", "出門聊寄雙遠目，二十四凹峰轉青。"]'),
('8ca72b68-681d-4310-ba28-f8df6ddc059e','偶成五首  其二','包恢','宋','宋诗','song-poetry','','[]','添我凉飈伴我閒，今年新竹未云慳。',32,'全唐诗/poet.song.193000.json','["添我凉飈伴我閒，今年新竹未云慳。", "翻嫌戶外三兩箇，遮斷東來半好山。"]'),
('068aee32-4878-4e59-adf7-313b28c9812e','偶成五首  其三','包恢','宋','宋诗','song-poetry','','[]','農家命脈寄田畝，可但稻粱枯與榮。',32,'全唐诗/poet.song.193000.json','["農家命脈寄田畝，可但稻粱枯與榮。", "造化何許須多力，須臾活幾萬蒼生。"]'),
('1b2ee7b7-580f-403a-a44d-856fb059a2c7','偶成五首  其四','包恢','宋','宋诗','song-poetry','','[]','南風正起北風微，誰謂秋高尚馬肥。',32,'全唐诗/poet.song.193000.json','["南風正起北風微，誰謂秋高尚馬肥。", "但願金飈摧落木，和根亦仆擬何歸。"]'),
('281b6afe-5d24-4eed-a486-3d81f5b269ae','偶成五首  其五','包恢','宋','宋诗','song-poetry','','[]','柔條嫩葉春新媚，勁幹剛枝歲久磨。',32,'全唐诗/poet.song.193000.json','["柔條嫩葉春新媚，勁幹剛枝歲久磨。", "忺厭人情每相反，欲支大厦問憑何。"]'),
('b9df4e72-515f-4b23-975f-a1002592a1bc','題碧巖二首  其一','包恢','宋','宋诗','song-poetry','','[]','萬山擁碧屹不動，萬石嵌崖何可攀。',32,'全唐诗/poet.song.193000.json','["萬山擁碧屹不動，萬石嵌崖何可攀。", "似這立身須定得，定時方始是牢關。"]'),
('698b4eaa-8fc0-42f8-9ac1-6208392bb832','題碧巖二首  其二','包恢','宋','宋诗','song-poetry','','[]','碧巖只在丹霞裏，丹碧從他色自殊。',32,'全唐诗/poet.song.193000.json','["碧巖只在丹霞裏，丹碧從他色自殊。", "我斷不隨他境轉，身心一定誓無渝。"]'),
('d92fdee3-7de3-4064-abc5-32c517b3cc19','二月道中效趙章泉體四首  其一','包恢','宋','宋诗','song-poetry','','[]','鳴蛙一部不虛鳴，知爲農人奏樂聲。',32,'全唐诗/poet.song.193000.json','["鳴蛙一部不虛鳴，知爲農人奏樂聲。", "一歲勤勞方此始，侑他南畝饁時情。"]'),
('f7b3ca4b-970e-42da-90d1-4b8d2f0a3fdf','二月道中效趙章泉體四首  其二','包恢','宋','宋诗','song-poetry','','[]','苦雨花無色與香，送春葉漫綠和黄。',32,'全唐诗/poet.song.193000.json','["苦雨花無色與香，送春葉漫綠和黄。", "蠶聲百鳥飛鳴少，遽聽催歸叫夜長。"]'),
('b25d5f85-1cb1-4a73-833e-e3f7c53abdc7','二月道中效趙章泉體四首  其三','包恢','宋','宋诗','song-poetry','','[]','躑躅紅花何實用，牡丹名品只虛奇。',32,'全唐诗/poet.song.193000.json','["躑躅紅花何實用，牡丹名品只虛奇。", "看今春晚方艱食，何似充饑有蕨萁。"]'),
('56fed17c-2e41-4798-b6fd-dff24f5554ac','二月道中效趙章泉體四首  其四','包恢','宋','宋诗','song-poetry','','[]','耕者勞筋苦骨餘，富家倉廩始多儲。',32,'全唐诗/poet.song.193000.json','["耕者勞筋苦骨餘，富家倉廩始多儲。", "及饑合發方牢閉，不識私家得食諸。"]'),
('3062df70-5d7e-4df6-b6ab-f511655244b8','句','包恢','宋','宋诗','song-poetry','','[]','日短暫居猶旅舍，夜長宜就作祠堂。',16,'全唐诗/poet.song.193000.json','["日短暫居猶旅舍，夜長宜就作祠堂。"]'),
('42d6b72d-326a-435e-bfe4-9f31221e4fae','戊戌二月十日京湖袁總郎以堂帖至有詔復除戶侍總饟','岳珂','宋','宋诗','song-poetry','','[]','晝長欹枕酣春卧，剝啄敲門驚夢破。',224,'全唐诗/poet.song.193000.json','["晝長欹枕酣春卧，剝啄敲門驚夢破。", "雙旗健步衣正黄，爵羅駭見久未嘗。", "泥紫一封芹詔香，王人繭牘親遣將。", "老夫五年坐奇謗，身則漁樵志猶壯。", "豈無戀闕如子牟，强擬隨裝學張敞。", "浮雲滿空能蔽日，雲散天空日華出。", "千三百載春又春，杜陵久矣無斯人。", "黄衣走塵漫踆踆，縱了桴鼓何足云。", "姑言絮舜工負恩，堯天舜日定不爾。", "皎皎太空無點滓，當時下書便疑似。", "聊坐和歌焉熱耳，寧比三光覆盆底。", "金羈欲脫還從頭，絡頭齕草均一牛。", "吾身本是報恩具，千年萬年屬明主。", "感恩欲愬淚如雨，且願投讒畀豺虎。"]'),
('efb43a0f-0a2e-4389-a67a-734971624230','五年不治筆研奉詔起家是日始草辭免奏旋假書吏於郡題寫皆生疏又堂帖趣行三日戒塗偶成二首  其一','岳珂','宋','宋诗','song-poetry','','[]','五年尺牘不牋天，一日除書到枕邊。',64,'全唐诗/poet.song.193000.json','["五年尺牘不牋天，一日除書到枕邊。", "感欲宣心筆無語，恩慚餬口鼎餘饘。", "說驂尚恐傳音誤，書馬還思習札便。", "燭灺燒殘人未寢，却輸鈴下愜安眠。"]'),
('14ab0236-8f26-4508-9970-9395a19ec5be','五年不治筆研奉詔起家是日始草辭免奏旋假書吏於郡題寫皆生疏又堂帖趣行三日戒塗偶成二首  其二','岳珂','宋','宋诗','song-poetry','','[]','露封謄奏曉鳴鈴，當御應關乙夜呈。',64,'全唐诗/poet.song.193000.json','["露封謄奏曉鳴鈴，當御應關乙夜呈。", "京兆有裝隨使者，陳留無酒憶厨兵。", "故營將鉞談家世，老吏公車識姓名。", "塵事看看到書尺，更驚三日有王程。"]'),
('68b1def3-a72c-48ef-bca7-554b5bc9f718','予控免不獲命恭讀詔書聖訓有朕正欲爲卿直前枉之語感激思奮始决小草之謀','岳珂','宋','宋诗','song-poetry','','[]','平生一寸心，不爲世塗折。',240,'全唐诗/poet.song.193000.json','["平生一寸心，不爲世塗折。", "平生七尺軀，擬慕志士烈。", "吾門古喬木，每抱歲寒節。", "三世秉一心，炯炯常不滅。", "雖如卞獻玉，自比來嚼鐵。", "閉門著辨誣，其事已合轍。", "及逢明聖知，所遇皆夐絕。", "隆興錄舊李，一誣出奎札。", "嘉熙今詔書，復以枉爲說。", "人生貴知心，萬事等一吷。", "矧以萬古光，下比覆盆揭。", "憶昔賈奇謗，同舟忽秦越。", "關弓比射羿，舍鏃不虛發。", "仍是同功家，以豢反得嚙。", "靜思誣與枉，二字謹區別。", "兩朝寓至鑑，四海仰日月。", "蕩誣貴昭昭，錯枉豈孑孑。", "此恩無以報，蛇雀況微物。", "匪石心可轉，襆被計當決。", "塵匣開青萍，何時釁妖血。"]'),
('273555c9-b27c-4357-b946-4388b3a21b73','黄鶴謠寄吳季謙侍郎時季謙自德安入城予適以使事在鄂','岳珂','宋','宋诗','song-poetry','','[]','盧山白鶴歸來雙，縞衣素袂玄爲裳。',160,'全唐诗/poet.song.193000.json','["盧山白鶴歸來雙，縞衣素袂玄爲裳。", "翅如車輪夜橫江，風聲曾走淮淝羌。", "戛然長鳴下柴桑，芝田啄粒遥相望。", "何人網羅倏高張，上決雲漢旁八荒。", "一隨鵬鵾驚遠翔，低頭不肯謀稻粱。", "一罹罝弋沮澤旁，局身筠籠翅摧藏。", "鸚鵡洲畔葭葦鄉，水雲蒼蒼江茫茫。", "九臯欲聞聲不揚，回顧鷗鷺羞顔行。", "忽聞緱笙度宮商，紅塵俯視有底忙。", "磯頭刷羽今正黄，欲搥此樓呼酒狂。"]'),
('5e5d78ba-2c6d-4b88-913d-c08ab9d39cb0','予以謬作數種并總所奏藁遺參贊高紫微聞以閲讀未及賜報平日正病無人爲過目者茲不特餉所有別白半生漫浪筆研間爲不虛矣因贈二首  其一','岳珂','宋','宋诗','song-poetry','','[]','夜半軍書尚掣鈴，想應欹枕夢難成。',64,'全唐诗/poet.song.193000.json','["夜半軍書尚掣鈴，想應欹枕夢難成。", "新涼頗復欺長夏，舊事何妨閲短檠。", "人說文衡真有託，公於詩卷若爲評。", "復襄遺跡今如許，試考當時六萬兵。"]'),
('428aa11c-0aac-4d53-9e92-ed2d63c8e20a','予以謬作數種并總所奏藁遺參贊高紫微聞以閲讀未及賜報平日正病無人爲過目者茲不特餉所有別白半生漫浪筆研間爲不虛矣因贈二首  其二','岳珂','宋','宋诗','song-poetry','','[]','涉筆牛腰倦不支，餘工那復到新詩。',64,'全唐诗/poet.song.193000.json','["涉筆牛腰倦不支，餘工那復到新詩。", "殷雷秧綠又期月，指日棗紅能幾時。", "自古兵財無上策，于今社稷寄西陲。", "入郛及國均危道，勿謂君侯不敢知。"]'),
('6cb1258f-3391-4608-8814-1c15dc667a4a','拙婦吟','岳珂','宋','宋诗','song-poetry','','[]','西風策策黄葉舞，茅簷三尺鳴秋雨。',291,'全唐诗/poet.song.193000.json','["西風策策黄葉舞，茅簷三尺鳴秋雨。", "東家拙婦擁面啼，强剔孤燈訴愁窶。", "當年採桑陌上歸，嬉遊不管春蠶饑。", "千絲萬縷繭白雪，便學紅女攀花枝。", "十七十八事機織，暗瑣青閨人不識。", "二十三十幽恨長，盧家古梁玉爲堂。", "四十五十已老大，唧唧鳴蛩欺獨卧。", "尚隨姑嫂作笑嗔，一生苦樂由他人。", "君不見昨朝縣吏踏門闑，杼柚已空盆盎竭。", "雞豚指柵索飲壺，掀釜叫嘑嗤婦拙。", "起來迎門陪笑面，不似嬌羞怕人見。", "今年歲事苦不登，且爲當家聊一展。", "吏囂不肯怒且訶，大兒門東窺飯籮。", "藁砧走藏姑誚駡，造餠無麫知如何。", "蹙金芙蓉戲雙鴛，繡床一倚曾萬錢。", "低頭長嘆祇自憐，昔者何巧今不然。", "吏嘑已倦里正醉，抆淚背人還滌器。", "明朝欲酒姑勿譁，正恐突隳驚阿家。"]'),
('7ae230f9-4f29-4593-8dca-7d4c9ba80792','春波堂小飲懷棠湖舊隠三首  其一','岳珂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生到處西湖長，眼底波光日日新。',64,'全唐诗/poet.song.193000.json','["平生到處西湖長，眼底波光日日新。", "圖在輞川非舊隠，夢回笠澤是前身。", "一江細雨欹青菊，萬里雄風起白蘋。", "獨立蒼茫動歸興，釣磯須理未垂綸。"]'),
('fbbcf4c7-a1f7-4353-b508-f32798275399','春波堂小飲懷棠湖舊隠三首  其二','岳珂','宋','宋诗','song-poetry','','[]','炎暑今年特地奇，不妨湖上訪清漪。',64,'全唐诗/poet.song.193000.json','["炎暑今年特地奇，不妨湖上訪清漪。", "長堤步屧誰堪擬，高閣凭闌我總宜。", "喚客黄鸝穿柳度，猜人白鳥映荷窺。", "衰翁病骨難禁熱，且倩西風自在吹。"]'),
('687066cb-075d-4899-8534-e21300af264e','春波堂小飲懷棠湖舊隠三首  其三','岳珂','宋','宋诗','song-poetry','','[]','虛欄四面挹湖光，最愛薰風六月涼。',64,'全唐诗/poet.song.193000.json','["虛欄四面挹湖光，最愛薰風六月涼。", "萬朶芙蕖紅影閙，兩行楊柳綠絲長。", "鋪陳雪月晶明態，商略陰晴濃淡妝。", "四序清游總如此，春波何事獨名堂。"]'),
('6f0f5231-65a1-4abc-b478-4ff2c4a74085','食棗有感二首  其一','岳珂','宋','宋诗','song-poetry','','[]','百果隨時效歲功，棗槃亦復薦年豐。',64,'全唐诗/poet.song.193000.json','["百果隨時效歲功，棗槃亦復薦年豐。", "柔柯低带隨風綠，纂實駢隨映日紅。", "聞說桃梨堪絜大，頗懷齊魯久爲戎。", "憂時把玩還驚歎，莫咏豳風詠北風。"]'),
('7ef32f14-e7fe-4cf9-8dd4-a3dadbd9fea8','食棗有感二首  其二','岳珂','宋','宋诗','song-poetry','','[]','碩棗名亭此地傳，况逢新摘正芳鮮。',64,'全唐诗/poet.song.193000.json','["碩棗名亭此地傳，况逢新摘正芳鮮。", "栗投聊寓孤臣報，瓜實初無小史緣。", "只合赤心思待敵，豈容白手覬延年。", "樓蘭可斬平生志，欲和安期覓劍仙。"]'),
('34d440b6-dfbf-49c5-9700-29fd8bfe0e09','約客春波督參劉郎中方赴高紫微之集道間相值不容留戲贈二首  其一','岳珂','宋','宋诗','song-poetry','','[]','春波堂上倚欄干，一曲樓臺晻靄間。',64,'全唐诗/poet.song.193000.json','["春波堂上倚欄干，一曲樓臺晻靄間。", "野衲再尋行脚債，釣簑聊寄賞心閒。", "燕低欲舞影翻水，鳥倦知還雲在山。", "匹似棠湖儘堪住，遶簷祇欠翠螺鬟。"]'),
('6d00f737-a790-4ecf-9c93-326f8b4ac717','約客春波督參劉郎中方赴高紫微之集道間相值不容留戲贈二首  其二','岳珂','宋','宋诗','song-poetry','','[]','錦帳星郎油壁車，紫微花下醉流霞。',64,'全唐诗/poet.song.193000.json','["錦帳星郎油壁車，紫微花下醉流霞。", "簫鸞東引瞻風馭，池鳳西游賦日華。", "蓼岸半紅秋漸老，柳堤仍綠約猶賒。", "一尊更趁萊衣綵，河漢還乘八月槎。"]'),
('7ffa8112-a91c-472c-ba43-2ea0f88d1284','餞孟運判寺簿赴京三首  其一','岳珂','宋','宋诗','song-poetry','','[]','溫純如玉絕纖瑕，驚坐何人指孟嘉。',64,'全唐诗/poet.song.193000.json','["溫純如玉絕纖瑕，驚坐何人指孟嘉。", "策馬殿軍勞不伐，舍魚取義理無差。", "讀碑襄水真爲谷，守壘房陵忍顧家。", "鄉國不妨動歸興，天津八月却隨楂。"]'),
('30731b04-f336-4a43-ad54-9af17297555f','餞孟運判寺簿赴京三首  其二','岳珂','宋','宋诗','song-poetry','','[]','詔書夜下日華門，輦路爭看使者軒。',64,'全唐诗/poet.song.193000.json','["詔書夜下日華門，輦路爭看使者軒。", "烽火三邊尚勍敵，煙塵萬里欠公言。", "不須目睫憂多壘，好吐胸懷悟至尊。", "富貴功名分中有，勿令仗馬媿廷鵷。"]'),
('f321b932-ca2f-44a3-9d16-a7a48bd99994','餞孟運判寺簿赴京三首  其三','岳珂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','半生共飲西江水，草木由來臭味同。',64,'全唐诗/poet.song.193000.json','["半生共飲西江水，草木由來臭味同。", "交臂便同鴻燕社，論心不隔馬牛風。", "君方鳴珮趨雙闕，我自燒車延五窮。", "景倩仙塵凝望處，爲言驛騎莫匆匆。"]'),
('421875a0-265a-4d09-89c5-59f4ca66e894','與高紫微雪溪餞客雖已預盟然坐次予每居上爲之踧踖寄此見意','岳珂','宋','宋诗','song-poetry','','[]','碧梧正耐雪溪秋，况是西風送客舟。',64,'全唐诗/poet.song.193000.json','["碧梧正耐雪溪秋，况是西風送客舟。", "華宴雖思奉婪尾，粗官何敢作遨頭。", "達尊諒識詩囊意，負約仍輸酒斛籌。", "想見尊前列紅袖，可憐無分聽梁州。"]'),
('32b9b4ae-ea71-4f94-bc67-cebefcc532cb','夜讀莊子呈高紫微','岳珂','宋','宋诗','song-poetry','','[]','蒙園傲吏御風仙，聊以巵言後世傳。',64,'全唐诗/poet.song.193000.json','["蒙園傲吏御風仙，聊以巵言後世傳。", "小大升潛同此地，智愚工拙豈其天。", "衆途適正何勞問，一理觀心本自然。", "從此二經束高閣，爲君終夕讀名篇。"]'),
('b04e58b6-887e-492d-a3ab-b5cf7fcaf543','秋夕有感二首呈督視參政  其一','岳珂','宋','宋诗','song-poetry','','[]','湯湯南紀重喉衿，縱敵年來患已深。',64,'全唐诗/poet.song.193000.json','["湯湯南紀重喉衿，縱敵年來患已深。", "七十萬家財與力，六千里地古猶今。", "薇屯正自憂無給，桑土當思徹未陰。", "用力愈勞工愈寡，相公試察此時心。"]'),
('2f906c3c-f86c-4073-b3c0-f423244775a9','秋夕有感二首呈督視參政  其二','岳珂','宋','宋诗','song-poetry','','[]','老去工夫在一丘，解驂重使借前籌。',64,'全唐诗/poet.song.193000.json','["老去工夫在一丘，解驂重使借前籌。", "憂關王國漫騰口，事爲他人常壓頭。", "蟻穴潰堤猶未計，鮒車涸轍若爲謀。", "恩波況是如天闊，早放棠湖理釣鈎。"]'),
('008c0884-772d-4eb0-9453-2c9b97a404cb','九江霜蟹比他處黑膏凝溢名冠食譜久擬遺高紫微而家僮後期未至以詩道意','岳珂','宋','宋诗','song-poetry','','[]','君不見東來海蟹誇江陰，肌如白玉黄如金。',198,'全唐诗/poet.song.193000.json','["君不見東來海蟹誇江陰，肌如白玉黄如金。", "又不見西來湖蟹到沔鄂，玉軟金流不堪斫。", "九江九月秋風高，霜前突兀贍兩螯。", "昆吾欲割不受刀，頗有萇碧流玄膏。", "平生尊前厭此味，更看康廬拂空翠。", "今年此曹殊未來，使我對酒空悠哉。", "舊傳騷人鍊奇句，無蟹無山兩孤負。", "老來政欠兩眼青，那復前籌虛借箸。", "祇今鄉國已駿奔，軍將日高應打門。", "流涎便作麯車夢，半席又擬鍾山分。", "先生家住岷峨脚，屢放清游仍大嚼。", "襟期盡醉何日同，試筮太玄呼郭索。"]'),
('76138f86-383e-4750-8569-02cff8494303','餞高紫微視師黄岡','岳珂','宋','宋诗','song-poetry','','[]','秋風九月邊塵高，千艘夜下宮錦袍。',64,'全唐诗/poet.song.193000.json','["秋風九月邊塵高，千艘夜下宮錦袍。", "文章不特動蠻貊，要識金版開六弢。", "孫曹已矣等陳迹，喚起坡仙同赤壁。", "喧闐笳鼓動地歸，重把功名光采石。"]'),
('5de1c711-31cc-4508-b2c8-7a4e63665455','以螃蟹寄高紫微踐約侑以雪醅時猶在黄岡','岳珂','宋','宋诗','song-poetry','','[]','前朝無蟹惟有詩，亦復無酒供一瓻。',96,'全唐诗/poet.song.193000.json','["前朝無蟹惟有詩，亦復無酒供一瓻。", "今朝有蟹仍有酒，極目征帆更搔首。", "古來樂事誇持螯，赤瓊釀髓玄玉膏。", "菊花吹英好時節，况是九日將登高。", "旌旗半江笳鼓發，不作詩人淡生活。", "待君浄洗沙漠塵，歸趁看燈更奇絕。"]'),
('52382c52-4349-40ae-8b5a-99810b8f2cbf','餞紫微高侍郎朝天','岳珂','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','紫微星郎天上客，身是南宮小宗伯。',262,'全唐诗/poet.song.193000.json','["紫微星郎天上客，身是南宮小宗伯。", "斗杓夜轉天門開，平地一聲驚霹靂。", "已將椽筆提斯文，更決河漢排風雲。", "銀潢直下洗戈甲，坐看九陌狂流奔。", "黄金爲臺玉爲帳，有眼須看舍人樣。", "紹興季歲說雍公，曾冠貂蟬登上相。", "峨嵋山高鍾異人，昔年相國今後身。", "聲名何嘗岷蜀隔，草木仍是江淮春。", "君不見嘉熙聖主躬神武，法祖整軍蕩强虜。", "又不見魏公一戰平麟猊，次年子月天廢齊。", "天心廢興真有待，肯以貪殘易仁愛。", "大數恰逢一百年，埽穴犁庭當復再。", "今年又自淮西來，右相勳名傳九垓。", "旄頭黑雲墜西北，兩兩比色明三台。", "先朝貝州妖賊起，若比此胡僅蜂蟻。", "當時禮部文侍郎，一日奏凱同平章。"]'),
('b81c10ba-a5b7-4f01-a0a3-b27c6734585e','後元祐行上辨章喬益公','岳珂','宋','宋诗','song-poetry','','[]','正月二日天氣清，六符兩兩三階平。',387,'全唐诗/poet.song.193000.json','["正月二日天氣清，六符兩兩三階平。", "閤門催班報麻案，珂馬玎玲萬人看。", "押麻參政拆璽封，宣詞舍人來殿東。", "鞠躬一聲百寮聽，軍國平章喬益公。", "天心果與人心同，大哉聖斷天與通。", "本朝太平說元祐，五嶽三光渾未剖。", "當年一日三制頒，呂范堂堂分左右。", "虔中大老更魁傑，申國勳名比韓富。", "民生是時非漢唐，親見至治躋羲皇。", "一塵不起四夷服，軌順星躔蕃五穀。", "士皆有造百姓寧，官僚徹底清似冰。", "桁楊畢空戈革偃，天街鏡浄無攙槍。", "彼何人斯階啟厲，九縣回飆八紘沸。", "高皇疋馬開東南，王業中興今五世。", "窮荒靺鞨何自來，中原萬里吹黄埃。", "數殫剝復回否泰，胚腪元氣鍾奇才。", "耆明壽雋軼千古，呂望鷹揚稱尚父。", "便教旦奭居東西，穆穆迓衡今再覩。", "官家即日開天章，貂冠玉佩游巖廊。", "一都一俞一吁咈，四海春風已披拂。", "聖賢自昔難相逢，巨魚縱壑鴻遇風。", "輿人歡呼爭誦說，元祐嘉熙莫分別。", "君不見徂徠處士歌一夔，濃墨大字慶曆詩。", "生民至今受其賜，千載萬載生光輝。"]'),
('81b4d31f-0665-4bd5-b511-83d2d9b5fa20','上巳約客總宜一病不及往二詩呈陳元履王囦衜諸人自酌  其一','岳珂','宋','宋诗','song-poetry','','[]','總宜閣畔小簾櫳，碧浸平湖面面風。',64,'全唐诗/poet.song.193000.json','["總宜閣畔小簾櫳，碧浸平湖面面風。", "別館柳陰聊繫馬，便橋紅影正垂虹。", "流觴有序傳詩客，在席無人稱倦翁。", "儂自醉歸翁自倦，風光流轉不須同。"]'),
('253da5c7-421b-4a6d-be42-4a6cf55f5e6a','上巳約客總宜一病不及往二詩呈陳元履王囦衜諸人自酌  其二','岳珂','宋','宋诗','song-poetry','','[]','我是棠磯舊釣徒，天教生與水雲俱。',64,'全唐诗/poet.song.193000.json','["我是棠磯舊釣徒，天教生與水雲俱。", "蘭亭正值人修禊，柳岸還添浪拍湖。", "幸有丈人觀筆法，可無嘉客醉兵厨。", "直須去躍城東馬，更與留春作後圖。"]'),
('635213c3-10b4-4508-8196-6305f367b05c','聞韓正倫檢正掛冠感歎故交悵然久之偶成三首  其一','岳珂','宋','宋诗','song-poetry','','[]','中興王社舊同功，三世何嘗間一忠。',64,'全唐诗/poet.song.193000.json','["中興王社舊同功，三世何嘗間一忠。", "北海真成賢吏歎，西州猶記勝游同。", "逢迎有意君雖謬，喜怒無心我自窮。", "詩禍古今均一律，莫將燈夜怨東風。"]'),
('83d675a0-5f36-4eca-bc93-c03a97576d6e','聞韓正倫檢正掛冠感歎故交悵然久之偶成三首  其二','岳珂','宋','宋诗','song-poetry','','[]','恩門小簡寫門生，六載交情老弟兄。',64,'全唐诗/poet.song.193000.json','["恩門小簡寫門生，六載交情老弟兄。", "一念吹毛牙角訟，十年握手肺肝傾。", "酌貪誰飲南𤃩水，敵怨人談北府兵。", "空券更憐蠅筆誤，却因誤處得分明。"]'),
('8133e4f2-ad6c-470e-90f3-677d1559d97a','聞韓正倫檢正掛冠感歎故交悵然久之偶成三首  其三','岳珂','宋','宋诗','song-poetry','','[]','心存即鹿嘆無虞，畫地雖工理反疎。',64,'全唐诗/poet.song.193000.json','["心存即鹿嘆無虞，畫地雖工理反疎。", "直枉已傳天子詔，厚誣猶見監奴書。", "儻令甬道真難繼，未必都曹可遂初。", "萬里上流關社稷，不知天意竟何如。"]'),
('494641a3-0a6b-4e44-b1ef-7a3c41f026fd','予癸巳在京口因郡中元夕張燈偶閲國史靖康丙午正月十五日辛巳祐陵南巡駐蹕是郡二月二十三日己未始還京師凡居郡三十有八茲聞簫鼓感舊興嘆不勝潸然因涉筆以記大略而僧有沖希者乃携以示正倫彼謂予諷己遂架大怨迄興妄獄聖明察知其冤予復將指前漫盡白因悼正倫之歿閔其左計亮其初心附昔所作詩于後','岳珂','宋','宋诗','song-poetry','','[]','駕軺老子久婆娑，坐聽笙歌擁綺羅。',64,'全唐诗/poet.song.193000.json','["駕軺老子久婆娑，坐聽笙歌擁綺羅。", "十里西涼憶如意，百年南國比流梭。", "吞聲有恨哀蒲柳，紀節無人廢蓼莪。", "寂寞丹心耿梅月，挑燈頻問夜如何。"]'),
('bcfd392f-9c3b-4a26-95f7-ea8f961040b1','興唐寺聞鐘','岳珂','宋','宋诗','song-poetry','','[]','興唐鐘刻無夫字，久欲摩挲與細論。',32,'全唐诗/poet.song.193000.json','["興唐鐘刻無夫字，久欲摩挲與細論。", "歸棹未容酬此志，一聲煙靄又黄昏。"]'),
('4545751f-6d61-4fe9-9371-d573dee13077','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其一','岳珂','宋','宋诗','song-poetry','','[]','雪錦亭前水接天，晚波如縠放歸船。',32,'全唐诗/poet.song.193000.json','["雪錦亭前水接天，晚波如縠放歸船。", "新詩開務從今日，此是江行第一篇。"]'),
('19dc88d9-9709-4582-b22a-de168afcebe0','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其二','岳珂','宋','宋诗','song-poetry','','[]','離歌已盡沙頭玉，夕照初翻浪底金。',32,'全唐诗/poet.song.193000.json','["離歌已盡沙頭玉，夕照初翻浪底金。", "自是晴鷗無六月，半江雪片湧波心。"]'),
('19836e50-44a6-4311-a3a3-b1b5ac32b48f','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其三','岳珂','宋','宋诗','song-poetry','','[]','蕭蕭衰髮倚西風，兩岸青山盡識儂。',32,'全唐诗/poet.song.193000.json','["蕭蕭衰髮倚西風，兩岸青山盡識儂。", "東去西來緣底事，祇應添得一龍鍾。"]'),
('af902845-4196-49e6-bb8c-3abe2f749ebe','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其四','岳珂','宋','宋诗','song-poetry','','[]','一江漲碧碧於藍，健櫓鳴鵝舳正銜。',32,'全唐诗/poet.song.193000.json','["一江漲碧碧於藍，健櫓鳴鵝舳正銜。", "纔似過都空萬馬，又驚倚岸閲千帆。"]'),
('9e5a9f94-ee76-429c-95c9-f4243fa774c9','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其五','岳珂','宋','宋诗','song-poetry','','[]','宵聲傳柝重城閉，曉漏迷鐘古寺荒。',32,'全唐诗/poet.song.193000.json','["宵聲傳柝重城閉，曉漏迷鐘古寺荒。", "仰看繁星垂四野，不知身世變炎涼。"]'),
('04051100-5adf-4240-b2f3-c788febe62d9','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其六','岳珂','宋','宋诗','song-poetry','','[]','一缾一錫一團蒲，到得今年一物無。',32,'全唐诗/poet.song.193000.json','["一缾一錫一團蒲，到得今年一物無。", "桑下勿興三宿念，古人不食武昌魚。"]'),
('6ffb065e-fdfa-4b5b-ac34-bf1ff89aae82','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其七','岳珂','宋','宋诗','song-poetry','','[]','葭葦延緣舞翠旌，白頭吹浪又相迎。',32,'全唐诗/poet.song.193000.json','["葭葦延緣舞翠旌，白頭吹浪又相迎。", "攀轅亦作留行計，莫道馮夷不世情。"]'),
('6ce62bd0-69e1-4bbd-b6e2-3db74a997bd8','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其八','岳珂','宋','宋诗','song-poetry','','[]','昌黎久願列三王，我亦曾親翰墨香。',32,'全唐诗/poet.song.193000.json','["昌黎久願列三王，我亦曾親翰墨香。", "惜別依依重回首，棠磯風月更思量。"]'),
('e940f57b-d0ac-4ada-9bd8-7a0247a7637f','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其九','岳珂','宋','宋诗','song-poetry','','[]','赤壁江頭白羽揮，鱖肥西塞酒同携。',32,'全唐诗/poet.song.193000.json','["赤壁江頭白羽揮，鱖肥西塞酒同携。", "歸期應在初弦月，家住康山西復西。"]'),
('17594ea9-8573-4541-8591-486742a4695e','至鄂期年以饟事不給於詩己亥夏五廿有八日始解維雪錦夜宿興唐寺繁星滿天四鼓遂行日初上已抵滸黄洲幾百里矣午後南風薄岸舟屹不能移延緣葭葦間至莫不得去始作紀事十解呈舊幕諸公  其一○','岳珂','宋','宋诗','song-poetry','','[]','人生邂逅適相懽，一曲高歌行路難。',32,'全唐诗/poet.song.193000.json','["人生邂逅適相懽，一曲高歌行路難。", "頻寄詩筩君勿厭，種花持釣是閑官。"]'),
('95056546-c035-4b61-9268-d25299a782cf','夜過壽昌','岳珂','宋','宋诗','song-poetry','','[]','風雲八字護城隅，樓殿崔嵬想帝居。',64,'全唐诗/poet.song.193000.json','["風雲八字護城隅，樓殿崔嵬想帝居。", "曾侍金輿惟石馬，幸因玉璽記銅魚。", "千年鼓角聲猶壯，四塞河山恨未袪。", "麋鹿已游人事改，何人曾讀輔吳書。"]'),
('989df0af-0303-46e0-86f5-91d66ba8e063','望樊口懷陶士行溫太真二首  其一','岳珂','宋','宋诗','song-poetry','','[]','昔年老子恨婆娑，未付其如印傳何。',64,'全唐诗/poet.song.193000.json','["昔年老子恨婆娑，未付其如印傳何。", "吳苑關心春日少，湘江回首暮雲多。", "可無司馬親封鑰，自是將軍老枕戈。", "我亦新來了官事，正輸一舸弄煙波。"]'),
('a865f3b7-ef39-4147-bfb3-4e5a9dd9ea47','望樊口懷陶士行溫太真二首  其二','岳珂','宋','宋诗','song-poetry','','[]','太真行酒知何地，渺莽遺基茂草深。',64,'全唐诗/poet.song.193000.json','["太真行酒知何地，渺莽遺基茂草深。", "聲色加人何足計，精神滿腹不同斟。", "六奇自可掀三狡，一正何妨讋百壬。", "墮幘吐茵均此轍，可憐枉用世儀心。"]'),
('769b040e-2827-4b3b-8ef6-f5041791beae','三江口過舟時方四鼓','岳珂','宋','宋诗','song-poetry','','[]','櫂鷁收金柅，釵蟲綴玉缸。',48,'全唐诗/poet.song.193000.json','["櫂鷁收金柅，釵蟲綴玉缸。", "地鄰今七澤，名襲古三江。", "岷漾雖分派，荆揚却異邦。", "晨光猶未發，早認白鷗雙。"]'),
('fb8dc657-a668-4077-b3a8-2f80a2f81f69','赤壁','岳珂','宋','宋诗','song-poetry','','[]','周郎二十四年少，蓋世功名隨一燎。',320,'全唐诗/poet.song.193000.json','["周郎二十四年少，蓋世功名隨一燎。", "親提三萬走曹瞞，不以敵勍恨兵少。", "豫州失匕已膽折，一日目明驚二妙。", "最憐黄蓋不知名，吏士相從倚營嘯。", "阿奴火攻本無策，破竹自繇人不料。", "貪降納侮理固宜，泥淖華容幾盡剿。", "古來行師有絕地，毋乃重詒千古笑。", "鏃湛縱是差可認，鼎峙詎關謀所召。", "二喬春鎖何足言，從此天光遂分耀。", "我聞漢賊久染指，奮毒摇牙噬江表。", "八荒囊括豈復遺，一蹙吳宮已爲沼。", "當時乘勝下部騎，考地當居楚南徼。", "蒙衝逆鬭須上流，揖寇那容越津要。", "武昌霸基跬步耳，肯使國畿紛戟旐。", "坡仙訪古特寓意，橫槊雄姿誰與弔。", "故將異地眩疑辭，政恐因訛啟譏誚。", "滄浪六月卷晴雪，歷歷江山人物眇。", "崩空亂石今幾存，仿佛棲巢尚驚鳥。", "夜深刁斗聲四發，星斗滿空群籟悄。", "便須喚起紫綺裘，孤鶴南天楚江曉。"]'),
('2df5404e-3e64-4741-b068-d05cb3e69f97','卷雪樓','岳珂','宋','宋诗','song-poetry','','[]','地靈境勝宅神游，第一江山卷雪樓。',64,'全唐诗/poet.song.193000.json','["地靈境勝宅神游，第一江山卷雪樓。", "勢擁萬峰淮甸接，氣吞七澤楚天浮。", "魚龍灂沸雲生檻，鷗鷺波閒月上鈎。", "畫棟珠簾朝復暮，英名常與水東流。"]'),
('8b0cc3e5-1f78-4f13-8e02-14ad9ba2014c','謁遺愛王祠二首  其一','岳珂','宋','宋诗','song-poetry','','[]','功定三分國，名高八字山。',48,'全唐诗/poet.song.193000.json','["功定三分國，名高八字山。", "威容尊國祀，□□□□□。", "虎卧無今古，烏靈信往還。", "保民存賜珓，猶掛屋楣間。"]'),
('04e3f046-d8c2-4ed3-96a9-cecf20b8ae19','謁遺愛王祠二首  其二','岳珂','宋','宋诗','song-poetry','','[]','大帝開江左，謀臣守四方。',48,'全唐诗/poet.song.193000.json','["大帝開江左，謀臣守四方。", "興邦有喬木，遺愛尚甘棠。", "日月扶聲烈，山川詫鬰蒼。", "中原知極目，應慨舊封疆。"]'),
('a756d20a-3df0-4dcd-b34d-0c7b6461ce42','寄王料院三首  其一','岳珂','宋','宋诗','song-poetry','','[]','平生初未識半面，此地相從方及朞。',64,'全唐诗/poet.song.193000.json','["平生初未識半面，此地相從方及朞。", "舉世公清如子少，隨時離合豈人爲。", "可堪歲月老奇傑，等是年時經嶮巇。", "閒適不同同患苦，兩心惟有一天知。"]'),
('3268938e-563a-4d5f-8095-ae8c3575bae1','寄王料院三首  其二','岳珂','宋','宋诗','song-poetry','','[]','炯炯青燈對擁爐，掣鈴夜半讀邊書。',64,'全唐诗/poet.song.193000.json','["炯炯青燈對擁爐，掣鈴夜半讀邊書。", "風煙解使寸心折，霜雪頓侵雙鬢疎。", "已事勿言穿塞馬，歷官可歎上竿魚。", "勤勞似此天應報，我自鋤犁一任渠。"]'),
('56a7a997-5cc8-4223-a3a4-5293c4b1f48a','寄王料院三首  其三','岳珂','宋','宋诗','song-poetry','','[]','一葉扁舟興浩然，筆床茶竈舊因緣。',64,'全唐诗/poet.song.193000.json','["一葉扁舟興浩然，筆床茶竈舊因緣。", "帆歸西塞秋風外，人在南樓夜月前。", "情不自由君憶我，老無所用我知天。", "何時見易園中路，拂石携壺同醉眠。"]'),
('c58a8992-5430-43e6-a7f3-4064d38d8357','後江行十絕  其一','岳珂','宋','宋诗','song-poetry','','[]','日日征帆上水風，掀天雪浪駭魚龍。',32,'全唐诗/poet.song.193000.json','["日日征帆上水風，掀天雪浪駭魚龍。", "不須檢校江行曆，知過雲山幾萬重。"]'),
('fd3252bd-2b6c-4432-9219-af859dc8c276','後江行十絕  其二','岳珂','宋','宋诗','song-poetry','','[]','遠村烟暝牛羊下，近岸波澄鷗鷺閒。',32,'全唐诗/poet.song.193000.json','["遠村烟暝牛羊下，近岸波澄鷗鷺閒。", "一抹斜陽江似鏡，天移小景向人間。"]'),
('2701c946-7ee9-4ad3-9cc7-4c07941fe183','後江行十絕  其三','岳珂','宋','宋诗','song-poetry','','[]','指點神鴉送客檣，江山回首鬰蒼蒼。',32,'全唐诗/poet.song.193000.json','["指點神鴉送客檣，江山回首鬰蒼蒼。", "吳朝千載興亡地，極目長淮恨更長。"]'),
('e97a731c-3ef3-474b-ba91-d52a5b7f977c','後江行十絕  其四','岳珂','宋','宋诗','song-poetry','','[]','擁騎年時憶往來，舊時行處半莓苔。',32,'全唐诗/poet.song.193000.json','["擁騎年時憶往來，舊時行處半莓苔。", "山雲勒駕應頻笑，又是江南勾當回。"]'),
('b43275ae-eb39-48c9-b2ba-ea6c975721ae','後江行十絕  其五','岳珂','宋','宋诗','song-poetry','','[]','夕舂正是隔前谿，江路行人猶未歸。',32,'全唐诗/poet.song.193000.json','["夕舂正是隔前谿，江路行人猶未歸。", "我笑卧龍成底事，晨光儘欠踏熹微。"]'),
('a5e248c6-805c-4a4f-b061-71178b253fcf','後江行十絕  其六','岳珂','宋','宋诗','song-poetry','','[]','叫着漁郎急掉頭，一聲別浦聽蓮謳。',32,'全唐诗/poet.song.193000.json','["叫着漁郎急掉頭，一聲別浦聽蓮謳。", "山遥水遠應同趣，我亦青帘問酒樓。"]'),
('0c8997b9-ad42-43bd-92be-bd6f0ae5ecba','後江行十絕  其七','岳珂','宋','宋诗','song-poetry','','[]','湓波已近見康廬，風月煙雲自卷舒。',32,'全唐诗/poet.song.193000.json','["湓波已近見康廬，風月煙雲自卷舒。", "白鳥歸來閒似我，向山深處認巢居。"]'),
('f6a96400-b9ff-42c3-bfd2-b32ffa130fd2','後江行十絕  其八','岳珂','宋','宋诗','song-poetry','','[]','官牌夾外少人煙，商婦琵琶久斷絃。',32,'全唐诗/poet.song.193000.json','["官牌夾外少人煙，商婦琵琶久斷絃。", "司馬青衫不須泣，江鷗對我正忻然。"]'),
('8329a4d0-7294-44bd-90e7-9cd422c5e5c8','後江行十絕  其九','岳珂','宋','宋诗','song-poetry','','[]','西望沙羨東秣陵，湓江中道是歸程。',32,'全唐诗/poet.song.193000.json','["西望沙羨東秣陵，湓江中道是歸程。", "柳陰繫纜人歸後，頻有黄鸝三四聲。"]'),
('e3aafba0-63d5-41f1-ac14-1c293a55ec28','後江行十絕  其一○','岳珂','宋','宋诗','song-poetry','','[]','人生最好是歸來，六月火雲溶雪醅。',32,'全唐诗/poet.song.193000.json','["人生最好是歸來，六月火雲溶雪醅。", "散髮晞風須一醉，月明携簟又涼臺。"]'),
('e7740f65-325a-4c16-98d7-0cc4f981942a','初還故居','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','元是廬山莫逆交，宮亭西畔着衡茅。',64,'全唐诗/poet.song.193000.json','["元是廬山莫逆交，宮亭西畔着衡茅。", "盟鷗似怯經新浪，怨鶴還知宿故巢。", "一沼種蓮衣可製，萬竿脫籜杖輕敲。", "不須海若逌然笑，乞與杯堂樂芥坳。"]'),
('4f243450-1447-40d2-8a3d-81f54611cc3b','集喜二首  其一','岳珂','宋','宋诗','song-poetry','','[]','鵲噪庭前木，蛛翻簷畔圍。',48,'全唐诗/poet.song.193000.json','["鵲噪庭前木，蛛翻簷畔圍。", "雙蓮瑞明月，萬柳舞晴暉。", "宿鶴迎風袂，盟鷗認雪衣。", "物情同一喜，應爲主人歸。"]'),
('caa0a2fb-ed66-4c16-8675-e957b48753c0','集喜二首  其二','岳珂','宋','宋诗','song-poetry','','[]','水面開新皺，山容散宿顰。',48,'全唐诗/poet.song.193000.json','["水面開新皺，山容散宿顰。", "松巢猨已識，花徑鹿初馴。", "雲倦隨歸鳥，風清似故人。", "逢迎真不暇，誰作近前嗔。"]'),
('71768a6d-4432-4852-8a3e-146738dd8a51','寄紫微高侍郎三首  其一','岳珂','宋','宋诗','song-poetry','','[]','去年紫塞兩相望，公在齊安我武昌。',64,'全唐诗/poet.song.193000.json','["去年紫塞兩相望，公在齊安我武昌。", "秋晏車箱訪流馬，夜深弧矢看天狼。", "不辭目斷傳烽堠，尚憶螯持共酒觴。", "今日區區話鵬鷃，圖南應是歎榆枋。"]'),
('06560ebc-ef32-442d-9e06-5b0aafb99ab8','寄紫微高侍郎三首  其二','岳珂','宋','宋诗','song-poetry','','[]','人生憂患偶同時，曾見驚塵傍紫微。',64,'全唐诗/poet.song.193000.json','["人生憂患偶同時，曾見驚塵傍紫微。", "坡老鶻巢尚堪俯，周郎羽扇想重揮。", "望風自絕胡南牧，囓雪應遲使北歸。", "從此青油欠籌畫，上方虛己聽宵衣。"]'),
('9b3a747b-619a-4048-84a6-4519a792ada3','寄紫微高侍郎三首  其三','岳珂','宋','宋诗','song-poetry','','[]','力勞效寡是窮途，贈策無人生大愚。',64,'全唐诗/poet.song.193000.json','["力勞效寡是窮途，贈策無人生大愚。", "三刖尚迷藏櫝寶，六街幾誤脫巾呼。", "味言已轉廷中轂，歸興難忘隴上鋤。", "欲問死生何許是，紫煙浮處認香鑪。"]'),
('f4147ae9-c8f6-4584-98b3-5d884b3ee633','歸自鄂雙蓮生于後池偶作再寄紫微','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','巋然康廬山，獨秀蓮花峰。',288,'全唐诗/poet.song.193000.json','["巋然康廬山，獨秀蓮花峰。", "派爲濂溪源，下有愛蓮翁。", "絕學嗣洙泗，千載同清風。", "書堂二池間，浮翠籠輕紅。", "居然不染塵，湧出清泠中。", "雪藕厲堅節，一念窒以通。", "朝卷而暮舒，吸之碧玉谿。", "潔凝月露潤，妖鄙桃李穠。", "食子味崖蜜，擘房透香叢。", "菰蒲儼不羣，魚鳶間相從。", "大哉君子操，視此褆其躬。", "我方賦歸來，來策溪上筇。", "家池忽驚見，晴霞照秋空。", "已迎顥氣澂，况復嘉瑞逢。", "雙葩本共根，殊質疑並鍾。", "摘奇且熟玩，比德思廣充。", "嘗聞古之人，即物皆至公。", "兩岐美報上，同穎還居東。", "雙觡賦長卿，奇木對終童。", "善推仁義端，脗合造化工。", "後世煽淫靡，世見了不同。", "聯芳天泉池，合歡華清宮。", "駢花耀鯉湖，十丈聞華潼。", "徒能資喪志，誰與思念功。"]'),
('544198bc-4390-455b-b105-f1dee6eaad7b','又賦雙蓮','岳珂','宋','宋诗','song-poetry','','[]','一舸歸來喜未涯，天教奇産瑞吾家。',64,'全唐诗/poet.song.193000.json','["一舸歸來喜未涯，天教奇産瑞吾家。", "交枝各倚青羅蓋，並蒂俱酣紅玉葩。", "湘女月裳疑共浴，越姬風袂憶同車。", "人生所欠惟閒適，且酌清尊對物華。"]'),
('281e1ba7-ab1a-4d5b-928d-ae134091718d','病中有感四首  其一','岳珂','宋','宋诗','song-poetry','','[]','欹枕目雙炯，觸屏腸九回。',48,'全唐诗/poet.song.193000.json','["欹枕目雙炯，觸屏腸九回。", "玉蟲迷眩霧，銀鹿伴饑雷。", "清夢雖驚隔，丹心未猝灰。", "青萍聊把玩，塵匣爲誰開。"]'),
('88ec721c-649e-42c3-b969-6d21278fea13','病中有感四首  其二','岳珂','宋','宋诗','song-poetry','','[]','一載爲官憂，文書每壓頭。',48,'全唐诗/poet.song.193000.json','["一載爲官憂，文書每壓頭。", "枕鈴常警夜，築甬更驚秋。", "倦豈因心至，閒常與病謀。", "息肩僅旬耳，二豎欲何求。"]'),
('c91f5c04-1ffd-464b-bb05-2cf39aa20fba','病中有感四首  其三','岳珂','宋','宋诗','song-poetry','','[]','秋近夜初長，開窗病骨涼。',48,'全唐诗/poet.song.193000.json','["秋近夜初長，開窗病骨涼。", "心驚嫠婦嘆，肘繫越人方。", "動帳風侵几，窺簷月在床。", "呼僮然粥鼎，我欲待晨光。"]'),
('64aff8ef-2a5d-4ad4-9c22-7c87d1fd7b58','病中有感四首  其四','岳珂','宋','宋诗','song-poetry','','[]','積病漸成衰，情知老見欺。',48,'全唐诗/poet.song.193000.json','["積病漸成衰，情知老見欺。", "眵昏先掩卷，肩竦不關詩。", "行圃須人助，登樓怯步遲。", "經年早知倦，况復隔年時。"]'),
('132e51e5-57a2-45a1-9aa5-f37b947b2149','太行道','岳珂','宋','宋诗','song-poetry','','[]','太行羊腸坂九折，雲黑風乾尺深雪。',192,'全唐诗/poet.song.193000.json','["太行羊腸坂九折，雲黑風乾尺深雪。", "堇泥道滑木葉寒，轆轆車聲行復歇。", "華山有馬久脫轅，歸來牧野經幾年。", "一從倉箱事居積，聊以知道煩長鞭。", "前車已覆覆道左，天井關頭夜明火。", "後車趣駕開井陘，唱籌仍復催連營。", "關山青草春二月，單軌一冬曾結轍。", "鬃頹毛落雙膊高，引領皮穿眼流血。", "去年搏手雙弮空，今年三月甬道同。", "可憐駑力不敢惜，轅下亦覺鹽車通。", "君恩天大示弗服，桃野已甘偕觳觫。", "感恩伏櫪飽秣芻，猶爲太行憂後車。"]'),
('ad1f75e8-924a-406e-b2b6-57ee25ebed83','長門怨','岳珂','宋','宋诗','song-poetry','','[]','驚風不成雨，行雲去無蹤。',192,'全唐诗/poet.song.193000.json','["驚風不成雨，行雲去無蹤。", "妾生三十年，著籍長門宮。", "宮車轆轆春雷曉，明星初熒綠雲擾。", "增成丙舍爭迎鑾，惟有長門閉花鳥。", "黄門開玉匙，畫史圖蛾眉。", "金鋪振瓊鑰，玉秀生銅池。", "朝陽纔回金屋在，轉盼不堪人事改。", "入宮已作鄭袖啼，出塞那知延壽賣。", "花殘鳥語頻，長門春復春。", "花鳥易驚老，况復門內人。", "東風動地夜來惡，萬翠千紅繞簾幙。", "當熊自有匪石心，肯顧班姬秋扇薄。", "長門勿輕怨，視此篋中扇。", "白華兮綠衣，自古兮有之。"]'),
('0bf8576a-7bb1-4d01-b7c0-e572bcb0eae2','病中散步六絕  其一','岳珂','宋','宋诗','song-poetry','','[]','一年無病緣官事，一病兼旬爲燕居。',32,'全唐诗/poet.song.193000.json','["一年無病緣官事，一病兼旬爲燕居。", "自是素餐天所厭，可能豎子解乘除。"]'),
('7d05b35e-e44c-4940-be6e-cc196aed3d74','病中散步六絕  其二','岳珂','宋','宋诗','song-poetry','','[]','池上荷花綠浄時，岸頭楊柳插天垂。',32,'全唐诗/poet.song.193000.json','["池上荷花綠浄時，岸頭楊柳插天垂。", "倦翁縱步聊行散，早有龜魚聖得知。"]'),
('58523a56-02c1-4c3f-915b-26b780d02a07','病中散步六絕  其三','岳珂','宋','宋诗','song-poetry','','[]','朝隨粥鼎蟬腹潤，夜掩書帷鰥目眠。',32,'全唐诗/poet.song.193000.json','["朝隨粥鼎蟬腹潤，夜掩書帷鰥目眠。", "無奈暑威侵病骨，起來搔首斗垂天。"]'),
('3a87f3d2-0624-479e-9064-739b090342b5','病中散步六絕  其四','岳珂','宋','宋诗','song-poetry','','[]','平頭奴子初茸鹿，利口嗇夫雙部蛙。',32,'全唐诗/poet.song.193000.json','["平頭奴子初茸鹿，利口嗇夫雙部蛙。", "二物何關人靜躁，不妨卧聽步隨車。"]'),
('71b1d92d-6167-4276-953c-a487fb9002fb','病中散步六絕  其五','岳珂','宋','宋诗','song-poetry','','[]','病疎酒醆傍茶甌，一獨醒中起百憂。',32,'全唐诗/poet.song.193000.json','["病疎酒醆傍茶甌，一獨醒中起百憂。", "七尺之軀三寸舌，問渠小大若爲謀。"]'),
('c8e4a537-706e-463e-9edb-d981706e6151','病中散步六絕  其六','岳珂','宋','宋诗','song-poetry','','[]','絕憐倦翼晚風高，解紲歸來得故巢。',32,'全唐诗/poet.song.193000.json','["絕憐倦翼晚風高，解紲歸來得故巢。", "物態隨人也歡喜，遊絲不住舞蠨蛸。"]'),
('d2797b56-1189-441e-bd52-dbbbe3584b88','夜觀象弈','岳珂','宋','宋诗','song-poetry','','[]','青燈相對夜初闌，適意棋枰伴我閒。',64,'全唐诗/poet.song.193000.json','["青燈相對夜初闌，適意棋枰伴我閒。", "天馬輜車金象國，虛龍縞襪寶臺山。", "進趨自可覘成敗，倖勝何嘗不往還。", "一著未容回局勢，不妨袖手酒杯間。"]'),
('d063fb27-b191-4914-a255-09f9450768d8','唐世有刺郡江表者時宰囑以新淦出筆令製以寄刺史始至召佳手一老父應命百日而得二管馳貢相府一見已訝其遲且鮮試之乃絕不堪大怒曰數千里乃寄兩管惡筆來刺史聞之懼欲寘老父於罪老父訴曰使君毋草草我所製乃歐褚所用丐先示以相君翰墨容再製苟不稱甘鼎鑊遂示之慨然曰如此只消使君三十錢筆不日獻五十管暨再使至長安相一試大喜復書令優賜匠者夜窗偶試毘陵張顥筆戲爲之賦','岳珂','宋','宋诗','song-poetry','','[]','世間未必無臯夔，九疑虞舜不可追。',285,'全唐诗/poet.song.193000.json','["世間未必無臯夔，九疑虞舜不可追。", "武皇銳意開絕漠，推鋒乃亦有衛霍。", "嗟哉格物本一理，顧人所用何如耳。", "筆工在昔本市傭，束毫傳筦求售同。", "誰云進技不進道，意匠輒與歐褚通。", "虔州刺史募佳筆，雙筦何堪須百日。", "星馳一騎到長安，試手鳳池隨弃擲。", "老奴恂慄丞相嗔，能用此筆能幾人。", "願窺翰墨減工製，必使揮毫誇入神。", "斗杓春回開電笑，橐籥果符人所料。", "中山聚族儻未殫，束帛那容及年少。", "是知人才用舍別識惟一心，皋夔衛霍無古今。", "妍媸能否俱在上所使，此筆區區正其比。", "我生識字僅一丁，眼前所見徒毘陵。", "未知當年新淦果何若，正恐鍾衛二王無合作。", "君不見此老一去知幾年，當時鑒裁無復傳。", "紛紛雞毛抱筩賣，恰費書傭三十錢。"]'),
('27fa751a-2bb0-4d8e-8d61-9fb44f942f3c','蒲萄','岳珂','宋','宋诗','song-poetry','','[]','當年博望奏邊功，異種曾携苜蓿同。',64,'全唐诗/poet.song.193000.json','["當年博望奏邊功，異種曾携苜蓿同。", "摘乳那煩挏馬令，引鬚聊愜好龍公。", "頗憐漢地離宮在，未許涼州酒甕空。", "回紇祇今重餧肉，清陰彌望滿關中。"]'),
('73901095-9d27-429f-93e6-13a31c88cd7b','荷花盛開以病旬餘不至亭上偶成二唐律  其一','岳珂','宋','宋诗','song-poetry','','[]','病襟傭策杖，天鏡恰開奩。',48,'全唐诗/poet.song.193000.json','["病襟傭策杖，天鏡恰開奩。", "青蓋迷前浦，紅粧間曲簷。", "藻窺知鷺下，萍破識魚潛。", "會看吳公陣，宮蛙奏曉嚴。"]'),
('e67aecfc-661a-48f6-8bd0-d0757c8c9d54','荷花盛開以病旬餘不至亭上偶成二唐律  其二','岳珂','宋','宋诗','song-poetry','','[]','好在中孚澤，猶橫未濟舟。',48,'全唐诗/poet.song.193000.json','["好在中孚澤，猶橫未濟舟。", "擲金隨柳舞，跳玉趁蓮謳。", "埽榻方思士，鈎簾也覓侯。", "病夫均一笑，此意本無求。"]'),
('7ddf8023-b274-4d6c-8030-c6769cb980cd','予歸未省松楸將以初秋望前汎湖之龍門已戒舟艦而連夕雨作不見月因賦天問二章  其一','岳珂','宋','宋诗','song-poetry','','[]','擬放平湖月下船，櫂歌中夕發長川。',64,'全唐诗/poet.song.193000.json','["擬放平湖月下船，櫂歌中夕發長川。", "蘋風好爲雲開幕，蘭槳不妨人扣舷。", "猨鶴候迎將曉日，魚龍悲嘯未晴天。", "玉川塌額金沙上，閶闔封詞漫一牋。"]'),
('14ae84f0-aa9a-40bc-b933-191858116380','予歸未省松楸將以初秋望前汎湖之龍門已戒舟艦而連夕雨作不見月因賦天問二章  其二','岳珂','宋','宋诗','song-poetry','','[]','小心風伯紫宮回，眼看銀蟾海上來。',64,'全唐诗/poet.song.193000.json','["小心風伯紫宮回，眼看銀蟾海上來。", "玄豹又成漫谷霧，斷虹猶作隠山雷。", "便教雨積三時害，未信晴無一日開。", "待試平生補天手，爲君明鏡再安臺。"]'),
('fcb411b2-e6e5-45c9-8bc9-10f81f19bf08','秋夕有感二首  其一','岳珂','宋','宋诗','song-poetry','','[]','早歲驪車擁漢關，憂心耿耿日凋顔。',64,'全唐诗/poet.song.193000.json','["早歲驪車擁漢關，憂心耿耿日凋顔。", "秋成正望狼烽急，夜枕不禁魚目鰥。", "三仕古猶關喜慍，萬金今不博安閒。", "回思此日一尊酒，只合長居木雁間。"]'),
('8579178e-2ca3-4c9d-a84b-c27f65d757e3','秋夕有感二首  其二','岳珂','宋','宋诗','song-poetry','','[]','從來難辨是幾微，談者雖多覺者希。',64,'全唐诗/poet.song.193000.json','["從來難辨是幾微，談者雖多覺者希。", "小隙便須防蟻穴，大寒何必泣牛衣。", "無旁掣肘方成事，不早抽頭即禍機。", "莫道不才明主棄，也曾攖頷觸天威。"]'),
('4e4e6d7c-1ed2-45eb-9c2f-0fb8f873ad71','寄李微之秘監三首  其一','岳珂','宋','宋诗','song-poetry','','[]','引領蓬萊唐謫仙，湓江一別又經年。',64,'全唐诗/poet.song.193000.json','["引領蓬萊唐謫仙，湓江一別又經年。", "麟臺高躡三神路，狐筆方持千載權。", "罏裊新煙招我隠，驛催逸事仗誰傳。", "校旗猶識臨淮略，更待涼臺親簡編。"]'),
('88d08a8f-d10d-4bf6-85ea-2ec007ff1704','寄李微之秘監三首  其二','岳珂','宋','宋诗','song-poetry','','[]','去冬雪裏拜箋題，曾說新除到殿西。',64,'全唐诗/poet.song.193000.json','["去冬雪裏拜箋題，曾說新除到殿西。", "劍棧雲連吳壘火，函關日照漢封泥。", "剡藤幸有繫書雁，錦柏難尋隔葉鸝。", "便是韓壇作曾築，田蕪亦盍賦歸兮。"]'),
('cb6107ce-6be3-4874-8c0d-a6149f3e75dc','寄李微之秘監三首  其三','岳珂','宋','宋诗','song-poetry','','[]','棠湖浩蕩有盟鷗，塞上歸來賦葉舟。',64,'全唐诗/poet.song.193000.json','["棠湖浩蕩有盟鷗，塞上歸來賦葉舟。", "范蠡功名付西子，庾公風月自南樓。", "不虞繞指柔百鍊，已幸安心老一丘。", "從此書來訪生死，漢陽煙樹隔吳頭。"]'),
('25ca1097-3609-4225-84fe-cb15f94f371b','讀劉琨傳','岳珂','宋','宋诗','song-poetry','','[]','古來萬事無真實，頼有區區史筆存。',32,'全唐诗/poet.song.193000.json','["古來萬事無真實，頼有區區史筆存。", "士雅聞雞偶同被，至今起舞說劉琨。"]'),
('f88cf173-59a3-4f03-aa12-2bb20c8bc012','送喬江州將漕江右  其一','岳珂','宋','宋诗','song-poetry','','[]','獵獵英聲世少雙，兩年鄉國望麾幢。',64,'全唐诗/poet.song.193000.json','["獵獵英聲世少雙，兩年鄉國望麾幢。", "才猷牛蔡硎初試，筆力龍文鼎獨扛。", "風節又新唐十道，恩波仍浹禹三江。", "澄清何事先經濟，尚使尊賢志未降。"]'),
('f27011d1-0cf7-49ae-86aa-390c7e4a1b94','送喬江州將漕江右  其二','岳珂','宋','宋诗','song-poetry','','[]','昔日東州看陣圖，武昌陸續拜魚書。',64,'全唐诗/poet.song.193000.json','["昔日東州看陣圖，武昌陸續拜魚書。", "我歸舊齒邦人版，公去新乘使者車。", "但願世官居鼎鼐，從教野老自犁鋤。", "西風鴻雁方遵渚，時有音塵接里廬。"]'),
('e1f62c0c-2dfd-4458-b136-0192f835da1a','次韻喬江州琵琶亭詩二首  其一','岳珂','宋','宋诗','song-poetry','','[]','共生壬子兩仙翁，不爲離春惜斷蓬。',64,'全唐诗/poet.song.193000.json','["共生壬子兩仙翁，不爲離春惜斷蓬。", "鐵撥鵾絃遺響在，繡衣龍節賞音同。", "穆曹技埒名俱勝，唐宋詩傳句並工。", "擊節雲篦定誰是，茫茫江月思何窮。"]'),
('277e7fad-b4e4-4210-88fb-2b391094799f','次韻喬江州琵琶亭詩二首  其二','岳珂','宋','宋诗','song-poetry','','[]','一葉西歸老倦翁，高樓突兀記推蓬。',64,'全唐诗/poet.song.193000.json','["一葉西歸老倦翁，高樓突兀記推蓬。", "景隨湓浦江山改，人與香山歲月同。", "異世剖符傳事比，出門合轍見詩工。", "我來君去如鴻燕，休歎長安目力窮。"]'),
('9ea417bb-a6f3-47b2-bb8d-a454abdee61c','聞江陵江帥海病訃二首  其一','岳珂','宋','宋诗','song-poetry','','[]','陷陣搴旗久冠軍，兩年爲國守西門。',64,'全唐诗/poet.song.193000.json','["陷陣搴旗久冠軍，兩年爲國守西門。", "枕戈常抱填膺憤，鑄印方承繫肘恩。", "汗馬策功雖屢奏，寢蛟遺恨正須論。", "尺緘一介纔經月，寂寞英聲已九京。"]'),
('d83c39c9-5ddb-4a61-b4ae-8d5796c34914','聞江陵江帥海病訃二首  其二','岳珂','宋','宋诗','song-poetry','','[]','荆楚初歸士若雲，連營幾載守空囷。',64,'全唐诗/poet.song.193000.json','["荆楚初歸士若雲，連營幾載守空囷。", "度支入境方移粟，神策呼街自脫巾。", "我已課無從此有，君方舉故責之新。", "可憐一夜妖星隕，不見春耕雜渭濱。"]'),
('a495698b-3f9e-4b72-82c1-2fe4149939b5','得陳元履家書六言四首  其一','岳珂','宋','宋诗','song-poetry','','[]','病骨經秋易怯，人情比日多疎。',28,'全唐诗/poet.song.193000.json','["病骨經秋易怯，人情比日多疎。", "驚起打門軍將，傳來置驛家書。"]'),
('21826d83-dcf4-4963-b70b-c7849eee1b62','得陳元履家書六言四首  其二','岳珂','宋','宋诗','song-poetry','','[]','老病兩無世用，謀謨百不如人。',28,'全唐诗/poet.song.193000.json','["老病兩無世用，謀謨百不如人。", "喜見東床論事，誰言下榻生塵。"]'),
('03136d24-035a-40c1-904c-513fbb35cbd8','得陳元履家書六言四首  其三','岳珂','宋','宋诗','song-poetry','','[]','安問經時落落，邊聲鎮日摇摇。',28,'全唐诗/poet.song.193000.json','["安問經時落落，邊聲鎮日摇摇。", "寄賀塞翁馬失，决疑天老龜焦。"]'),
('9faf9ab1-f079-4ad1-a9b5-c4fd961c9e5d','得陳元履家書六言四首  其四','岳珂','宋','宋诗','song-poetry','','[]','窺戶幾回鵲喜，繞階一夜蛩吟。',28,'全唐诗/poet.song.193000.json','["窺戶幾回鵲喜，繞階一夜蛩吟。", "痛飲政須似舊，安居且願如今。"]'),
('8fe98390-eb2e-49fd-9b15-1580fccdb1d6','觀物四首 蛩','岳珂','宋','宋诗','song-poetry','','[]','春蠶繰繭白如霜，機婦停機待天涼。',64,'全唐诗/poet.song.193000.json','["春蠶繰繭白如霜，機婦停機待天涼。", "井蛩一夜秋已至，寸絲千結縈柔腸。", "催租吏囂翁媼怒，裘葛未成心轉苦。", "篝燈促織永夜忙，悔殺比隣日長語。"]'),
('e818b091-4ab7-4c32-ad6f-94b32195e59e','觀物四首 蛙','岳珂','宋','宋诗','song-poetry','','[]','鳴蛙恰恰地底鳴，池泉深澈池草青。',64,'全唐诗/poet.song.193000.json','["鳴蛙恰恰地底鳴，池泉深澈池草青。", "秧田正枯須水活，龍骨車翻蛙不驚。", "在池固合憂涸鮒，鼓吹未妨明月步。", "可憐强聒將何爲，到底官私不關汝。"]'),
('6caa423a-ccfb-405c-a4d3-c06c24ca4454','觀物四首 蟬','岳珂','宋','宋诗','song-poetry','','[]','亂蟬凄咽下復高，逢秋輒作升木號。',64,'全唐诗/poet.song.193000.json','["亂蟬凄咽下復高，逢秋輒作升木號。", "老夫觸熱思靜卧，夕陽畏見聲嘈嘈。", "客來畫冊誇莫二，伐木驅蟬蟬不至。", "不辭來歲無繁陰，正恐先爲斧斤費。"]'),
('d24a5301-5a77-4bf1-bfdd-d13174a8b397','觀物四首 蚊','岳珂','宋','宋诗','song-poetry','','[]','嗇夫利口工噬膚，纖腰蠆尾不受驅。',64,'全唐诗/poet.song.193000.json','["嗇夫利口工噬膚，纖腰蠆尾不受驅。", "不知一噤何所苦，拍拍攘攘歌且呼。", "清晨出帷晝藏隙，正是袢蒸炎暑日。", "但願涼風即日來，且爲蒼生膏血惜。"]'),
('13a272a6-df83-4a3b-9d19-ce9843395c25','紫微花','岳珂','宋','宋诗','song-poetry','','[]','凡卉同資造化工，紫微元不待東風。',64,'全唐诗/poet.song.193000.json','["凡卉同資造化工，紫微元不待東風。", "明霞絢爛瓊爲蕊，曉日離披綺作叢。", "塵境斷無青瑣隔，仙姿元與赤城通。", "最憐耐久堪承露，誰道花無百日紅。"]'),
('06b2181a-12ec-466b-8d80-6c8e593d76a3','新刊予西陲奏藁成','岳珂','宋','宋诗','song-poetry','','[]','昔人甫徹棄芻狗，此日已歸談木牛。',64,'全唐诗/poet.song.193000.json','["昔人甫徹棄芻狗，此日已歸談木牛。", "報國無階空馬革，託身有地早菟裘。", "乘車載苡纔經謗，三宿戀桑真可羞。", "掩卷勿驚臣議戇，舜瞳應顧殿西頭。"]'),
('c11f248c-3d45-49f0-99cd-5f3a04b10141','閒居六詠 早起','岳珂','宋','宋诗','song-poetry','','[]','五夜玉繩轉，雙轤金井寒。',48,'全唐诗/poet.song.193000.json','["五夜玉繩轉，雙轤金井寒。", "背人蚊作市，欺夢蟈鳴官。", "竹逕風初度，松梢月尚團。", "踞龜猶汗漫，何計覓乘鸞。"]'),
('1fb02c50-b495-4b96-905b-b3ddab117d4d','閒居六詠 午睡','岳珂','宋','宋诗','song-poetry','','[]','東日平明際，北窗高卧時。',48,'全唐诗/poet.song.193000.json','["東日平明際，北窗高卧時。", "五經方坦腹，百慮且伸眉。", "蕉覆從疑鹿，槐安更獵龜。", "覺來還一莞，七椀玉川詩。"]'),
('ba99062f-28f7-4c16-be43-63c581708868','閒居六詠 晝閒','岳珂','宋','宋诗','song-poetry','','[]','用關無用地，才與不才間。',48,'全唐诗/poet.song.193000.json','["用關無用地，才與不才間。", "萬法因心起，幾人如我閒。", "床頭看黄卷，屋外儘青山。", "隠几逌然笑，何人戰觸蠻。"]'),
('3edb8d9f-a908-43f9-8cd7-5d7fae437caf','閒居六詠 晡飲','岳珂','宋','宋诗','song-poetry','','[]','閒居欣少事，燕坐覺無營。',48,'全唐诗/poet.song.193000.json','["閒居欣少事，燕坐覺無營。", "炎暑鏖天陣，驅除須酒兵。", "勿嫌晡日杲，自有晚風清。", "堪笑竹中飲，終成七子名。"]'),
('128a4ee0-3975-43ee-b466-89bc370140e6','閒居六詠 晚步','岳珂','宋','宋诗','song-poetry','','[]','抱病游從少，居閒醉醒頻。',48,'全唐诗/poet.song.193000.json','["抱病游從少，居閒醉醒頻。", "心懷喜無事，脚力尚隨人。", "野徑經行地，園亭自在身。", "不妨歸步晚，長趁月華新。"]'),
('a3ae494e-fbe4-4724-b0b3-3f9b9f9c281e','閒居六詠 夜坐','岳珂','宋','宋诗','song-poetry','','[]','一窗涼浸月，四壁息聞雷。',48,'全唐诗/poet.song.193000.json','["一窗涼浸月，四壁息聞雷。", "銅漏水仍滴，金爐香未灰。", "徘徊聽蛩遠，熠燿逐螢來。", "看劍挑燈久，譙城角引梅。"]'),
('9f734fa1-dab5-411a-b303-5ba6d42fcfc5','予自武昌携二猿歸夜聞清嘯偶成','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','樂天聽琵琶，嘗賦猿哀鳴。',240,'全唐诗/poet.song.193000.json','["樂天聽琵琶，嘗賦猿哀鳴。", "物産無古今，均此潯陽城。", "我居廬山趾，日夕游郊坰。", "步足歷幽谷，登山窮絕陘。", "經行徧巖岫，未始聞此聲。", "相望三百年，山水同虞衡。", "詎可風氣殊，乃亦殊所生。", "矯矯長臂公，相從東歸舲。", "皎皎白玉面，玄衣吟嘯清。", "綫垂黄金衣，詭侍誇異形。", "不繫李約鐵，悲風動南𤃩。", "不把碧玉環，峽山棲杳冥。", "楚賓攀樹枝，腸斷不堪聽。", "變化倏異塗，更作巴西稱。", "突兀見眼前，兒童不知名。", "西軒驟雨過，東牖初月明。", "循階聞夜蛩，有酒仍獨傾。", "忽聞湘水吟，頓覺凄然驚。", "吾方笑樂天，爲此外物攖。", "反觀還自笑，翁倦非忘情。"]'),
('95dc1788-1696-4c66-85b5-5d779037d043','小閣後薙草','岳珂','宋','宋诗','song-poetry','','[]','當暑涼風愜北窗，半庭蒿棘礙支床。',64,'全唐诗/poet.song.193000.json','["當暑涼風愜北窗，半庭蒿棘礙支床。", "無花可繼陳朝曲，有草已成陶徑荒。", "幸可一縑供廐櫪，便容四坐接盃觴。", "醉歌家有秦聲妓，且爲治蕪一奮卬。"]'),
('7512c16d-8eb2-4124-b117-66d324e21e83','賀李微之兼工侍二首  其一','岳珂','宋','宋诗','song-poetry','','[]','奎章夜下九重天，雍乘疇咨法從賢。',64,'全唐诗/poet.song.193000.json','["奎章夜下九重天，雍乘疇咨法從賢。", "紀雉重開五工正，止麟還見一經傳。", "紫荷佩袷新簪橐，青汗磨鉛舊簡編。", "便合史筵尊領袖，紅雲堆裏望台躔。"]'),
('778d38af-20a6-490d-92a0-58cab7a5b329','賀李微之兼工侍二首  其二','岳珂','宋','宋诗','song-poetry','','[]','當時邛蜀起徵君，褒貶春秋頼洽聞。',64,'全唐诗/poet.song.193000.json','["當時邛蜀起徵君，褒貶春秋頼洽聞。", "又見璧跗攽異數，要令金匱闡斯文。", "魚鳬西隔一隅地，龍馬南來四世勳。", "陳古鑑今皆實蹟，論思亟願張吾軍。"]'),
('0c5215ac-f315-4a54-ae8e-d495e82ab119','賀高中書兼崇政殿說書三首  其一','岳珂','宋','宋诗','song-poetry','','[]','谹議通三府，高名動四聰。',48,'全唐诗/poet.song.193000.json','["谹議通三府，高名動四聰。", "鳳池仍舊渥，虎觀冊新功。", "晝日槐方翠，秋風棗已紅。", "直須先抗議，莫待入雲中。"]'),
('cf7f328c-3b64-4532-ba82-77616b3b71e4','賀高中書兼崇政殿說書三首  其二','岳珂','宋','宋诗','song-poetry','','[]','日月熙明地，風雲際會辰。',48,'全唐诗/poet.song.193000.json','["日月熙明地，風雲際會辰。", "紫宮瞻象逼，丹扆喜情親。", "遜志賢謨在，仔肩聖德新。", "耕莘須負鼎，從此學商臣。"]'),
('f0c5847a-1e2a-47a1-a6c0-d082907066c3','賀高中書兼崇政殿說書三首  其三','岳珂','宋','宋诗','song-poetry','','[]','邇聯咨夕訪，清問切辰猷。',48,'全唐诗/poet.song.193000.json','["邇聯咨夕訪，清問切辰猷。", "博學今中壘，遐征古上遊。", "齒寒當預計，身履即良籌。", "頗牧豈云遠，隠憂其有瘳。"]'),
('d8d98d9a-ba65-4761-b86b-e87a866eb8bc','觀八陣圖說  其一','岳珂','宋','宋诗','song-poetry','','[]','八陣初興黄帝時，貙劉在漢紀乘之。',64,'全唐诗/poet.song.193000.json','["八陣初興黄帝時，貙劉在漢紀乘之。", "流形龍虎隨雷雨，定位鳥蛇分坎離。", "地以雲升高復下，天從風別正之奇。", "自然至理開成象，一氣未應虛艮維。"]'),
('43d946be-44ac-4f38-bc77-daa114c066d3','觀八陣圖說  其二','岳珂','宋','宋诗','song-poetry','','[]','天分三百六十度，巧歷難窺本在奇。',64,'全唐诗/poet.song.193000.json','["天分三百六十度，巧歷難窺本在奇。", "萬世機緘發龍卧，六軍偏伍漫魚麗。", "常山變化徒言用，斜谷崎嶇不遇時。", "積石平沙人不識，儘從靺鞨說行師。"]'),
('8f40093d-6e18-4b60-aa85-e0f2de1ca522','張孝顯晨訪懋忠堂因拉陳升可王囦道同飲徑醉卧小閣醒則晡矣戲呈諸公','岳珂','宋','宋诗','song-poetry','','[]','凌晨有客來款門，盥櫛下榻呼冠巾。',192,'全唐诗/poet.song.193000.json','["凌晨有客來款門，盥櫛下榻呼冠巾。", "怪生鵲喜繞庭樹，迎客不但填河津。", "清尊湛湛開北牖，頤指市奴駿奔走。", "烹鮮煮餠羅朝槃，苜蓿闌干豈無有。", "一杯兩杯叱先驅，羣羊入夢撞甕菹。", "三杯四杯舌底滑，闔坐牢辭輒投轄。", "共言卯飲夕不同，能使終日長冬烘。", "一朝便廢一日事，除却投床百無技。", "老夫笑倒絕冠纓，人生無日無經營。", "經營至竟有底成，謹閟此舌君勿評。", "直須大噭五六七，不醉不扶毋返室。", "高眠一枕醉復醒，莫管今朝更明日。"]'),
('93a67039-4d0c-4fc1-8c99-9350c8a38d1d','吳季謙侍郎送家釀香泉絕無灰得未曾有戲成報章','岳珂','宋','宋诗','song-poetry','','[]','義豐愛酒憎官壺，日長忍渴呼酪奴。',339,'全唐诗/poet.song.193000.json','["義豐愛酒憎官壺，日長忍渴呼酪奴。", "自言畏灰如畏虎，有酒不向官坊酤。", "當家香泉世無比，米潔麯甘醇且美。", "釀時不著一點灰，滿酌寒泉挹清泚。", "小槽滴瀝竹筧承，冰渠夜濺真珠明。", "一泓澄澈玉無底，滿甕盎盎春風生。", "釀成不肯飲俗客，澆著柴桑舊時宅，共此千年醉眠石。", "更將餘瀝走馬軍，來注吾家老瓦盆，許我自飲不許分。", "老境宦游環軌轍，官酒徧嘗隨地別，何曾見灰能作孽。", "饑來一腹大於蟬，鯨呿自覺吸百川。", "是灰是酒俱不辨，豈問他州并異縣。", "今夕何夕翻露漿，扣壺一洗灰土腸。", "君不見柴桑于酒特寓意，相逢不擇賤與貴，要是醇醨均一致。", "汝陽後來帝家子，路逢麴車不知味，流涎正復何所謂。", "貧爲田舍富天宗，遇酒隨飲莫適從。", "豈如仙家居義豐，無懷自與造化通。", "彼燧人氏初何功，酬君三語將無同。", "同不同，君信否。", "黄花飄香石耐久，明日山行且携酒。"]'),
('d311e98d-5dda-44e9-a40b-6e72a3ff775e','珊瑚','岳珂','宋','宋诗','song-poetry','','[]','銅柯凝異質，鐵網隊層淵。',48,'全唐诗/poet.song.193000.json','["銅柯凝異質，鐵網隊層淵。", "海霧夜涵潤，山霞朝欲然。", "綠鬟尚欹枕，烏帽稱鳴鞭。", "勿爲毛錐子，日興靡萬錢。"]'),
('baed8a6e-c6f3-4cf0-90be-2ca9cceb1561','無題','岳珂','宋','宋诗','song-poetry','','[]','秋水芙蓉試早粧，半軒微雨灑鴛鴦。',64,'全唐诗/poet.song.193000.json','["秋水芙蓉試早粧，半軒微雨灑鴛鴦。", "細腰正欠酬金餠，奮翼何堪卸玉梁。", "髮鬒釵橫人在牖，繩低斗轉月侵床。", "無情花影雲來去，都做一天風露涼。"]'),
('17c79e2a-3fb5-4173-80a4-0090e4e6165d','得報狀邸吏緘至朝堂八月月單有感而作三首  其一','岳珂','宋','宋诗','song-poetry','','[]','紫殿朝儀正，朱書郡邸隨。',48,'全唐诗/poet.song.193000.json','["紫殿朝儀正，朱書郡邸隨。", "九天排仗馬，百辟聽朝雞。", "蹕警楓庭悄，人歸柳院迷。", "廿年曾襆被，猶憶直金閨。"]'),
('e52e6fbb-ddde-4874-9a1b-5b0f001042d8','得報狀邸吏緘至朝堂八月月單有感而作三首  其二','岳珂','宋','宋诗','song-poetry','','[]','十月蒼龍闕，三朝白虎樽。',48,'全唐诗/poet.song.193000.json','["十月蒼龍闕，三朝白虎樽。", "無囊持塞吏，有匭達民言。", "故事尋常略，遺風萬一存。", "獨憐記廷諍，斷報說開元。"]'),
('bb35e15c-e60b-49c0-acc4-6ff57206ee0e','得報狀邸吏緘至朝堂八月月單有感而作三首  其三','岳珂','宋','宋诗','song-poetry','','[]','上雍迫日近，清朝儀物多。',48,'全唐诗/poet.song.193000.json','["上雍迫日近，清朝儀物多。", "衛官朝進輦，沙路晝鳴珂。", "盛禮陳圭璧，駢觀隘綺羅。", "邊書須急徹，深願鑒□□。"]'),
('92bb428c-8b97-40c1-8763-d8145a0eb655','憶昔二首  其一','岳珂','宋','宋诗','song-poetry','','[]','憶昔紹興際，垂髫游上都。',48,'全唐诗/poet.song.193000.json','["憶昔紹興際，垂髫游上都。", "舜廊時訪道，禹殿日陳謨。", "士肄幾三代，兒嬉徧九衢。", "謏聞仍有幸，猶及拜先儒。"]'),
('ec62b6c8-623d-4a86-ae5d-f987f942d082','憶昔二首  其二','岳珂','宋','宋诗','song-poetry','','[]','升平當暇歲，遐邇屢豐年。',48,'全唐诗/poet.song.193000.json','["升平當暇歲，遐邇屢豐年。", "環轍道萬里，軺車開兩川。", "干戈今滿地，劍棧漫梯天。", "試向長淮望，馮高更憮然。"]'),
('379e8862-4aa4-443a-94f2-33238115e820','聞陳元履除諸軍審計司','岳珂','宋','宋诗','song-poetry','','[]','老去獃衫合付人，除書一昔到柴門。',64,'全唐诗/poet.song.193000.json','["老去獃衫合付人，除書一昔到柴門。", "無才空負凝旒眷，有壻初承結綬恩。", "未辦功名酬父祖，併將佔畢付兒孫。", "幸然官事渠能了，且注田家老瓦盆。"]'),
('9e1997eb-3ea6-4700-8963-2179a66bea06','胡羊二首  其一','岳珂','宋','宋诗','song-poetry','','[]','生與氈裘並，衣同罽毯齊。',48,'全唐诗/poet.song.193000.json','["生與氈裘並，衣同罽毯齊。", "引弓兒習體，擊鼓地連臍。", "低草野迷北，驚群磧度西。", "中郎猶未返，休說海邊羝。"]'),
('a0e6203f-547e-4d96-a9af-90017608760d','胡羊二首  其二','岳珂','宋','宋诗','song-poetry','','[]','䢇毛吹朔雪，細肋卧晴沙。',48,'全唐诗/poet.song.193000.json','["䢇毛吹朔雪，細肋卧晴沙。", "曉牧尾摇扇，春游項引車。", "湩流便逐草，酪膩正需茶。", "日夕歸棲處，因風想塞笳。"]'),
('ba7c50f0-f1d2-495b-b24f-864a6bdda602','饅頭','岳珂','宋','宋诗','song-poetry','','[]','幾年太學飽諸儒，餘伎猶傳笋蕨厨。',64,'全唐诗/poet.song.193000.json','["幾年太學飽諸儒，餘伎猶傳笋蕨厨。", "公子彭生紅縷肉，將軍鐵杖白蓮膚。", "芳馨政可資椒實，粗澤何妨比瓠壺。", "老去齒牙辜大嚼，流涎聊合慰饞奴。"]'),
('0176b93a-1c81-4dd5-8a98-4b3b72bb3ce0','小墅桂花盛開與客醉樹下因賦二律  其一','岳珂','宋','宋诗','song-poetry','','[]','舊游曾賦小山篇，浪蕊浮葩總遜妍。',64,'全唐诗/poet.song.193000.json','["舊游曾賦小山篇，浪蕊浮葩總遜妍。", "金粟同瞻黄面老，玉枝爭擁碧霞仙。", "化身瑞相已百億，匝地香風更大千。", "無量現前金世界，倦翁又結醉中緣。"]'),
('65cbf143-6e7c-4661-a2ec-e7af163ca003','小墅桂花盛開與客醉樹下因賦二律  其二','岳珂','宋','宋诗','song-poetry','','[]','黄金湧出碧檀欒，消得充庭舞廣寒。',64,'全唐诗/poet.song.193000.json','["黄金湧出碧檀欒，消得充庭舞廣寒。", "露蕊移將天上種，雲階借與月中看。", "扶疎清影立黄鵠，匼匝滿庭翔翠鸞。", "吹徹玉笙正涼透，香風萬斛夜漫漫。"]'),
('23d48279-f325-4a86-ace9-a6ae6e1b52c8','雨中觀廬山  其一','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雨裏觀山夐不同，何須九疊看屏風。',64,'全唐诗/poet.song.193000.json','["雨裏觀山夐不同，何須九疊看屏風。", "紫觚壇上排蒼璧，青步障邊鋪翠茸。", "谷錦未迴晴日照，衣綃聊借淡煙籠。", "祇今萬木添紅纈，更倩青霜染曉楓。"]'),
('cffc72e1-f714-47db-8756-c711b0fbb922','雨中觀廬山  其二','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','半生每負看山眼，此日真成带雨遊。',64,'全唐诗/poet.song.193000.json','["半生每負看山眼，此日真成带雨遊。", "欹枕有無疑欲暮，成峰橫側總宜秋。", "耳喧似厭泉嗚咽，腰繫不妨雲去留。", "明日新晴馬蹄放，直須三峽看龍湫。"]'),
('b042d1b1-d93c-48a9-887e-3b9b5e80fb8c','約吳季謙山行書來問期戲答','岳珂','宋','宋诗','song-poetry','','[]','連朝積雨快新晴，雨後青山眼倍明。',64,'全唐诗/poet.song.193000.json','["連朝積雨快新晴，雨後青山眼倍明。", "大路岳蓮聊戲馬，西園池柳正啼鶑。", "已拚一醉從金諾，共聽層淵噴玉聲。", "月裏看山儘清絕，可憐偏照國西營。"]'),
('88d13084-b035-4bb9-8de3-d6ff999342c6','觀芙蓉有感','岳珂','宋','宋诗','song-poetry','','[]','芙蓉城邊觀芙蓉，開時淡白蔫深紅。',64,'全唐诗/poet.song.193000.json','["芙蓉城邊觀芙蓉，開時淡白蔫深紅。", "新晴著人過於酒，聊與老面回春風。", "少年白面豈長好，花落花開不知老。", "老來會有少年時，對酒不飲將何爲。"]'),
('d516b94c-e9ee-455a-b66a-40c28600deb3','邵伯溫聞見錄載范忠宣帥慶陽時總管种詁無故訟於朝上遣御史按治詁停任公亦罷帥至公爲樞密副使詁尚停任復薦爲永興軍路鈐轄又薦知隰州公每自咎曰先人與种氏上世有契義某不肖爲其子孫所訟寧論事之曲直哉予在山中讀書偶見此書而表之','岳珂','宋','宋诗','song-poetry','','[]','君不見孔融昔日見李膺，百世尚以通家稱。',198,'全唐诗/poet.song.193000.json','["君不見孔融昔日見李膺，百世尚以通家稱。", "又不見孔融後來薦鴻豫，卵翼方成比行路。", "北海平生開酒尊，未應賓客皆若人。", "倘令同德更比義，華胄肯以遥遥論。", "世間麟鳳雜梟虺，人事會逢總如此。", "高平丞相本大賢，尺璧那容寸瑕指。", "一朝契家青澗种，轉頭不記龍圖公。", "蟈鳴亂磬蠅點素，丞相襟量滄溟同。", "歸來端委廟堂上，一眚不捐三世將。", "自言曲直何必言，愧死老奴作何樣。", "吁嗟此輩何代無，高平堂堂真丈夫。", "邵家聞見訂千古，寂寞澗城墳上土。"]'),
('e4a7ce1e-afec-414d-a4eb-40e04b446ede','趙季茂通判惠詩走筆奉和十篇  其一','岳珂','宋','宋诗','song-poetry','','[]','病懶兩相宜，閒吟九日詩。',48,'全唐诗/poet.song.193000.json','["病懶兩相宜，閒吟九日詩。", "江山雖舊隠，泉石是新知。", "不分黄花老，從教烏帽吹。", "白衣渾未至，醒眼欲何爲。"]'),
('8881fa3d-289a-421a-b9d5-c0e04ee46559','趙季茂通判惠詩走筆奉和十篇  其二','岳珂','宋','宋诗','song-poetry','','[]','山行事事宜，酒興富於詩。',48,'全唐诗/poet.song.193000.json','["山行事事宜，酒興富於詩。", "雲錦工何用，風帘酒聖知。", "囊空須共賦，笛好愛孤吹。", "斟酌蒼茫咏，凭高漫爾爲。"]'),
('4a53fb83-400b-440b-aad7-c567cc7aaf2a','趙季茂通判惠詩走筆奉和十篇  其三','岳珂','宋','宋诗','song-poetry','','[]','晴佳雨亦宜，雲黑又催詩。',48,'全唐诗/poet.song.193000.json','["晴佳雨亦宜，雲黑又催詩。", "靜處景俱勝，閒中趣自知。", "攀條隨客嗅，卷葉看兒吹。", "世事只如此，吾今何所爲。"]'),
('e133207e-1a6d-4abb-a60b-747d3126554e','趙季茂通判惠詩走筆奉和十篇  其四','岳珂','宋','宋诗','song-poetry','','[]','落拓與閒宜，繙書更賦詩。',48,'全唐诗/poet.song.193000.json','["落拓與閒宜，繙書更賦詩。", "世方隨世競，吾自喜吾知。", "王褚齒猶冷，申韓毛必吹。", "蚩蚩天所畀，誰謂涉人爲。"]'),
('2fd13c64-0526-4c01-aae2-238eb6d8823d','趙季茂通判惠詩走筆奉和十篇  其五','岳珂','宋','宋诗','song-poetry','','[]','草堂無不宜，猶記樂天詩。',48,'全唐诗/poet.song.193000.json','["草堂無不宜，猶記樂天詩。", "尚有驚猿怨，莫教司馬知。", "上宮仙闕近，左蠡客帆吹。", "欲涉窮陘步，茲狂何悔爲。"]'),
('1859ebf5-c958-42b6-8bcb-dbfda882fdf5','趙季茂通判惠詩走筆奉和十篇  其六','岳珂','宋','宋诗','song-poetry','','[]','閒花取次宜，宜酒更宜詩。',48,'全唐诗/poet.song.193000.json','["閒花取次宜，宜酒更宜詩。", "葉落澗魚避，枝翻山鳥知。", "簪來擎雨重，摘處任風吹。", "得句須旬鍛，未應無所爲。"]'),
('763758c6-164e-40d8-8328-51afdb8b2a33','趙季茂通判惠詩走筆奉和十篇  其七','岳珂','宋','宋诗','song-poetry','','[]','醉裏筍輿宜，閒携一卷詩。',48,'全唐诗/poet.song.193000.json','["醉裏筍輿宜，閒携一卷詩。", "微吟因興寄，會意祇心知。", "谷霧連衣潤，天風带葉吹。", "卷窮還自笑，那復記誰爲。"]'),
('3fe4aaa7-7232-478a-ac57-6f6c2d910e17','趙季茂通判惠詩走筆奉和十篇  其八','岳珂','宋','宋诗','song-poetry','','[]','秋氣與人宜，山家物物詩。',48,'全唐诗/poet.song.193000.json','["秋氣與人宜，山家物物詩。", "題新興常倦，景好句先知。", "雲斷邊鴻信，天晴野馬吹。", "閒情君莫問，謀自不相爲。"]'),
('006bc9f1-4d2c-489d-a58c-f856fa132933','趙季茂通判惠詩走筆奉和十篇  其九','岳珂','宋','宋诗','song-poetry','','[]','天巧與天宜，雕鎪焉用詩。',48,'全唐诗/poet.song.193000.json','["天巧與天宜，雕鎪焉用詩。", "冥鴻吾自愛，隠豹彼何知。", "牧笛方堪聽，胡笳不奈吹。", "傷時燭之武，老矣不能爲。"]'),
('b6341cb1-1406-429e-823b-4519fb9ba004','趙季茂通判惠詩走筆奉和十篇  其一○','岳珂','宋','宋诗','song-poetry','','[]','置散分之宜，半生衡泌詩。',48,'全唐诗/poet.song.193000.json','["置散分之宜，半生衡泌詩。", "神情一無繫，山水兩相知。", "流詠雙魚寄，賞音孤竹吹。", "十篇聊報況，惟此尚堪爲。"]'),
('39241e50-f1d2-4f7f-bfbe-9c5d202f3618','己亥八月廿一日除書予拜太平興國宮祠官呈趙季茂','岳珂','宋','宋诗','song-poetry','','[]','世間何物最是閒，司諫拂衣歸華山。',134,'全唐诗/poet.song.193000.json','["世間何物最是閒，司諫拂衣歸華山。", "倦來忘記省不得，依約此語祥符間。", "終南捷徑本自錯，老子新司紫元鑰。", "官家雇我作閒人，有酒醉呼端不惡。", "歲糜廩粟月俸錢，豢鶴有料芝有田。", "人生何必待有用，我老得此寧非天。", "君不見當年把臂龍圖上，司諫放歸元未放。", "又不見倦翁山行醉復醒，說著拂衣今亦忘。"]'),
('27fddd91-12ee-40e6-ad5f-681f4f08ca8f','述山中語呈郡侯董庭直少監','岳珂','宋','宋诗','song-poetry','','[]','山行霜清羣木落，回首重雲望城郭。',192,'全唐诗/poet.song.193000.json','["山行霜清羣木落，回首重雲望城郭。", "城郭西畔江正橫，中有千騎隨雙旌。", "山頭一灣霜月明，旌底史君如許清。", "我行山間已一月，枕石潄流更奇絕。", "頗從野老談政聲，所恨輕爲數旬別。", "別來有書招我歸，我適把酒窮攀躋。", "相呼一醉已心許，野老來前聽我語。", "今年歲歉流離多，带牛佩犢無奈何。", "史君鎮靜不猛厲，使汝安卧仍行歌。", "山中故侯布鞋濕，杖掛百錢遺不拾。", "新來又拜散人呼，正好舉杯和月吸。", "我醉汝醉今頼誰，爲言野老知不知。"]'),
('7ac0dd6b-bc00-4ce1-b36e-bf40752a030a','奉寄何正父總幹','岳珂','宋','宋诗','song-poetry','','[]','經旬習懶慣山居，不寫城間一字書。',64,'全唐诗/poet.song.193000.json','["經旬習懶慣山居，不寫城間一字書。", "把菊見山新趣倦，汎蓮依水舊交疎。", "無心是處友麋鹿，有客寄誰烹鯉魚。", "見說近來軍食足，不妨詩卷訪犁鋤。"]'),
('75578d76-3943-487b-b98c-61c8fc398a63','奉寄胡教授','岳珂','宋','宋诗','song-poetry','','[]','山中秋風寒刮席，忽憶無氈泮宮客。',163,'全唐诗/poet.song.193000.json','["山中秋風寒刮席，忽憶無氈泮宮客。", "夜長螢火一燈孤，四壁蛩聲更幽寂。", "文人自古常獨清，强挽詩人同此盟。", "飯顆山頭報卓午，絳紗帳下聽三更。", "吾儕賦分本無二，老子新來添倦意。", "入山四旬未擬回，醉後行歌醒復醉。", "平生巖穴不作難，更願他人同此歡。", "廣文愛山儂等耳，雖有幽寂無儂閒。", "君不見晨招在館笑在列，楹杙昌苓競工拙。", "倦翁此事都不知，從今對酒看山嬉。"]'),
('284b2df2-29ef-4727-aa21-28adbfd8ed3d','山中奉寄通判楊宗博二首  其一','岳珂','宋','宋诗','song-poetry','','[]','多病山中客，無人傍酒罇。',48,'全唐诗/poet.song.193000.json','["多病山中客，無人傍酒罇。", "與猨分橡子，爲鹿長禾孫。", "白晝雲歸屋，黄昏雨打門。", "忽懷楊司馬，煙靄隔重閽。"]'),
('6196c6df-4929-4e7a-8297-8146b46dc1f9','山中奉寄通判楊宗博二首  其二','岳珂','宋','宋诗','song-poetry','','[]','步壑斗堪摘，登樓雲與齊。',48,'全唐诗/poet.song.193000.json','["步壑斗堪摘，登樓雲與齊。", "未應隨日涉，猶欠樂天題。", "舊覽開青眼，新編寫赫蹏。", "便須聯和軸，寄我小山西。"]'),
('bba9d8eb-5aeb-4f2b-821c-a047b4701aad','酬趙季茂遣餉松實鰻鮆柔魚','岳珂','宋','宋诗','song-poetry','','[]','掀天吹浪九夷東，維錯分珍意倍濃。',64,'全唐诗/poet.song.193000.json','["掀天吹浪九夷東，維錯分珍意倍濃。", "越井戲沙形酷似，秦囊遺算墨猶封。", "色欺金嫩三江鮆，實比瓊酥十丈松。", "珍重故人勞問遺，爲言耕隴正勤農。"]'),
('d06d4a90-b38d-456e-b175-7b87f08bab5f','九月一日聞雁','岳珂','宋','宋诗','song-poetry','','[]','今年九月旦，澤國始聞雁。',80,'全唐诗/poet.song.193000.json','["今年九月旦，澤國始聞雁。", "雝雝三兩聲，雲關更凄斷。", "宿豫旱且蝗，豈汝無稻粱。", "窮漠三萬里，還復思故鄉。", "雁來過期已一月，汝來之遲果何說。", "雁對以臆不能言，來時胡兒將寇邊。"]'),
('8943c86c-1d8c-4f9b-994c-be49cb1771d9','次韻趙季茂寄詩','岳珂','宋','宋诗','song-poetry','','[]','蒹葭道阻長，人在水中央。',48,'全唐诗/poet.song.193000.json','["蒹葭道阻長，人在水中央。", "鴻筆寫秋思，驪珠比夜光。", "律嚴詩格壯，鈐度置郵忙。", "鉅軸注銀水，欲題無漢陽。"]'),
('643efe0c-de5b-4d3a-a969-92da7458b39d','山中書懷','岳珂','宋','宋诗','song-poetry','','[]','我昨浮平湖，時適逢中秋。',288,'全唐诗/poet.song.193000.json','["我昨浮平湖，時適逢中秋。", "十年鷗鷺盟，萬丈蛟龍湫。", "微風自遠至，皓月當上頭。", "朋游凡三人，一舉累百甌。", "清光洞虛明，醉舞相勸酬。", "枕籍起更酌，微茫寄安流。", "長空隠繩低，中夕發櫂謳。", "未開晨曦輪，已繫橫堤舟。", "駕言舍維檝，登途肅衾裯。", "凄凄感霜露，鬰鬰瞻松楸。", "惻愴動五情，顧省經幾丘。", "僾然儵如在，惕若疑可求。", "暌離纔經歲，蓊蒨驚且稠。", "每欲棲猨扃，於焉築菟裘。", "經營眺高岡，夷坦開平疇。", "左撫芙蓉屏，右瞰鴻雁洲。", "風雷凄五更，雲月澄雙眸。", "汜蘭滋畹茂，叢桂連山幽。", "驚鳶下跕跕，候蟲鳴啾啾。", "振策後無繼，蝎屐杳莫周。", "誰接西山袂，且爲東皋留。", "一憩動踰月，四顧無與儔。", "棲禽競晨噪，落霞觀夕收。", "樵歌路崎嶇，漁笛聲咿嚘。"]'),
('6f0c7af4-0791-4f3f-8b8c-a49ace739dd7','九月十三日始就郊墅拜寶謨閣直學士提舉江州太平興國宮之命','岳珂','宋','宋诗','song-poetry','','[]','槐影西清舞翠鸞，竹宮高接五雲環。',64,'全唐诗/poet.song.193000.json','["槐影西清舞翠鸞，竹宮高接五雲環。", "職陪溫洛圖書地，名在元封卜祝間。", "晝訪未承龍閣問，晨香猶厠羽衣班。", "祠官到處無公事，且聽松聲老此山。"]'),
('744de2b5-1d02-47ed-8c27-b0cfb177cb58','茶花盛放滿山','岳珂','宋','宋诗','song-poetry','','[]','花容縝栗露冰膚，消得脂韋酪作奴。',64,'全唐诗/poet.song.193000.json','["花容縝栗露冰膚，消得脂韋酪作奴。", "葉底綻葩黄映玉，枝間著子碧垂珠。", "潔躬淡薄隠君子，苦口森嚴大丈夫。", "便合味言歸雋永，移根禁禦比青蒲。"]'),
('8e4c16f5-6128-4a5e-9e92-bca5a435d582','九月十四日夜月明如晝敬想合宮竣事志喜而作','岳珂','宋','宋诗','song-poetry','','[]','纖塵不動月流空，雲繞昆侖想合宮。',64,'全唐诗/poet.song.193000.json','["纖塵不動月流空，雲繞昆侖想合宮。", "蟬冕侍祠三事列，雞竿賜赦九州同。", "裁儀丙巳尊容典，肇祀庚寅識聖功。", "田野老臣察天意，夜深頻起候西風。"]'),
('538316c2-ac97-4983-a543-ed4c8ead39e4','寄喬益公','岳珂','宋','宋诗','song-poetry','','[]','峩峩傑閣凌西清，高排雲漢垂日星。',240,'全唐诗/poet.song.193000.json','["峩峩傑閣凌西清，高排雲漢垂日星。", "千年福地開殊庭，絳節中天朝百靈。", "屬車小儒風埃底，歲一周星陪豹尾。", "有眼未識奎壁寒，有脚未踏仙晨班。", "忽傳天上鳳銜詔，碧篆五雲爭焜燿。", "洞深紫府掣金鋪，初日丹霞兩相照。", "劫塵超出乘剛風，帝恩廣大天九重。", "封詞寄與小心風，額塌沙土輸愚忠。", "今春轉粟折衝府，赤手親曾哺饑虎。", "十三萬兵猶未補，秋來無地無冬防。", "頗聞宿師無見糧，要是倖安那可常。", "門生感恩感刻骨，本末親嘗究根窟。", "于今况是香火閒，詎敢攙越說侵官。", "西陲奏稿卷十二，中有醫方方有意。", "芻蕘思報無已時，願軫蕭牆儆先備。"]'),
('ddf4303b-55a2-490e-a03d-cbaa94acb5f7','將游太平宮小詩呈趙季茂','岳珂','宋','宋诗','song-poetry','','[]','聖治峰前松檜寒，舊遊從此解歸鞍。',64,'全唐诗/poet.song.193000.json','["聖治峰前松檜寒，舊遊從此解歸鞍。", "著身泉石無心客，主掌雲山正額官。", "老去隠居居紫府，新來雜壓壓黄冠。", "門東曾有劉仙洞，剝蘚携筇試扣看。"]'),
('de5caf16-d01e-4cb7-be52-c56adacab296','螃蟹','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','無腸公子郭索君，橫行湖海劍戟羣。',64,'全唐诗/poet.song.193000.json','["無腸公子郭索君，橫行湖海劍戟羣。", "紫髯綠殻琥珀髓，以不負腹誇將軍。", "酒船拍浮老子慣，咀嚼兩螯仍把玩。", "廬山對此眼倍青，願從公子醉復醒。"]'),
('f723a062-6fb9-4f81-8b8b-73e8f27de5b3','聞畫眉鳥聲戲作','岳珂','宋','宋诗','song-poetry','','[]','木杪幽禽巧語新，何時曾記得名因。',64,'全唐诗/poet.song.193000.json','["木杪幽禽巧語新，何時曾記得名因。", "樣傳京兆成雙嫵，人指漁陽開小顰。", "儘稱如簧啼白晝，未須對鏡學青春。", "山中有叟嗒無語，短褐龐眉更笑人。"]'),
('05adc495-77f1-40ad-92d2-d47898e8d59c','小春六花 綠萼梅','岳珂','宋','宋诗','song-poetry','','[]','晚秋過了小春催，放盡山家綠萼梅。',64,'全唐诗/poet.song.193000.json','["晚秋過了小春催，放盡山家綠萼梅。", "東閣渠關詩興動，南枝先放暖風回。", "素裳肌透未融雪，碧蒼色欺初暈苔。", "惆悵東籬正岑寂，重陽消得滿園開。"]'),
('8e8bc35b-00f4-4ca9-be7d-3cac80d6a1b3','小春六花 茶花','岳珂','宋','宋诗','song-poetry','','[]','萬峰落葉木槎牙，春色初回壟上茶。',64,'全唐诗/poet.song.193000.json','["萬峰落葉木槎牙，春色初回壟上茶。", "淺蕊黄金韻梔子，嫩容白玉沁梨花。", "西風凝露纔成顆，北苑喊雷應未芽。", "苦口味言終有益，莫將容悅比浮葩。"]'),
('af660758-3d9c-4f8b-aa33-689584fa3710','小春六花 芙蓉','岳珂','宋','宋诗','song-poetry','','[]','人道秋來不似春，芙蓉特地張吾軍。',64,'全唐诗/poet.song.193000.json','["人道秋來不似春，芙蓉特地張吾軍。", "紅粧綠水照清夜，綵仗青旂朝大昕。", "吳陣綺羅千隊擁，秦川錦繡五花羣。", "可憐倚袖清霜早，日薄雲輕醉未醺。"]');
